    @staticmethod
    def _extract_first_url(text: str) -> str:
        match = re.search(r"https?://[^\s<>\"']+", str(text or ""))
        return match.group(0).rstrip(".,);]") if match else ""

    @staticmethod
    def _format_pansou_datetime(value: Any) -> str:
        text = str(value or "").strip()
        if not text or text.startswith("0001-01-01"):
            return ""
        text = text.replace("T", " ").replace("Z", "")
        if len(text) >= 10:
            text = text[:10].replace("-", "/")
        return text.strip()

    @staticmethod
    def _format_pansou_display_datetime(value: Any) -> str:
        text = str(value or "").strip()
        if not text:
            return ""
        if text.startswith("🕒"):
            return text
        match = re.match(r"^\d{4}[/-](\d{2}[/-]\d{2})(?:\b|$)", text)
        if match:
            text = match.group(1).replace("-", "/")
        return f"🕒{text}"

    @staticmethod
    def _keyword_prefers_mp_pt_search(text: str) -> bool:
        raw = str(text or "").strip()
        if not raw:
            return False
        compact = re.sub(r"\s+", "", raw).lower()
        if re.search(r"\b(?:s\d{1,2}e\d{1,3}|e\d{1,3}|ep\d{1,3})\b", raw, flags=re.IGNORECASE):
            return True
        if re.search(r"第\s*\d+\s*(?:季|集|话|回|期)", raw):
            return True
        if re.search(r"更新(?:至)?\s*(?:ep|e)?\s*0*\d{1,3}", raw, flags=re.IGNORECASE):
            return True
        if re.search(r"更(?:至)?\s*0*\d{1,3}\s*集", raw, flags=re.IGNORECASE):
            return True
        return any(token in compact for token in ["全集", "全季", "完结", "短剧", "剧集", "season"])

    @staticmethod
    def _normalize_search_prefix(text: str) -> Tuple[str, str]:
        raw = str(text or "").strip()
        raw = re.sub(r"[\u00a0\u1680\u180e\u2000-\u200b\u202f\u205f\u3000]+", " ", raw)
        raw = re.sub(r"\s+", " ", raw).strip()
        for pattern in (
            r"^(?:mp|pt)\s*搜索\s*(.*)$",
            r"^原生\s*搜索\s*(.*)$",
        ):
            match = re.match(pattern, raw, flags=re.IGNORECASE)
            if match:
                return "mp", match.group(1).strip()
        mappings = [
            ("盘搜更新检查", "update_pansou"),
            ("盘搜检查", "update_pansou"),
            ("影巢更新检查", "update_hdhive"),
            ("影巢检查", "update_hdhive"),
            ("更新检查", "update"),
            ("更新搜索", "update"),
            ("查更新", "update"),
            ("更新", "update"),
            ("资源决策", "smart_decision"),
            ("智能决策", "smart_decision"),
            ("智能执行", "smart_execute"),
            ("智能搜执行", "smart_execute"),
            ("智能计划", "smart_plan"),
            ("智能搜计划", "smart_plan"),
            ("智能搜索", "smart"),
            ("智能搜", "smart"),
            ("MP搜索", "mp"),
            ("MP 搜索", "mp"),
            ("PT搜索", "mp"),
            ("PT 搜索", "mp"),
            ("pt搜索", "mp"),
            ("pt 搜索", "mp"),
            ("原生搜索", "mp"),
            ("原生 搜索", "mp"),
            ("搜索资源", "pansou"),
            ("找资源", "pansou"),
            ("搜索", "search"),
            ("找", "search"),
            ("1搜索", "pansou"),
            ("2搜索", "hdhive"),
            ("影巢搜索", "hdhive"),
            ("yc", "hdhive"),
            ("2", "hdhive"),
            ("盘搜搜索", "pansou"),
            ("盘搜", "pansou"),
            ("ps", "pansou"),
            ("1", "pansou"),
        ]
        for prefix, mode in mappings:
            if raw == prefix:
                return mode, ""
            if raw.startswith(prefix + " "):
                return mode, raw[len(prefix):].strip()
            if raw.startswith(prefix):
                remain = raw[len(prefix):].strip()
                if remain:
                    return mode, remain
        if raw.startswith("检查 "):
            remain = raw[len("检查"):].strip()
            if remain:
                return "update", remain
        return "", raw

    @staticmethod
    def _is_generic_search_command(text: str) -> bool:
        raw = str(text or "").strip()
        raw = re.sub(r"[\u00a0\u1680\u180e\u2000-\u200b\u202f\u205f\u3000]+", " ", raw)
        raw = re.sub(r"\s+", " ", raw).strip().lower()
        return any(
            raw == prefix or raw.startswith(prefix + " ")
            for prefix in ["搜索资源", "找资源", "搜索", "找"]
        )

    @staticmethod
    def _is_explicit_pansou_command(text: str) -> bool:
        raw = str(text or "").strip()
        raw = re.sub(r"[\u00a0\u1680\u180e\u2000-\u200b\u202f\u205f\u3000]+", " ", raw)
        raw = re.sub(r"\s+", " ", raw).strip().lower()
        return any(
            raw == prefix or raw.startswith(prefix + " ")
            for prefix in ["盘搜搜索", "盘搜", "ps", "1搜索", "1"]
        )

    @staticmethod
    def _extract_smart_decision_intent(text: str) -> Tuple[str, str]:
        raw = str(text or "").strip()
        if not raw:
            return "", ""
        patterns = [
            ("execute_now", [
                r"(?:直接|立即|马上|立刻)?确认执行$",
                r"(?:直接|立即|马上|立刻)?确认$",
                r"(?:直接|立即|马上|立刻)?执行$",
                r"(?:直接|立即|马上|立刻)?下载$",
                r"(?:直接|立即|马上|立刻)?转存$",
                r"(?:直接|立即|马上|立刻)?解锁$",
                r"(?:直接|立即|马上|立刻)?处理$",
            ]),
            ("make_plan", [
                r"(?:先)?生成计划$",
                r"(?:先)?做计划$",
                r"(?:先)?出计划$",
                r"(?:先)?计划$",
                r"(?:先)?待确认计划$",
            ]),
            ("show_detail", [
                r"详情$",
                r"(?:先)?看详情$",
                r"(?:先)?看一下$",
                r"(?:先)?看看$",
                r"(?:只)?看推荐$",
                r"(?:只)?看结果$",
                r"(?:先)?推荐一下$",
            ]),
        ]
        compact = re.sub(r"\s+", "", raw)
        for intent, tokens in patterns:
            for token in tokens:
                if re.search(token, compact, flags=re.IGNORECASE):
                    cleaned = re.sub(token, "", compact, flags=re.IGNORECASE).strip()
                    return cleaned or raw, intent
        return raw, ""

    @classmethod
    def _extract_mp_result_filter_intent(cls, text: str) -> Tuple[str, str]:
        raw = str(text or "").strip()
        if not raw:
            return "", ""
        episode_patterns = [
            r"(?:给我|帮我|只看|看看|看一下|要|下)?\s*s\d{1,2}\s*e0*(\d{1,3})\s*(?:集|资源|结果)?",
            r"(?:给我|帮我|只看|看看|看一下|要|下)?\s*e0*(\d{1,3})\s*(?:集|资源|结果)?",
            r"(?:给我|帮我|只看|看看|看一下|要|下)?\s*第\s*(\d{1,3})\s*集\s*(?:资源|结果)?",
            r"(?:给我|帮我|只看|看看|看一下|要|下)?\s*第\s*([零〇一二两三四五六七八九十]{1,4})\s*集\s*(?:资源|结果)?",
        ]
        for pattern in episode_patterns:
            match = re.search(pattern, raw, flags=re.IGNORECASE)
            if not match:
                continue
            raw_episode = match.group(1)
            if str(raw_episode).isdigit():
                episode = int(raw_episode)
            else:
                episode = cls._parse_simple_cjk_number(str(raw_episode)) or 0
            if episode <= 0:
                continue
            cleaned = (raw[:match.start()] + " " + raw[match.end():]).strip(" ：:，,。")
            cleaned = re.sub(r"\s+", " ", cleaned).strip()
            cleaned = re.sub(r"(?:的|第)$", "", cleaned).strip()
            return cleaned or raw, f"episode:{episode}"
        patterns = [
            r"(?:给我|帮我|只看|看看|看一下)?最新(?:一)?集(?:资源|结果)?",
            r"(?:给我|帮我|只看|看看|看一下)?最新(?:两|2)集(?:资源|结果)?",
            r"只(?:要|看)(?:当前)?最新",
        ]
        cleaned = raw
        matched = False
        for pattern in patterns:
            new_value = re.sub(pattern, " ", cleaned, flags=re.IGNORECASE)
            if new_value != cleaned:
                matched = True
                cleaned = new_value
        cleaned = re.sub(r"\s+", " ", cleaned).strip(" ：:，,。")
        cleaned = re.sub(r"(?:的|第)$", "", cleaned).strip()
        return (cleaned or raw, "latest_episode") if matched else (raw, "")

    async def _assistant_smart_decision_followup_detail(
        self,
        request,
        *,
        session: str,
        cache_key: str,
        keyword: str,
        compact: bool = False,
        apikey: str = "",
        media_type: str = "",
        year: str = "",
        source_order: Optional[List[str]] = None,
        target_path: str = "",
        decision_profile: str = "",
    ):
        decision_result = await self._assistant_smart_resource_decision(
            request,
            keyword=keyword,
            session=session,
            cache_key=cache_key,
            media_type=media_type,
            year=year,
            source_order=source_order,
            target_path=target_path,
            decision_profile=decision_profile,
        )
        state = self._load_session(cache_key)
        if not isinstance(state, dict) or self._clean_text(state.get("kind")) != "assistant_smart_search":
            return decision_result
        return await self.api_assistant_pick(
            _JsonRequestShim(request, {
                "session": session,
                "session_id": cache_key,
                "choice": 0,
                "action": "best",
                "path": target_path,
                "compact": compact,
                "apikey": apikey,
            })
        )

    @staticmethod
    def _match_command_prefix(raw: str, prefixes: List[str]) -> Optional[Tuple[str, str]]:
        text = str(raw or "").strip()
        for prefix in prefixes:
            if not text.startswith(prefix):
                continue
            remain = text[len(prefix):]
            if not remain:
                return prefix, ""
            return prefix, remain.lstrip(" ：:").strip()
        return None

    @staticmethod
    def _normalize_mp_recommend_request(value: Any, default_source: str = "tmdb_trending") -> Tuple[str, str]:
        raw = str(value or "").strip()
        compact = re.sub(r"[\s，。？！!?,、:：]+", "", raw).lower()
        allowed_sources = {
            "tmdb_trending",
            "tmdb_movies",
            "tmdb_tvs",
            "douban_hot",
            "douban_movie_hot",
            "douban_tv_hot",
            "douban_showing",
            "douban_movie_showing",
            "douban_movie_top250",
            "douban_tv_animation",
            "bangumi_calendar",
        }
        if compact in allowed_sources:
            if compact == "douban_showing":
                return "douban_movie_showing", "movie"
            return compact, "all"
        source_aliases = {
            "trending": ("tmdb_trending", "all"),
            "tmdb": ("tmdb_trending", "all"),
            "tmdb热门": ("tmdb_trending", "all"),
            "tmdb电影": ("tmdb_movies", "movie"),
            "tmdb剧集": ("tmdb_tvs", "tv"),
            "tmdb电视剧": ("tmdb_tvs", "tv"),
            "豆瓣": ("douban_hot", "all"),
            "豆瓣热门": ("douban_hot", "all"),
            "豆瓣电影": ("douban_movie_hot", "movie"),
            "豆瓣热门电影": ("douban_movie_hot", "movie"),
            "豆瓣热映": ("douban_movie_showing", "movie"),
            "豆瓣电视剧": ("douban_tv_hot", "tv"),
            "豆瓣剧集": ("douban_tv_hot", "tv"),
            "豆瓣top250": ("douban_movie_top250", "movie"),
            "top250": ("douban_movie_top250", "movie"),
            "douban_showing": ("douban_movie_showing", "movie"),
            "正在热映": ("douban_movie_showing", "movie"),
            "热映": ("douban_movie_showing", "movie"),
            "院线": ("douban_movie_showing", "movie"),
            "bangumi": ("bangumi_calendar", "tv"),
            "番剧": ("bangumi_calendar", "tv"),
            "今日番剧": ("bangumi_calendar", "tv"),
            "每日放送": ("bangumi_calendar", "tv"),
            "动画番剧": ("bangumi_calendar", "tv"),
        }
        if compact in source_aliases:
            return source_aliases[compact]
        if "top250" in compact:
            return "douban_movie_top250", "movie"
        if any(token in compact for token in ["bangumi", "番剧", "每日放送", "今日放送", "今日动画"]):
            return "bangumi_calendar", "tv"
        if any(token in compact for token in ["正在热映", "热映", "院线"]):
            return "douban_movie_showing", "movie"
        if "豆瓣" in compact:
            if "动画" in compact:
                return "douban_tv_animation", "tv"
            if any(token in compact for token in ["电视剧", "剧集", "剧", "tv"]):
                return "douban_tv_hot", "tv"
            if any(token in compact for token in ["电影", "movie"]):
                return "douban_movie_hot", "movie"
            return "douban_hot", "all"
        if "tmdb" in compact:
            if any(token in compact for token in ["电视剧", "剧集", "剧", "tv"]):
                return "tmdb_tvs", "tv"
            if any(token in compact for token in ["电影", "movie"]):
                return "tmdb_movies", "movie"
            return "tmdb_trending", "all"
        if any(token in compact for token in ["电视剧", "剧集", "剧集推荐", "热门剧", "热门电视剧"]):
            return "tmdb_tvs", "tv"
        if any(token in compact for token in ["电影", "影视电影", "热门电影"]):
            return "tmdb_movies", "movie"
        return default_source or "tmdb_trending", "all"

    @classmethod
    def _resolve_pan_path_value(cls, value: str) -> str:
        text = str(value or "").strip()
        if not text:
            return ""
        alias_map = {
            "分享": "/飞书",
            "飞书": "/飞书",
            "待整理": "/待整理",
            "最新动画": "/最新动画",
        }
        mapped = alias_map.get(text, text)
        return cls._normalize_path(mapped)

    @staticmethod
    def _normalize_pick_action(value: Any) -> str:
        text = str(value or "").strip().lower()
        if text in {"继续决策", "继续资源决策", "decision_continue"}:
            return "decision_continue"
        if text in {"换影巢", "切换影巢", "走影巢", "用影巢", "decision_hdhive"}:
            return "decision_hdhive"
        if text in {"换盘搜", "切换盘搜", "走盘搜", "用盘搜", "decision_pansou"}:
            return "decision_pansou"
        if text in {"换pt", "换原生", "换mp", "切换pt", "切换原生", "切换mp", "走pt", "走原生", "走mp", "decision_mp_pt"}:
            return "decision_mp_pt"
        if text in {"保守一点", "更保守", "保守模式", "decision_conservative"}:
            return "decision_conservative"
        if text in {"激进一点", "更激进", "激进模式", "decision_aggressive"}:
            return "decision_aggressive"
        if text in {"只用夸克", "只有夸克", "仅夸克", "只要夸克", "decision_only_quark"}:
            return "decision_only_quark"
        if text in {"只用115", "只有115", "仅115", "只要115", "decision_only_115"}:
            return "decision_only_115"
        if text in {"两者都可", "云盘都可", "115和夸克都可", "115夸克都可", "decision_cloud_both"}:
            return "decision_cloud_both"
        if text in {"只走pt", "只走原生", "只用pt", "只用原生", "只走mp", "只用mp", "decision_only_mp_pt"}:
            return "decision_only_mp_pt"
        if text in {"只走盘搜", "只用盘搜", "decision_only_pansou"}:
            return "decision_only_pansou"
        if text in {"只走影巢", "只用影巢", "decision_only_hdhive"}:
            return "decision_only_hdhive"
        if text in {"不用盘搜", "关闭盘搜", "禁用盘搜", "decision_disable_pansou"}:
            return "decision_disable_pansou"
        if text in {"不用影巢", "关闭影巢", "禁用影巢", "decision_disable_hdhive"}:
            return "decision_disable_hdhive"
        if text in {"不用pt", "不用原生", "关闭pt", "关闭原生", "关闭mp", "decision_disable_mp_pt"}:
            return "decision_disable_mp_pt"
        if text in {"按保存偏好", "恢复偏好", "恢复默认偏好", "清除会话偏好", "decision_reset_preferences"}:
            return "decision_reset_preferences"
        if text in {"确认执行", "确认执行吧", "就执行吧", "直接来", "执行它", "确认处理", "确认转存", "确认解锁"}:
            return "best_execute"
        if text in {"先计划", "先做计划", "先生成计划", "先出计划", "还是先计划"}:
            return "best_plan"
        if text in {"先看详情", "先看推荐", "先看结果", "看最佳", "看看最佳", "先看一下"}:
            return "best"
        if text in {"best_execute", "execute_best", "执行最佳", "最佳执行", "立即执行最佳", "直接执行最佳"}:
            return "best_execute"
        if text in {"best_plan", "plan_best", "计划最佳", "最佳计划", "计划推荐", "推荐计划", "最优计划"}:
            return "best_plan"
        if text in {"detail", "details", "review", "详情", "审查"}:
            return "detail"
        if text in {"best", "best_result", "recommend_best", "最佳", "最佳片源", "推荐片源", "推荐下载", "最优"}:
            return "best"
        if text in {"plan", "dry_run", "make_plan", "计划", "生成计划", "计划选择", "计划处理", "转存计划", "解锁计划"}:
            return "plan"
        if text in {"n", "next", "next_page", "下一页", "下页"} or text.startswith("n "):
            return "next_page"
        return ""

    @staticmethod
    def _normalize_smart_search_short_action(value: Any, *, state_kind: str = "") -> str:
        if str(state_kind or "").strip() != "assistant_smart_search":
            return ""
        compact = re.sub(r"\s+", "", str(value or "").strip().lower())
        if compact in {"详情", "看详情", "看看", "看一下", "detail", "details"}:
            return "best"
        if compact in {"计划", "做计划", "plan"}:
            return "best_plan"
        if compact in {"确认", "执行", "确认吧", "执行吧", "确定执行", "execute", "run"}:
            return "best_execute"
        return ""

    @staticmethod
    def _is_pending_plan_confirmation_text(value: Any) -> bool:
        raw = str(value or "").strip()
        if not raw:
            return False
        compact = re.sub(r"\s+", "", raw).lower()
        if re.search(r"\d", compact):
            return False
        return compact in {
            "确认",
            "确认吧",
            "确认执行",
            "确认执行吧",
            "执行",
            "执行吧",
            "execute",
            "run",
            "确定",
            "确定执行",
            "执行下载",
            "确认下载",
            "开始下载",
            "下载吧",
        }

    @classmethod
    def _parse_pending_plan_numeric_confirmation(cls, value: Any) -> int:
        raw = cls._normalize_fullwidth_digits(cls._clean_text(value))
        if not raw:
            return 0
        compact = re.sub(r"[\s，。？！!?,、:：；;“”\"'（）()【】\[\]]+", "", raw)
        # Only a bare number or explicit execution wording may confirm a saved plan.
        # "下载1" is treated as the current PT-list download command, not a saved-plan
        # confirmation, so it must not match here.
        match = re.fullmatch(r"(?:执行|确认|执行计划|确认计划)?(\d+)", compact, flags=re.IGNORECASE)
        if not match:
            return 0
        return cls._safe_int(match.group(1), 0)

    def _is_pending_plan_numeric_confirmation(self, value: Any, plan: Optional[Dict[str, Any]]) -> bool:
        index = self._parse_pending_plan_numeric_confirmation(value)
        if index <= 0 or not isinstance(plan, dict):
            return False
        expected_choices: List[int] = []
        execute_body = plan.get("execute_body") if isinstance(plan.get("execute_body"), dict) else {}
        expected_choices.append(self._safe_int(execute_body.get("plan_rank"), 0))
        expected_choices.append(self._safe_int(execute_body.get("choice") or execute_body.get("index"), 0))
        for action in plan.get("actions") or []:
            if isinstance(action, dict):
                expected_choices.append(self._safe_int(action.get("plan_rank"), 0))
                expected_choices.append(self._safe_int(action.get("choice") or action.get("index"), 0))
        return index in {choice for choice in expected_choices if choice > 0}

    @classmethod
    def _normalize_ai_reingest_short_action(
        cls,
        value: Any,
        *,
        state: Optional[Dict[str, Any]] = None,
    ) -> Dict[str, Any]:
        current_state = dict(state or {})
        kind = cls._clean_text(current_state.get("kind"))
        compact = re.sub(r"\s+", "", str(value or "").strip().lower())
        result: Dict[str, Any] = {}
        ai_session_kinds = {
            "assistant_ai_failed_samples",
            "assistant_ai_sample_worklist",
            "assistant_ai_sample_insights",
            "assistant_ai_replay",
        }
        saved_plan = dict((current_state.get("saved_plan") or {}).get("latest") or {})
        saved_workflow = cls._clean_text(saved_plan.get("workflow"))
        has_pending_ai_replay_plan = (
            bool((current_state.get("saved_plan") or {}).get("has_pending"))
            and saved_workflow == "ai_replay_failed_sample"
        )
        if has_pending_ai_replay_plan and compact in {"确认", "确认吧", "执行", "执行吧", "确定", "确定执行", "run", "execute"}:
            return {"action": "execute_plan"}
        if kind not in ai_session_kinds:
            return {}
        keyword = cls._clean_text(current_state.get("keyword"))
        if keyword and compact in {"诊断", "本地诊断", "重新诊断", "看诊断"}:
            return {"action": "mp_local_diagnose", "keyword": keyword}
        if keyword and compact in {"入库状态", "看入库状态", "状态"}:
            return {"action": "mp_ingest_status", "keyword": keyword}
        if compact in {"工作清单", "返回工作清单", "回工作清单"}:
            return {"action": "ai_sample_worklist", "keyword": keyword}
        if compact in {"失败样本", "返回失败样本", "回失败样本"}:
            return {"action": "ai_failed_samples", "keyword": keyword}
        if compact in {"样本洞察", "洞察", "返回样本洞察", "回样本洞察"}:
            return {"action": "ai_sample_insights", "keyword": keyword}
        raw = cls._clean_text(value)
        replay_match = re.match(r"^\s*(重放|重识别|重跑)\s*(\d+)(?:\s+(.*))?$", raw)
        if replay_match:
            result = {
                "action": "ai_replay_failed_sample",
                "sample_index": replay_match.group(2),
                "keyword": "",
                "mode": "",
                "remove_if_resolved": "true",
            }
            remain_text = cls._clean_text(replay_match.group(3))
            if "保留样本" in remain_text or "不移除" in remain_text:
                result["remove_if_resolved"] = "false"
            return result
        return {}

    @classmethod
    def _normalize_mp_recommend_short_action(
        cls,
        value: Any,
        *,
        state: Optional[Dict[str, Any]] = None,
    ) -> Dict[str, Any]:
        current_state = dict(state or {})
        if cls._clean_text(current_state.get("kind")) != "assistant_mp_recommend":
            return {}
        raw = cls._clean_text(value)
        patterns = [
            (r"^\s*(?:决策|资源决策|智能决策)\s*(\d+)\s*$", {"mode": "smart_decision"}),
            (r"^\s*(?:详情|查看详情|看详情)\s*(\d+)\s*$", {"action": "detail"}),
            (r"^\s*(?:计划|生成计划|先计划)\s*(\d+)\s*$", {"action": "plan"}),
            (r"^\s*(?:确认|执行|直接执行)\s*(\d+)\s*$", {"mode": "smart_execute"}),
            (r"^\s*(?:盘搜|ps)\s*(\d+)\s*$", {"mode": "pansou"}),
            (r"^\s*(?:影巢|yc)\s*(\d+)\s*$", {"mode": "hdhive"}),
            (r"^\s*(?:原生|mp|pt)\s*(\d+)\s*$", {"mode": "mp"}),
        ]
        for pattern, base in patterns:
            match = re.match(pattern, raw, flags=re.IGNORECASE)
            if match:
                return {"index": match.group(1), **base}
        selected_index = cls._safe_int(current_state.get("selected_index"), 0)
        if selected_index <= 0:
            items = current_state.get("items") if isinstance(current_state.get("items"), list) else []
            if items:
                selected_index = 1
        if selected_index > 0:
            no_index_aliases = {
                "详情": {"action": "detail"},
                "查看详情": {"action": "detail"},
                "看详情": {"action": "detail"},
                "决策": {"mode": "smart_decision"},
                "资源决策": {"mode": "smart_decision"},
                "智能决策": {"mode": "smart_decision"},
                "计划": {"action": "plan"},
                "生成计划": {"action": "plan"},
                "先计划": {"action": "plan"},
                "确认": {"mode": "smart_execute"},
                "执行": {"mode": "smart_execute"},
                "直接执行": {"mode": "smart_execute"},
                "盘搜": {"mode": "pansou"},
                "ps": {"mode": "pansou"},
                "影巢": {"mode": "hdhive"},
                "yc": {"mode": "hdhive"},
                "原生": {"mode": "mp"},
                "mp": {"mode": "mp"},
                "pt": {"mode": "mp"},
            }
            shortcut = no_index_aliases.get(raw)
            if shortcut:
                return {"index": selected_index, **shortcut}
        return {}

    @classmethod
    def _normalize_mp_recommend_followup(
        cls,
        value: Any,
        *,
        state: Optional[Dict[str, Any]] = None,
    ) -> Dict[str, Any]:
        current_state = dict(state or {})
        if cls._clean_text(current_state.get("kind")) != "assistant_mp_recommend":
            return {}
        compact = re.sub(r"[\s，。？！!?,、:：]+", "", cls._clean_text(value)).lower()
        followup_aliases = {
            "电影": ("tmdb_movies", "movie"),
            "热门电影": ("tmdb_movies", "movie"),
            "电视剧": ("tmdb_tvs", "tv"),
            "热门电视剧": ("tmdb_tvs", "tv"),
            "豆瓣": ("douban_hot", "all"),
            "豆瓣热门": ("douban_hot", "all"),
            "热映": ("douban_movie_showing", "movie"),
            "正在热映": ("douban_movie_showing", "movie"),
            "番剧": ("bangumi_calendar", "tv"),
            "今日番剧": ("bangumi_calendar", "tv"),
            "tmdb": ("tmdb_trending", "all"),
            "热门": ("tmdb_trending", "all"),
        }
        source_pair = followup_aliases.get(compact)
        if not source_pair:
            return {}
        source_name, media_type = source_pair
        return {"action": "mp_recommendations", "keyword": source_name, "type": media_type}

    @classmethod
    def _normalize_recommend_handoff_action(
        cls,
        value: Any,
        *,
        state: Optional[Dict[str, Any]] = None,
    ) -> Dict[str, Any]:
        current_state = dict(state or {})
        kind = cls._clean_text(current_state.get("kind"))
        if kind not in {"assistant_pansou", "assistant_mp", "assistant_hdhive"}:
            return {}
        handoff = current_state.get("recommend_handoff")
        if not isinstance(handoff, dict) or not handoff:
            return {}
        compact = re.sub(r"[\s，。？！!?,、:：]+", "", cls._clean_text(value)).lower()
        if compact not in {"回推荐", "回榜单", "返回推荐", "返回榜单", "推荐", "榜单"}:
            switch_mode_aliases = {
                "盘搜": "pansou",
                "ps": "pansou",
                "影巢": "hdhive",
                "yc": "hdhive",
                "原生": "mp",
                "mp": "mp",
            }
            switch_mode = switch_mode_aliases.get(compact)
            if not switch_mode:
                return {}
            return {"action": "switch_recommend_handoff_source", "mode": switch_mode}
        return {"action": "return_to_recommend"}

    @classmethod
    def _normalize_recommend_handoff_short_action(
        cls,
        value: Any,
        *,
        state: Optional[Dict[str, Any]] = None,
    ) -> Dict[str, Any]:
        current_state = dict(state or {})
        kind = cls._clean_text(current_state.get("kind"))
        if kind not in {"assistant_pansou", "assistant_mp", "assistant_hdhive"}:
            return {}
        handoff = current_state.get("recommend_handoff")
        if not isinstance(handoff, dict) or not handoff:
            return {}
        compact = re.sub(r"[\s，。？！!?,、:：]+", "", cls._clean_text(value)).lower()
        if compact in {"决策", "资源决策", "智能决策"}:
            return {"action": "return_to_smart_decision"}
        if kind in {"assistant_pansou", "assistant_mp"}:
            if compact in {"详情", "看详情", "看看", "看一下", "detail", "details"}:
                return {"route_action": "best"}
            if compact in {"计划", "做计划", "plan"}:
                return {"route_action": "best_plan"}
        if compact in {"确认", "确认吧", "确认执行", "执行", "执行吧", "确定执行", "run", "execute"}:
            return {"action": "confirm_recommend_handoff"}
        return {}

    @classmethod
    def _normalize_recommend_source_compound_action(
        cls,
        value: Any,
        *,
        state: Optional[Dict[str, Any]] = None,
    ) -> Dict[str, Any]:
        current_state = dict(state or {})
        kind = cls._clean_text(current_state.get("kind"))
        if kind not in {"assistant_mp_recommend", "assistant_pansou", "assistant_mp", "assistant_hdhive"}:
            return {}
        compact = re.sub(r"[\s，。？！!?,、:：]+", "", cls._clean_text(value)).lower()
        source_aliases = {
            "盘搜": "pansou",
            "ps": "pansou",
            "原生": "mp",
            "mp": "mp",
        }
        action_aliases = {
            "详情": "best",
            "看详情": "best",
            "计划": "best_plan",
            "确认": "best_execute",
            "执行": "best_execute",
        }
        for alias, mode in source_aliases.items():
            if not compact.startswith(alias):
                continue
            remain = compact[len(alias):]
            followup_action = action_aliases.get(remain)
            if not followup_action:
                continue
            return {
                "action": "recommend_source_compound",
                "mode": mode,
                "followup_action": followup_action,
            }
        return {}

    @classmethod
    def _normalize_mp_recommend_direct_intent(cls, value: Any) -> Dict[str, Any]:
        raw = cls._clean_text(value)
        if not raw:
            return {}
        prefix_match = cls._match_command_prefix(raw, ["智能发现", "热门发现", "热门推荐", "推荐"])
        if not prefix_match:
            return {}
        _, remain = prefix_match
        remain = cls._clean_text(remain)
        if not remain:
            return {}
        suffix_aliases: List[Tuple[str, Dict[str, str]]] = [
            ("资源决策", {"mode": "smart_decision"}),
            ("智能决策", {"mode": "smart_decision"}),
            ("查看详情", {"action": "detail"}),
            ("看详情", {"action": "detail"}),
            ("确认执行", {"mode": "smart_execute"}),
            ("直接执行", {"mode": "smart_execute"}),
            ("生成计划", {"action": "plan"}),
            ("先计划", {"action": "plan"}),
            ("详情", {"action": "detail"}),
            ("决策", {"mode": "smart_decision"}),
            ("计划", {"action": "plan"}),
            ("确认", {"mode": "smart_execute"}),
            ("执行", {"mode": "smart_execute"}),
            ("盘搜", {"mode": "pansou"}),
            ("影巢", {"mode": "hdhive"}),
            ("原生", {"mode": "mp"}),
        ]
        for suffix, action_payload in suffix_aliases:
            separator = f" {suffix}"
            if remain.endswith(separator):
                keyword = cls._clean_text(remain[: -len(separator)])
            elif remain == suffix:
                keyword = ""
            else:
                continue
            if not keyword:
                return {}
            return {"keyword": keyword, "index": 1, **action_payload}
        return {}

    @staticmethod
    def _normalize_pick_mode(value: Any) -> str:
        text = str(value or "").strip().lower()
        compact = re.sub(r"\s+", "", text)
        if not compact:
            return ""
        if any(token in compact for token in ["smart_execute", "smartexecute", "直接执行", "确认执行", "立即执行", "确认", "执行"]):
            return "smart_execute"
        if any(token in compact for token in ["smart_plan", "smartplan", "生成计划", "先计划", "计划"]):
            return "smart_plan"
        if any(token in compact for token in ["smart_decision", "smartdecision", "智能决策", "资源决策", "决策"]):
            return "smart_decision"
        if re.search(r"(^|[^a-z])smart($|[^a-z])", text):
            return "smart_decision"
        if any(token in compact for token in ["hdhive", "影巢", "影潮", "走影巢", "用影巢"]):
            return "hdhive"
        if re.search(r"(^|[^a-z])yc($|[^a-z])", text):
            return "hdhive"
        if any(token in compact for token in ["pansou", "盘搜", "走盘搜", "用盘搜"]):
            return "pansou"
        if re.search(r"(^|[^a-z])ps($|[^a-z])", text):
            return "pansou"
        if any(token in compact for token in ["mp", "原生", "moviepilot", "站点", "pt"]):
            return "mp"
        return ""

    @staticmethod
    def _normalize_fullwidth_digits(value: Any) -> str:
        return str(value or "").translate(str.maketrans("０１２３４５６７８９", "0123456789"))

    @staticmethod
    def _parse_chinese_pick_number(value: Any) -> int:
        text = str(value or "").strip()
        if not text:
            return 0
        text = text.replace("两", "二").replace("〇", "零")
        digits = {
            "零": 0,
            "一": 1,
            "二": 2,
            "三": 3,
            "四": 4,
            "五": 5,
            "六": 6,
            "七": 7,
            "八": 8,
            "九": 9,
        }
        if text.isdigit():
            return int(text)
        if any(ch not in digits and ch not in {"十", "百"} for ch in text):
            return 0
        if len(text) == 1:
            return digits.get(text, 0)
        total = 0
        remainder = text
        if "百" in remainder:
            left, _, remainder = remainder.partition("百")
            hundreds = 1 if not left else digits.get(left, 0)
            if hundreds <= 0:
                return 0
            total += hundreds * 100
        if "十" in remainder:
            left, _, right = remainder.partition("十")
            tens = 1 if not left else digits.get(left, 0)
            ones = 0 if not right else digits.get(right, 0)
            if tens <= 0 or (right and ones <= 0):
                return 0
            total += tens * 10 + ones
            return total
        if total and len(remainder) == 1:
            return total + digits.get(remainder, 0)
        return total

    @classmethod
    def _normalize_pick_action_fragment(cls, value: Any) -> str:
        compact = re.sub(r"[\s的地得一下]+", "", str(value or "").strip().lower())
        if not compact:
            return ""
        action = cls._normalize_pick_action(compact)
        if action:
            return action
        if any(token in compact for token in ["详情", "明细", "查看", "看看", "看下", "看一下"]):
            return "detail"
        if "审查" in compact:
            return "detail"
        if any(token in compact for token in ["计划", "dryrun", "makeplan"]):
            return "plan"
        return ""

    @classmethod
    def _parse_compact_pick_text(cls, value: Any) -> Tuple[int, str]:
        raw = cls._normalize_fullwidth_digits(value)
        compact = re.sub(r"[\s，。？！!?,、:：；;“”\"'（）()【】\[\]]+", "", raw)
        if not compact:
            return 0, ""
        chinese_number = r"[零〇一二两三四五六七八九十百]+"
        number_token = rf"(?:\d+|{chinese_number})"

        def number_value(token: str) -> int:
            return cls._safe_int(token, 0) if token.isdigit() else cls._parse_chinese_pick_number(token)

        # Short forms: "16详情", "十六详情", "16", "十六".
        match = re.fullmatch(rf"({number_token})(.*)", compact)
        if match:
            index = number_value(match.group(1))
            suffix = match.group(2)
            action = cls._normalize_pick_action_fragment(suffix)
            if index > 0 and (not suffix or action):
                return index, action

        # Reversed short forms: "详情16", "详情十六", "计划16".
        match = re.fullmatch(rf"(.+?)({number_token})", compact)
        if match:
            action = cls._normalize_pick_action_fragment(match.group(1))
            index = number_value(match.group(2))
            if index > 0 and action:
                return index, action

        # Natural phrases: "我要看看 16 的详情", "帮我看第十六个详情".
        natural_action = cls._normalize_pick_action_fragment(compact)
        if natural_action:
            digit_match = re.search(r"\d+", compact)
            if digit_match:
                return cls._safe_int(digit_match.group(0), 0), natural_action
            for cn_match in re.finditer(chinese_number, compact):
                token = cn_match.group(0)
                # Avoid treating "看一下详情" as "pick 1 detail".
                if len(token) == 1 and token in {"一", "二", "三"}:
                    continue
                index = cls._parse_chinese_pick_number(token)
                if index > 0:
                    return index, natural_action
        return 0, ""

    @classmethod
    def _parse_pick_text(cls, value: Any) -> Tuple[int, str, str, str]:
        raw = cls._normalize_fullwidth_digits(cls._clean_text(value))
        action = cls._normalize_pick_action(raw)
        if action:
            return 0, "", action, ""
        alias_pattern = r"^(?:/smart_pick|smart_pick|计划选择|计划处理|生成计划|转存计划|解锁计划|计划(?=\s*\d)|选择|选|继续|pick|plan|dry_run|make_plan)\s*"
        alias_match = re.match(alias_pattern, raw, flags=re.IGNORECASE)
        digit_match = re.match(r"^(\d+)(.*)$", raw)
        compact_index, compact_action = cls._parse_compact_pick_text(raw)
        if compact_index > 0 and not alias_match:
            return compact_index, "", compact_action, ""
        if not alias_match and not digit_match:
            return 0, "", "", ""
        if digit_match and not alias_match:
            suffix = cls._clean_text(digit_match.group(2))
            if suffix and not (
                suffix.startswith("/")
                or "=" in suffix
                or cls._normalize_pick_mode(suffix)
                or cls._normalize_pick_action(suffix)
                or suffix.lower() in {"n", "next"}
            ):
                return 0, "", "", ""
        text = re.sub(alias_pattern, "", raw, flags=re.IGNORECASE).strip()
        if alias_match and cls._normalize_pick_action(alias_match.group(0).strip()) == "plan":
            action = "plan"
        index = 0
        path = ""
        mode = ""
        pick_action = action or ""
        match = re.search(r"\d+", text)
        if match:
            index = cls._safe_int(match.group(0), 0)
        elif text:
            compact_index, compact_action = cls._parse_compact_pick_text(text)
            if compact_index > 0:
                index = compact_index
                if compact_action:
                    pick_action = compact_action
        for token in text.split():
            if "=" not in token:
                if not pick_action:
                    pick_action = cls._normalize_pick_action(token)
                continue
            key, token_value = token.split("=", 1)
            key = key.strip().lower()
            token_value = token_value.strip()
            if key in {"path", "dir", "目录", "位置"} and token_value:
                path = cls._resolve_pan_path_value(token_value)
            elif key in {"mode", "search_mode", "target", "方式", "来源", "渠道"} and token_value:
                mode = cls._normalize_pick_mode(token_value)
        if not mode:
            mode = cls._normalize_pick_mode(text)
        if not pick_action:
            suffix = re.sub(r"\d+", " ", text, count=1).strip()
            pick_action = cls._normalize_pick_action(suffix)
        return index, path, pick_action, mode

    def init_plugin(self, config: Optional[Dict[str, Any]] = None):
        config = config or {}
        self._enabled = bool(config.get("enabled", False))
        self._notify = bool(config.get("notify", True))
        self._debug = bool(config.get("debug", False))
        self._quark_cookie = self._clean_text(config.get("quark_cookie"))
        self._quark_default_path = self._normalize_path(config.get("quark_default_path") or "/飞书")
        self._quark_timeout = self._safe_int(config.get("quark_timeout"), 30)
        self._quark_auto_import_cookiecloud = bool(config.get("quark_auto_import_cookiecloud", True))
        self._pansou_enabled = bool(config.get("pansou_enabled", True))
        self._pansou_base_url = self._clean_text(config.get("pansou_base_url") or "http://127.0.0.1:805").rstrip("/")
        self._pansou_timeout = max(3, min(120, self._safe_int(config.get("pansou_timeout"), 20)))
        self._hdhive_api_key = self._clean_text(config.get("hdhive_api_key"))
        self._hdhive_base_url = self._clean_text(config.get("hdhive_base_url") or "https://hdhive.com").rstrip("/")
        self._hdhive_timeout = self._safe_int(config.get("hdhive_timeout"), 30)
        self._hdhive_default_path = self._normalize_path(config.get("hdhive_default_path") or "/待整理")
        self._hdhive_candidate_page_size = max(5, min(10, self._safe_int(config.get("hdhive_candidate_page_size"), self._assistant_result_page_size)))
        self._hdhive_resource_enabled = bool(config.get("hdhive_resource_enabled", True))
        self._hdhive_max_unlock_points = max(0, self._safe_int(config.get("hdhive_max_unlock_points"), 20))
        self._hdhive_checkin_enabled = bool(config.get("hdhive_checkin_enabled", False))
        self._hdhive_checkin_gambler_mode = bool(config.get("hdhive_checkin_gambler_mode", False))
        self._hdhive_checkin_once = bool(config.get("hdhive_checkin_once", False))
        self._hdhive_checkin_cron = self._clean_text(config.get("hdhive_checkin_cron") or "0 8 * * *")
        self._hdhive_checkin_cookie = self._clean_text(config.get("hdhive_checkin_cookie"))
        self._hdhive_checkin_auto_login = bool(config.get("hdhive_checkin_auto_login", True))
        self._hdhive_checkin_username = self._clean_text(config.get("hdhive_checkin_username"))
        self._hdhive_checkin_password = self._clean_text(config.get("hdhive_checkin_password"))
        self._p115_default_path = self._normalize_path(config.get("p115_default_path") or "/待整理")
        self._p115_client_type = P115TransferService.normalize_qrcode_client_type(config.get("p115_client_type"))
        self._p115_cookie = self._clean_text(config.get("p115_cookie"))
        self._p115_prefer_direct = bool(config.get("p115_prefer_direct", True))
        self._mp_pt_enabled = bool(config.get("mp_pt_enabled", True))
        self._mp_download_save_path = self._clean_text(config.get("mp_download_save_path"))
        self._assistant_default_pt_min_seeders = max(0, self._safe_int(config.get("assistant_default_pt_min_seeders"), 3))
        self._assistant_default_auto_ingest_enabled = bool(config.get("assistant_default_auto_ingest_enabled", False))
        self._assistant_default_auto_ingest_score_threshold = max(1, min(100, self._safe_int(config.get("assistant_default_auto_ingest_score_threshold"), 90)))
        self._assistant_default_confirm_score_threshold = max(1, min(100, self._safe_int(config.get("assistant_default_confirm_score_threshold"), 70)))
        self._feishu_enabled = bool(config.get("feishu_enabled", False))
        self._feishu_allow_all = bool(config.get("feishu_allow_all", False))
        self._feishu_reply_enabled = bool(config.get("feishu_reply_enabled", True))
        self._feishu_reply_receive_id_type = self._clean_text(config.get("feishu_reply_receive_id_type") or "chat_id")
        self._feishu_app_id = self._clean_text(config.get("feishu_app_id"))
        self._feishu_app_secret = self._clean_text(config.get("feishu_app_secret"))
        self._feishu_verification_token = self._clean_text(config.get("feishu_verification_token"))
        self._feishu_allowed_chat_ids = FeishuChannel.split_lines(config.get("feishu_allowed_chat_ids"))
        self._feishu_allowed_user_ids = FeishuChannel.split_lines(config.get("feishu_allowed_user_ids"))
        self._feishu_command_whitelist = FeishuChannel.merge_command_whitelist(
            FeishuChannel.split_commands(config.get("feishu_command_whitelist"))
        )
        self._feishu_command_aliases = FeishuChannel.merge_command_aliases(
            self._clean_text(config.get("feishu_command_aliases"))
        )
        self._feishu_command_mode = self._clean_text(config.get("feishu_command_mode") or "resource_officer")
        self._quark_service = QuarkTransferService(
            cookie=self._quark_cookie,
            timeout=self._quark_timeout,
            default_target_path=self._quark_default_path,
            auto_import_cookiecloud=self._quark_auto_import_cookiecloud,
            cookie_refresh_callback=self._refresh_quark_cookie_from_cookiecloud,
        )
        self._hdhive_service = HDHiveOpenApiService(
            api_key=self._hdhive_api_key,
            base_url=self._hdhive_base_url,
            timeout=self._hdhive_timeout,
        )
        self._p115_service = P115TransferService(
            default_target_path=self._p115_default_path,
            cookie=self._p115_cookie,
            prefer_direct=self._p115_prefer_direct,
        )
        self._restore_persisted_sessions()
        self._restore_execution_history()
        self._restore_hdhive_checkin_history()
        self._restore_workflow_plans()
        self._restore_assistant_preferences()
        self._agent_tools_reloaded = False
        self._ensure_feishu_channel().configure(self._build_config())
        if self._enabled and self._feishu_enabled:
            self._feishu_channel.start()
        elif self._feishu_channel is not None:
            self._feishu_channel.stop()
        self._maybe_run_hdhive_checkin_once()

    def get_state(self) -> bool:
        if self._enabled:
            self._maybe_reload_agent_tools_once()
        return self._enabled

