    @staticmethod
    def _resource_has_free_marker(item: Optional[Dict[str, Any]]) -> bool:
        if not isinstance(item, dict) or not item:
            return False
        for key in ["unlock_points", "cost", "points", "price", "point_text"]:
            text = str(item.get(key) or "").strip().lower()
            if text in {"0", "free", "免费", "0分"}:
                return True
        blob = " ".join(
            str(item.get(key) or "")
            for key in [
                "title",
                "remark",
                "description",
                "desc",
                "detail",
                "details",
                "summary",
                "note",
                "source",
                "source_name",
            ]
        ).lower()
        return "免费" in blob or " free " in f" {blob} "

    @staticmethod
    def _resource_points_value(item: Optional[Dict[str, Any]]) -> Optional[int]:
        if not item:
            return None
        raw = item.get("unlock_points")
        if raw is None:
            raw = item.get("cost")
        if raw is None:
            raw = item.get("points")
        text = str(raw or "").strip()
        if not text:
            return 0 if AgentResourceOfficer._resource_has_free_marker(item) else None
        if text.lower() == "free" or text == "免费":
            return 0
        match = re.search(r"-?\d+", text)
        if not match:
            return 0 if AgentResourceOfficer._resource_has_free_marker(item) else None
        try:
            return int(match.group(0))
        except Exception:
            return None

    def _check_hdhive_unlock_points_limit(self, resource: Optional[Dict[str, Any]]) -> Tuple[bool, str, Dict[str, Any]]:
        limit = max(0, self._safe_int(self._hdhive_max_unlock_points, 20))
        if limit <= 0:
            return True, "", {"limit": limit, "points": None, "limited": False}
        points = self._resource_points_value(resource)
        title = self._clean_text((resource or {}).get("title") or (resource or {}).get("matched_title") or "该资源")
        if points is None:
            return True, "", {"limit": limit, "points": None, "limited": False, "reason": "unknown_points", "title": title}
        if points > limit:
            return False, (
                f"已阻止影巢解锁：{title} 需要 {points} 分，超过当前单资源积分上限 {limit} 分。"
                "如确认要解锁，请提高上限或临时设为 0。"
            ), {"limit": limit, "points": points, "limited": True, "reason": "points_over_limit"}
        return True, "", {"limit": limit, "points": points, "limited": False}

    def _default_assistant_preferences(self) -> Dict[str, Any]:
        return {
            "schema_version": "preferences.v1",
            "initialized": False,
            "prefer_resolution": "4K",
            "prefer_dolby_vision": True,
            "prefer_hdr": True,
            "prefer_chinese_subtitle": True,
            "prefer_complete_series": True,
            "prefer_cloud_provider": "",
            "enable_pansou": True,
            "enable_hdhive": True,
            "enable_mp_pt": True,
            "has_quark": True,
            "has_115": True,
            "cloud_default_path": self._hdhive_default_path,
            "quark_default_path": self._quark_default_path,
            "p115_default_path": self._p115_default_path,
            "pt_require_free": False,
            "pt_min_seeders": self._assistant_default_pt_min_seeders,
            "pt_prefer_free": True,
            "hdhive_max_unlock_points": self._hdhive_max_unlock_points,
            "auto_ingest_enabled": self._assistant_default_auto_ingest_enabled,
            "auto_ingest_score_threshold": self._assistant_default_auto_ingest_score_threshold,
            "confirm_score_threshold": self._assistant_default_confirm_score_threshold,
            "updated_at": 0,
        }

    def _normalize_preference_key(self, session: Any = None, user_key: Any = None) -> str:
        key = self._clean_text(user_key)
        if key:
            return key
        session_name = self._clean_text(session) or "default"
        return f"session:{session_name}"

    def _normalize_assistant_preferences(self, value: Optional[Dict[str, Any]] = None) -> Dict[str, Any]:
        defaults = self._default_assistant_preferences()
        payload = dict(value or {})
        if "resolution_priority" in payload and "prefer_resolution" not in payload:
            choices = payload.get("resolution_priority")
            if isinstance(choices, (list, tuple)) and choices:
                payload["prefer_resolution"] = choices[0]
            else:
                payload["prefer_resolution"] = choices
        if "subtitle_priority" in payload and "prefer_chinese_subtitle" not in payload:
            subtitle_text = " ".join(str(item) for item in payload.get("subtitle_priority") or []) if isinstance(payload.get("subtitle_priority"), (list, tuple)) else str(payload.get("subtitle_priority") or "")
            payload["prefer_chinese_subtitle"] = bool(re.search(r"中文|中字|简中|繁中|双语|chinese", subtitle_text, flags=re.IGNORECASE))
        if "pt_free_only" in payload and "pt_require_free" not in payload:
            payload["pt_require_free"] = payload.get("pt_free_only")
        if "preferred_cloud_drive" in payload and "prefer_cloud_provider" not in payload:
            providers = payload.get("preferred_cloud_drive")
            payload["prefer_cloud_provider"] = providers[0] if isinstance(providers, (list, tuple)) and providers else providers
        if "available_sources" in payload:
            sources = payload.get("available_sources")
            if isinstance(sources, (list, tuple, set)):
                source_list = [self._clean_text(item).lower() for item in sources]
                if "enable_pansou" not in payload:
                    payload["enable_pansou"] = "pansou" in source_list or "盘搜" in source_list
                if "enable_hdhive" not in payload:
                    payload["enable_hdhive"] = any(item in source_list for item in ["hdhive", "影巢", "影潮"])
                if "enable_mp_pt" not in payload:
                    payload["enable_mp_pt"] = any(item in source_list for item in ["mp_pt", "mp", "pt", "原生", "moviepilot"])
        if "available_providers" in payload:
            providers = payload.get("available_providers")
            if isinstance(providers, (list, tuple, set)):
                provider_list = [self._clean_text(item).lower() for item in providers]
                if "has_115" not in payload:
                    payload["has_115"] = "115" in provider_list
                if "has_quark" not in payload:
                    payload["has_quark"] = "quark" in provider_list or "夸克" in provider_list
        if "auto_ingest" in payload and "auto_ingest_enabled" not in payload:
            payload["auto_ingest_enabled"] = payload.get("auto_ingest")
        if "auto_execute_score_threshold" in payload and "auto_ingest_score_threshold" not in payload:
            payload["auto_ingest_score_threshold"] = payload.get("auto_execute_score_threshold")
        normalized = {**defaults, **payload}
        normalized["schema_version"] = "preferences.v1"
        normalized["initialized"] = bool(normalized.get("initialized"))
        normalized["prefer_resolution"] = self._clean_text(normalized.get("prefer_resolution") or defaults["prefer_resolution"]).upper()
        normalized["prefer_dolby_vision"] = self._parse_bool_value(normalized.get("prefer_dolby_vision"), True)
        normalized["prefer_hdr"] = self._parse_bool_value(normalized.get("prefer_hdr"), True)
        normalized["prefer_chinese_subtitle"] = self._parse_bool_value(normalized.get("prefer_chinese_subtitle"), True)
        normalized["prefer_complete_series"] = self._parse_bool_value(normalized.get("prefer_complete_series"), True)
        normalized["prefer_cloud_provider"] = self._clean_text(normalized.get("prefer_cloud_provider")).lower()
        normalized["enable_pansou"] = self._parse_bool_value(normalized.get("enable_pansou"), True)
        normalized["enable_hdhive"] = self._parse_bool_value(normalized.get("enable_hdhive"), True)
        normalized["enable_mp_pt"] = self._parse_bool_value(normalized.get("enable_mp_pt"), True)
        if not self._pansou_enabled:
            normalized["enable_pansou"] = False
        if not self._hdhive_resource_enabled:
            normalized["enable_hdhive"] = False
        if not self._mp_pt_enabled:
            normalized["enable_mp_pt"] = False
        normalized["has_quark"] = self._parse_bool_value(normalized.get("has_quark"), True)
        normalized["has_115"] = self._parse_bool_value(normalized.get("has_115"), True)
        normalized["cloud_default_path"] = self._normalize_path(normalized.get("cloud_default_path") or self._hdhive_default_path)
        normalized["quark_default_path"] = self._normalize_path(normalized.get("quark_default_path") or self._quark_default_path)
        normalized["p115_default_path"] = self._normalize_path(normalized.get("p115_default_path") or self._p115_default_path)
        normalized["pt_require_free"] = self._parse_bool_value(normalized.get("pt_require_free"), False)
        normalized["pt_min_seeders"] = max(0, self._safe_int(normalized.get("pt_min_seeders"), 3))
        normalized["pt_prefer_free"] = self._parse_bool_value(normalized.get("pt_prefer_free"), True)
        normalized["hdhive_max_unlock_points"] = max(0, self._safe_int(normalized.get("hdhive_max_unlock_points"), self._hdhive_max_unlock_points))
        normalized["auto_ingest_enabled"] = self._parse_bool_value(normalized.get("auto_ingest_enabled"), False)
        normalized["auto_ingest_score_threshold"] = max(1, min(100, self._safe_int(normalized.get("auto_ingest_score_threshold"), 90)))
        normalized["confirm_score_threshold"] = max(1, min(100, self._safe_int(normalized.get("confirm_score_threshold"), 70)))
        normalized["updated_at"] = self._safe_int(normalized.get("updated_at"), 0)
        return normalized

    def _restore_assistant_preferences(self) -> None:
        try:
            restored = self.get_data(self._assistant_preferences_store_key) or {}
            if isinstance(restored, dict):
                self._assistant_preferences = {
                    self._clean_text(key): self._normalize_assistant_preferences(value)
                    for key, value in restored.items()
                    if self._clean_text(key) and isinstance(value, dict)
                }
        except Exception:
            self._assistant_preferences = {}

    def _persist_assistant_preferences(self) -> None:
        try:
            items = list((self._assistant_preferences or {}).items())[-self._assistant_preferences_limit:]
            self._assistant_preferences = {key: value for key, value in items if key}
            self.save_data(key=self._assistant_preferences_store_key, value=self._assistant_preferences)
        except Exception:
            pass

    def _assistant_preferences_public_data(self, *, session: str = "", user_key: str = "") -> Dict[str, Any]:
        key = self._normalize_preference_key(session=session, user_key=user_key)
        preferences = self._normalize_assistant_preferences((self._assistant_preferences or {}).get(key))
        questions = [
            "你更偏好 4K 还是 1080P？",
            "是否优先杜比视界 / HDR？",
            "是否必须中文字幕？",
            "电视剧是否优先全集或完整季？",
            "你可用哪些源？例如：只用盘搜、只用影巢、只用 MP/PT，或者关闭其中某些源。",
            "你可用哪些云盘？例如：只有夸克、只有 115、两者都可。",
            "PT 资源最低做种数是多少？默认 3。",
            "影巢单资源最多愿意消耗多少积分？默认 20。",
            "是否允许 90 分以上资源自动入库？默认关闭。",
        ]
        return {
            "schema_version": "preferences.v1",
            "key": key,
            "initialized": bool(preferences.get("initialized")),
            "preferences": preferences,
            "needs_onboarding": not bool(preferences.get("initialized")),
            "onboarding_questions": questions if not bool(preferences.get("initialized")) else [],
            "defaults": self._default_assistant_preferences(),
        }

    def _save_assistant_preferences(
        self,
        *,
        session: str = "",
        user_key: str = "",
        preferences: Optional[Dict[str, Any]] = None,
    ) -> Dict[str, Any]:
        key = self._normalize_preference_key(session=session, user_key=user_key)
        current = self._normalize_assistant_preferences((self._assistant_preferences or {}).get(key))
        incoming = dict(preferences or {})
        merged = {**current, **incoming}
        merged["initialized"] = self._parse_bool_value(incoming.get("initialized"), True) if "initialized" in incoming else True
        merged["updated_at"] = int(time.time())
        normalized = self._normalize_assistant_preferences(merged)
        self._assistant_preferences[key] = normalized
        self._persist_assistant_preferences()
        return self._assistant_preferences_public_data(session=session, user_key=key)

    def _reset_assistant_preferences(self, *, session: str = "", user_key: str = "") -> Dict[str, Any]:
        key = self._normalize_preference_key(session=session, user_key=user_key)
        self._assistant_preferences.pop(key, None)
        self._persist_assistant_preferences()
        return self._assistant_preferences_public_data(session=session, user_key=key)

    def _assistant_preferences_status_brief(self, *, session: str = "", user_key: str = "") -> Dict[str, Any]:
        data = self._assistant_preferences_public_data(session=session, user_key=user_key)
        prefs = dict(data.get("preferences") or {})
        brief = {
            "key": data.get("key"),
            "initialized": bool(data.get("initialized")),
            "needs_onboarding": bool(data.get("needs_onboarding")),
            "summary": {
                "prefer_resolution": self._clean_text(prefs.get("prefer_resolution")),
                "prefer_dolby_vision": bool(prefs.get("prefer_dolby_vision")),
                "prefer_hdr": bool(prefs.get("prefer_hdr")),
                "prefer_chinese_subtitle": bool(prefs.get("prefer_chinese_subtitle")),
                "prefer_complete_series": bool(prefs.get("prefer_complete_series")),
                "prefer_cloud_provider": self._clean_text(prefs.get("prefer_cloud_provider")),
                "enable_pansou": bool(prefs.get("enable_pansou")),
                "enable_hdhive": bool(prefs.get("enable_hdhive")),
                "enable_mp_pt": bool(prefs.get("enable_mp_pt")),
                "has_quark": bool(prefs.get("has_quark")),
                "has_115": bool(prefs.get("has_115")),
                "pt_min_seeders": self._safe_int(prefs.get("pt_min_seeders"), 3),
                "pt_require_free": bool(prefs.get("pt_require_free")),
                "hdhive_max_unlock_points": self._safe_int(prefs.get("hdhive_max_unlock_points"), self._hdhive_max_unlock_points),
                "auto_ingest_enabled": bool(prefs.get("auto_ingest_enabled")),
                "auto_ingest_score_threshold": self._safe_int(prefs.get("auto_ingest_score_threshold"), 90),
            },
        }
        if brief["needs_onboarding"]:
            brief["onboarding_questions"] = data.get("onboarding_questions") or []
            brief["recommended_action"] = "ask_user_preferences_then_save"
        return brief

    def _assistant_default_preferences_template(self) -> Dict[str, Any]:
        prefs = self._default_assistant_preferences()
        return {
            "prefer_resolution": prefs.get("prefer_resolution"),
            "prefer_dolby_vision": prefs.get("prefer_dolby_vision"),
            "prefer_hdr": prefs.get("prefer_hdr"),
            "prefer_chinese_subtitle": prefs.get("prefer_chinese_subtitle"),
            "prefer_complete_series": prefs.get("prefer_complete_series"),
            "prefer_cloud_provider": prefs.get("prefer_cloud_provider"),
            "enable_pansou": prefs.get("enable_pansou"),
            "enable_hdhive": prefs.get("enable_hdhive"),
            "enable_mp_pt": prefs.get("enable_mp_pt"),
            "has_quark": prefs.get("has_quark"),
            "has_115": prefs.get("has_115"),
            "pt_require_free": prefs.get("pt_require_free"),
            "pt_min_seeders": prefs.get("pt_min_seeders"),
            "hdhive_max_unlock_points": prefs.get("hdhive_max_unlock_points"),
            "p115_default_path": prefs.get("p115_default_path"),
            "quark_default_path": prefs.get("quark_default_path"),
            "auto_ingest_enabled": prefs.get("auto_ingest_enabled"),
            "auto_ingest_score_threshold": prefs.get("auto_ingest_score_threshold"),
        }

    def _assistant_preferences_for_session(self, session: str = "", user_key: str = "") -> Dict[str, Any]:
        key = self._normalize_preference_key(session=session, user_key=user_key)
        return self._normalize_assistant_preferences((self._assistant_preferences or {}).get(key))

    def _assistant_source_enabled(self, preferences: Optional[Dict[str, Any]], source_type: str) -> bool:
        prefs = self._normalize_assistant_preferences(preferences)
        source = self._clean_text(source_type).lower()
        if source == "pansou":
            return bool(prefs.get("enable_pansou"))
        if source == "hdhive":
            return bool(prefs.get("enable_hdhive"))
        if source in {"mp", "mp_pt", "pt"}:
            return bool(prefs.get("enable_mp_pt"))
        return True

    def _assistant_available_cloud_providers(self, preferences: Optional[Dict[str, Any]]) -> List[str]:
        prefs = self._normalize_assistant_preferences(preferences)
        providers: List[str] = []
        if self._parse_bool_value(prefs.get("has_115"), True):
            providers.append("115")
        if self._parse_bool_value(prefs.get("has_quark"), True):
            providers.append("quark")
        return providers

    def _assistant_enabled_cloud_source_order(
        self,
        *,
        session: str = "",
        source_order: Optional[List[str]] = None,
        session_overrides: Optional[Dict[str, Any]] = None,
    ) -> List[str]:
        preferences = self._assistant_smart_merge_session_preferences(
            self._assistant_preferences_for_session(session=session),
            session_overrides=session_overrides,
        )
        return self._assistant_smart_search_source_order(
            preferences,
            source_order=source_order or ["pansou", "hdhive"],
        )

    def _assistant_transfer_source_order(
        self,
        *,
        preferences: Optional[Dict[str, Any]],
        prefer_provider: str = "",
        requested_source_order: Optional[List[str]] = None,
    ) -> List[str]:
        prefs = self._normalize_assistant_preferences(preferences)
        pansou_enabled = self._assistant_source_enabled(prefs, "pansou")
        hdhive_enabled = self._assistant_source_enabled(prefs, "hdhive")
        provider = self._clean_text(prefer_provider).lower()
        if provider == "quark":
            return ["pansou"] if pansou_enabled else []
        if provider == "115":
            return ["pansou"] if pansou_enabled else []
        return self._assistant_smart_search_source_order(
            prefs,
            source_order=requested_source_order or ["pansou", "hdhive"],
        )

    def _assistant_filter_cloud_items_by_preferences(
        self,
        items: Optional[List[Dict[str, Any]]],
        preferences: Optional[Dict[str, Any]],
    ) -> List[Dict[str, Any]]:
        available = set(self._assistant_available_cloud_providers(preferences))
        source_items = [dict(item or {}) for item in (items or []) if isinstance(item, dict)]
        if not available:
            return []
        if available == {"115", "quark"}:
            return source_items

        filtered: List[Dict[str, Any]] = []
        for item in source_items:
            provider = self._clean_text(
                item.get("pan_type")
                or item.get("provider")
                or item.get("channel")
                or item.get("network")
                or item.get("netdisk")
                or item.get("cloud")
            ).lower()
            if provider in {"quark", "夸克", "quarkcloud"}:
                provider = "quark"
            elif provider in {"115", "115cloud", "115网盘"}:
                provider = "115"
            if provider in available:
                filtered.append(item)
        return filtered

    def _assistant_smart_search_source_order(
        self,
        preferences: Optional[Dict[str, Any]],
        source_order: Optional[List[str]] = None,
    ) -> List[str]:
        prefs = self._normalize_assistant_preferences(preferences)
        requested = [self._clean_text(item).lower() for item in (source_order or []) if self._clean_text(item)]
        order = requested or ["pansou", "hdhive", "mp_pt"]
        normalized: List[str] = []
        for item in order:
            if item in {"mp", "pt"}:
                item = "mp_pt"
            if item not in {"pansou", "hdhive", "mp_pt"} or item in normalized:
                continue
            if self._assistant_source_enabled(prefs, item):
                normalized.append(item)
        return normalized

    def _assistant_smart_source_availability(
        self,
        preferences: Optional[Dict[str, Any]],
        *,
        source_order: Optional[List[str]] = None,
    ) -> Tuple[List[Dict[str, Any]], List[Dict[str, Any]]]:
        prefs = self._normalize_assistant_preferences(preferences)
        available_cloud = self._assistant_available_cloud_providers(prefs)
        order = self._assistant_smart_search_source_order(prefs, source_order=source_order)
        source_labels = {
            "pansou": "盘搜",
            "hdhive": "影巢",
            "mp_pt": "MP/PT",
        }
        available: List[Dict[str, Any]] = []
        blocked: List[Dict[str, Any]] = []
        for source in ["pansou", "hdhive", "mp_pt"]:
            entry = {
                "source_type": source,
                "label": source_labels[source],
            }
            if source not in order:
                if not self._assistant_source_enabled(prefs, source):
                    blocked.append({**entry, "reason": f"当前偏好已关闭{source_labels[source]}"})
                else:
                    blocked.append({**entry, "reason": "当前决策顺序未包含该源"})
                continue
            if source in {"pansou", "hdhive"} and not available_cloud:
                blocked.append({**entry, "reason": "当前偏好未启用任何云盘"})
                continue
            available.append({
                **entry,
                "provider_scope": list(available_cloud) if source in {"pansou", "hdhive"} else ["pt"],
            })
        if "115" not in available_cloud:
            blocked.append({"source_type": "115", "label": "115", "reason": "当前偏好未启用 115"})
        if "quark" not in available_cloud:
            blocked.append({"source_type": "quark", "label": "夸克", "reason": "当前偏好未启用夸克"})
        return available, blocked

    def _assistant_smart_decision_preferences(
        self,
        preferences: Optional[Dict[str, Any]],
        *,
        decision_profile: str = "",
    ) -> Dict[str, Any]:
        prefs = self._normalize_assistant_preferences(preferences)
        profile = self._clean_text(decision_profile).lower()
        if not profile:
            return prefs
        updated = dict(prefs)
        confirm_threshold = self._safe_int(
            updated.get("confirm_score_threshold"),
            self._assistant_default_confirm_score_threshold,
        )
        if profile == "conservative":
            updated["confirm_score_threshold"] = max(confirm_threshold, min(95, confirm_threshold + 10))
        elif profile == "aggressive":
            updated["confirm_score_threshold"] = max(40, min(100, confirm_threshold - 10))
        return self._normalize_assistant_preferences(updated)

    def _assistant_smart_session_overrides_summary(self, overrides: Optional[Dict[str, Any]]) -> str:
        raw = dict(overrides or {})
        if not raw:
            return ""
        payload = self._normalize_assistant_preferences(raw)
        parts: List[str] = []
        if "has_quark" in raw or "has_115" in raw:
            if payload.get("has_quark") and not payload.get("has_115"):
                parts.append("只用夸克")
            elif payload.get("has_115") and not payload.get("has_quark"):
                parts.append("只用115")
            elif payload.get("has_115") and payload.get("has_quark"):
                parts.append("115 / 夸克都可")
        if "enable_pansou" in raw or "enable_hdhive" in raw or "enable_mp_pt" in raw:
            enabled_sources: List[str] = []
            if payload.get("enable_pansou"):
                enabled_sources.append("盘搜")
            if payload.get("enable_hdhive"):
                enabled_sources.append("影巢")
            if payload.get("enable_mp_pt"):
                enabled_sources.append("MP/PT")
            if enabled_sources:
                parts.append("仅会话源：" + " / ".join(enabled_sources))
        return "；".join(parts[:2])

    def _assistant_smart_merge_session_preferences(
        self,
        preferences: Optional[Dict[str, Any]],
        *,
        session_overrides: Optional[Dict[str, Any]] = None,
        decision_profile: str = "",
    ) -> Dict[str, Any]:
        merged = {
            **self._normalize_assistant_preferences(preferences),
            **dict(session_overrides or {}),
        }
        return self._assistant_smart_decision_preferences(
            merged,
            decision_profile=decision_profile,
        )

    def _assistant_smart_apply_session_override(
        self,
        session_overrides: Optional[Dict[str, Any]],
        *,
        adjust_action: str,
        source_order: Optional[List[str]] = None,
    ) -> Tuple[Dict[str, Any], List[str]]:
        overrides = dict(session_overrides or {})
        order = [self._clean_text(item).lower() for item in (source_order or []) if self._clean_text(item)]
        normalized_action = self._clean_text(adjust_action).lower()
        if normalized_action == "decision_only_quark":
            overrides["has_quark"] = True
            overrides["has_115"] = False
            overrides["prefer_cloud_provider"] = "quark"
        elif normalized_action == "decision_only_115":
            overrides["has_quark"] = False
            overrides["has_115"] = True
            overrides["prefer_cloud_provider"] = "115"
        elif normalized_action == "decision_cloud_both":
            overrides["has_quark"] = True
            overrides["has_115"] = True
            overrides["prefer_cloud_provider"] = ""
        elif normalized_action == "decision_only_mp_pt":
            overrides["enable_pansou"] = False
            overrides["enable_hdhive"] = False
            overrides["enable_mp_pt"] = True
            order = ["mp_pt"]
        elif normalized_action == "decision_only_pansou":
            overrides["enable_pansou"] = True
            overrides["enable_hdhive"] = False
            overrides["enable_mp_pt"] = False
            order = ["pansou"]
        elif normalized_action == "decision_only_hdhive":
            overrides["enable_pansou"] = False
            overrides["enable_hdhive"] = True
            overrides["enable_mp_pt"] = False
            order = ["hdhive"]
        elif normalized_action == "decision_disable_pansou":
            overrides["enable_pansou"] = False
        elif normalized_action == "decision_disable_hdhive":
            overrides["enable_hdhive"] = False
        elif normalized_action == "decision_disable_mp_pt":
            overrides["enable_mp_pt"] = False
        elif normalized_action == "decision_reset_preferences":
            overrides = {}
            order = []
        return overrides, order

    def _parse_assistant_preferences_text(self, text: str) -> Dict[str, Any]:
        raw = self._clean_text(text)
        compact = re.sub(r"\s+", "", raw).lower()
        payload: Dict[str, Any] = {}
        if re.search(r"1080|fhd", raw, flags=re.IGNORECASE):
            payload["prefer_resolution"] = "1080P"
        elif re.search(r"4k|2160|uhd", raw, flags=re.IGNORECASE):
            payload["prefer_resolution"] = "4K"

        if re.search(r"(不要|不需要|关闭|禁用).{0,4}(杜比|dv)", raw, flags=re.IGNORECASE):
            payload["prefer_dolby_vision"] = False
        elif re.search(r"杜比|dv|dolby", raw, flags=re.IGNORECASE):
            payload["prefer_dolby_vision"] = True

        if re.search(r"(不要|不需要|关闭|禁用).{0,4}hdr", raw, flags=re.IGNORECASE):
            payload["prefer_hdr"] = False
        elif re.search(r"hdr", raw, flags=re.IGNORECASE):
            payload["prefer_hdr"] = True

        if re.search(r"(不要|不需要|关闭|禁用).{0,6}(中字|中文|字幕)", raw, flags=re.IGNORECASE) or re.search(r"无字幕也可|字幕无所谓", raw):
            payload["prefer_chinese_subtitle"] = False
        elif re.search(r"中字|中文|简中|繁中|双语字幕|字幕", raw, flags=re.IGNORECASE):
            payload["prefer_chinese_subtitle"] = True

        if re.search(r"不强求全集|不要全集|单集也可|更新也可", raw):
            payload["prefer_complete_series"] = False
        elif re.search(r"全集|完整季|整季|完结", raw):
            payload["prefer_complete_series"] = True

        if re.search(r"夸克优先|优先夸克|quark", raw, flags=re.IGNORECASE):
            payload["prefer_cloud_provider"] = "quark"
        elif re.search(r"115优先|优先115", raw):
            payload["prefer_cloud_provider"] = "115"

        if re.search(r"只用盘搜|仅用盘搜|只搜盘搜", raw):
            payload["enable_pansou"] = True
            payload["enable_hdhive"] = False
            payload["enable_mp_pt"] = False
        elif re.search(r"只用影巢|仅用影巢|只搜影巢|只用影潮", raw):
            payload["enable_pansou"] = False
            payload["enable_hdhive"] = True
            payload["enable_mp_pt"] = False
        elif re.search(r"只用原生|只用pt|仅用pt|只搜pt|只搜原生|只要原生", raw, flags=re.IGNORECASE):
            payload["enable_pansou"] = False
            payload["enable_hdhive"] = False
            payload["enable_mp_pt"] = True
        if re.search(r"(不要|不用|关闭|禁用).{0,4}盘搜", raw):
            payload["enable_pansou"] = False
        elif re.search(r"(启用|使用|打开).{0,4}盘搜", raw):
            payload["enable_pansou"] = True
        if re.search(r"(不要|不用|关闭|禁用).{0,4}(影巢|影潮)", raw):
            payload["enable_hdhive"] = False
        elif re.search(r"(启用|使用|打开).{0,4}(影巢|影潮)", raw):
            payload["enable_hdhive"] = True
        if re.search(r"(不要|不用|关闭|禁用).{0,4}(pt|原生)", raw, flags=re.IGNORECASE):
            payload["enable_mp_pt"] = False
        elif re.search(r"(启用|使用|打开).{0,4}(pt|原生)", raw, flags=re.IGNORECASE):
            payload["enable_mp_pt"] = True

        if re.search(r"只有夸克|仅有夸克|只用夸克|没有115|不用115", raw, flags=re.IGNORECASE):
            payload["has_quark"] = True
            payload["has_115"] = False
        elif re.search(r"只有115|仅有115|只用115|没有夸克|不用夸克", raw, flags=re.IGNORECASE):
            payload["has_115"] = True
            payload["has_quark"] = False
        if re.search(r"(不要|不用|关闭|禁用).{0,4}夸克", raw, flags=re.IGNORECASE):
            payload["has_quark"] = False
        elif re.search(r"(启用|使用|打开).{0,4}夸克", raw, flags=re.IGNORECASE):
            payload["has_quark"] = True
        if re.search(r"(不要|不用|关闭|禁用).{0,4}115", raw):
            payload["has_115"] = False
        elif re.search(r"(启用|使用|打开).{0,4}115", raw):
            payload["has_115"] = True

        if re.search(r"pt.{0,4}(只要|必须).{0,4}免费|只下免费|只要免费", raw, flags=re.IGNORECASE):
            payload["pt_require_free"] = True
        elif re.search(r"pt.{0,4}(不限|不强求).{0,4}免费|不只要免费|免费不强求", raw, flags=re.IGNORECASE):
            payload["pt_require_free"] = False

        seed_match = re.search(r"(?:做种|种子|seeders?|seeder)[^\d]{0,8}(\d+)", raw, flags=re.IGNORECASE)
        if seed_match:
            payload["pt_min_seeders"] = self._safe_int(seed_match.group(1), 3)

        points_match = re.search(r"(?:影巢|积分|解锁)[^\d]{0,10}(\d+)", raw)
        if points_match:
            payload["hdhive_max_unlock_points"] = self._safe_int(points_match.group(1), self._hdhive_max_unlock_points)

        if re.search(r"(不|不要|关闭|禁用).{0,4}自动入库", raw):
            payload["auto_ingest_enabled"] = False
        elif re.search(r"自动入库|自动下载|自动转存", raw):
            payload["auto_ingest_enabled"] = True

        threshold_match = re.search(r"(?:自动入库(?:评分|分数|阈值)|评分阈值|分数阈值|阈值)[^\d]{0,10}(\d{2,3})", raw)
        if threshold_match:
            payload["auto_ingest_score_threshold"] = self._safe_int(threshold_match.group(1), 90)

        for key, target in [
            ("115目录", "p115_default_path"),
            ("p115目录", "p115_default_path"),
            ("夸克目录", "quark_default_path"),
            ("quark目录", "quark_default_path"),
            ("云盘目录", "cloud_default_path"),
        ]:
            match = re.search(rf"{re.escape(key)}\s*=\s*([^\s，,]+)", raw, flags=re.IGNORECASE)
            if match:
                payload[target] = self._normalize_path(match.group(1))

        if "initialized" not in payload and payload:
            payload["initialized"] = True
        if "auto_ingest_score_threshold" in payload:
            payload["auto_ingest_score_threshold"] = max(1, min(100, self._safe_int(payload["auto_ingest_score_threshold"], 90)))
        if "pt_min_seeders" in payload:
            payload["pt_min_seeders"] = max(0, self._safe_int(payload["pt_min_seeders"], 3))
        if "hdhive_max_unlock_points" in payload:
            payload["hdhive_max_unlock_points"] = max(0, self._safe_int(payload["hdhive_max_unlock_points"], self._hdhive_max_unlock_points))
        return payload

    @staticmethod
    def _score_text_blob(item: Any) -> str:
        if isinstance(item, dict):
            parts: List[str] = []
            for value in item.values():
                if isinstance(value, (dict, list, tuple)):
                    parts.append(AgentResourceOfficer._score_text_blob(value))
                elif value is not None:
                    parts.append(str(value))
            return " ".join(parts).lower()
        if isinstance(item, (list, tuple)):
            return " ".join(AgentResourceOfficer._score_text_blob(value) for value in item).lower()
        return str(item or "").lower()

    @staticmethod
    def _score_has_any(text: str, keywords: List[str]) -> bool:
        return any(keyword.lower() in text for keyword in keywords)

    @classmethod
    def _score_quality_rank(cls, item: Any) -> int:
        text = cls._score_text_blob(item)
        rank = 0
        if cls._score_has_any(text, ["dolby vision", "dovi", "dv", "杜比视界"]):
            rank += 60
        if cls._score_has_any(text, ["hdr10", "hdr", "hlg", "杜比", "臻彩"]):
            rank += 45
        if cls._score_has_any(text, ["60fps", "60帧", "50fps", "50帧", "高帧率"]):
            rank += 35
        if cls._score_has_any(text, ["4k", "2160", "uhd"]):
            rank += 25
        if cls._score_has_any(text, ["高码率", "remux", "原盘", "web-dl", "webrip"]):
            rank += 15
        if cls._score_has_any(text, ["e01", "s01", "全集", "全季", "更新至", "更至"]):
            rank += 10
        if cls._score_has_any(text, ["中字", "简中", "繁中", "内封", "内嵌", "字幕"]):
            rank += 8
        return rank

    @staticmethod
    def _extract_series_progress(text: str) -> Dict[str, int]:
        blob = str(text or "").lower()
        result = {"max_episode": 0, "episode_count": 0}
        episodes: List[int] = []
        for pattern in (
            r"\be(\d{1,3})\b",
            r"第\s*(\d{1,3})\s*集",
            r"更新(?:至)?\s*(?:ep|e)?\s*0*(\d{1,3})",
            r"更(?:至)?\s*0*(\d{1,3})\s*集",
        ):
            for match in re.finditer(pattern, blob, flags=re.IGNORECASE):
                try:
                    episodes.append(int(match.group(1)))
                except Exception:
                    continue
        for pattern in (
            r"e0*(\d{1,3})\s*[-~—]\s*e?0*(\d{1,3})",
            r"第?\s*0*(\d{1,3})\s*[-~—]\s*0*(\d{1,3})\s*集",
        ):
            match = re.search(pattern, blob, flags=re.IGNORECASE)
            if not match:
                continue
            try:
                start_ep = int(match.group(1))
                end_ep = int(match.group(2))
            except Exception:
                continue
            if end_ep >= start_ep > 0:
                result["episode_count"] = max(result["episode_count"], end_ep - start_ep + 1)
                episodes.extend([start_ep, end_ep])
        if episodes:
            result["max_episode"] = max(episodes)
        if result["episode_count"] <= 0 and len(set(episodes)) >= 2:
            sorted_eps = sorted(set(episodes))
            if sorted_eps == list(range(sorted_eps[0], sorted_eps[-1] + 1)):
                result["episode_count"] = len(sorted_eps)
        return result

    @staticmethod
    def _score_level(score: int) -> str:
        if score >= 90:
            return "excellent"
        if score >= 70:
            return "confirm"
        return "low"

    def _score_decision(
        self,
        *,
        score: int,
        risk_reasons: List[str],
        hard_risk_reasons: Optional[List[str]] = None,
        preferences: Dict[str, Any],
        default_action: str,
    ) -> Dict[str, Any]:
        threshold = max(1, min(100, self._safe_int(preferences.get("auto_ingest_score_threshold"), 90)))
        confirm_threshold = max(1, min(100, self._safe_int(preferences.get("confirm_score_threshold"), 70)))
        auto_enabled = self._parse_bool_value(preferences.get("auto_ingest_enabled"), False)
        hard_risks = [self._clean_text(item) for item in (hard_risk_reasons or []) if self._clean_text(item)]
        hard_risk = bool(hard_risks)
        can_auto = bool(auto_enabled and not hard_risk and score >= threshold)
        if can_auto:
            recommended = default_action
        elif score >= confirm_threshold and not hard_risk:
            recommended = "ask_confirm"
        else:
            recommended = "do_not_auto"
        return {
            "score": score,
            "score_level": self._score_level(score),
            "risk_reasons": risk_reasons,
            "hard_risk_reasons": hard_risks,
            "can_auto_execute": can_auto,
            "recommended_action": recommended,
            "auto_ingest_enabled": auto_enabled,
            "auto_ingest_score_threshold": threshold,
            "confirm_score_threshold": confirm_threshold,
        }

    def _score_cloud_resource(
        self,
        item: Dict[str, Any],
        *,
        preferences: Optional[Dict[str, Any]] = None,
        source_type: str = "cloud",
        target_path: str = "",
    ) -> Dict[str, Any]:
        prefs = self._normalize_assistant_preferences(preferences)
        text = self._score_text_blob(item)
        score = 20
        reasons: List[str] = []
        risks: List[str] = []
        hard_risks: List[str] = []
        resolution_pref = self._clean_text(prefs.get("prefer_resolution")).lower()
        provider = self._clean_text(item.get("pan_type") or item.get("channel")).lower()
        media_type = self._clean_text(item.get("media_type") or item.get("type")).lower()
        series_like = (
            media_type in {"tv", "series", "电视剧", "剧集", "番剧"}
            or bool(re.search(r"\bs\d{1,2}\b|\be\d{1,3}\b|season|第\s*\d+\s*集|[全整]季|全集|完结|更至|更新至|短剧|剧集", text, flags=re.IGNORECASE))
        )
        series_progress = self._extract_series_progress(text)

        if "2160" in text or "4k" in text or "uhd" in text:
            score += 25
            reasons.append("4K/UHD +25")
        elif "1080" in text:
            score += 16
            reasons.append("1080P +16")
        elif "720" in text:
            score += 6
            reasons.append("720P +6")
        if resolution_pref and resolution_pref in text:
            score += 5
            reasons.append(f"匹配偏好分辨率 {resolution_pref.upper()} +5")

        if self._score_has_any(text, ["dolby vision", "dovi", "dv", "杜比视界"]):
            score += 18
            reasons.append("杜比视界 +18")
        elif self._score_has_any(text, ["hdr10", "hdr", "hlg", "杜比"]):
            score += 12
            reasons.append("HDR +12")
        if self._score_has_any(text, ["60fps", "60帧", "50fps", "50帧", "高帧率"]):
            score += 4
            reasons.append("高帧率 +4")

        if self._score_has_any(text, ["中字", "中文字幕", "简中", "繁中", "内封简繁", "双语", "官中"]):
            score += 14
            reasons.append("中文字幕 +14")
        elif self._parse_bool_value(prefs.get("prefer_chinese_subtitle"), True):
            score -= 5
            risks.append("未识别到中文字幕")

        completeness_detected = self._score_has_any(text, ["全集", "全季", "完结", "complete", "全 ", "更至", "更0", "更新至"])
        if not completeness_detected and series_like and series_progress.get("episode_count", 0) >= 3:
            completeness_detected = True

        if completeness_detected:
            score += 12
            reasons.append("完整度信息 +12")
        elif series_like and self._parse_bool_value(prefs.get("prefer_complete_series"), True):
            score -= 6
            risks.append("未识别到全集/更新完整度")

        if series_like and series_progress.get("max_episode", 0) > 0:
            progress_bonus = min(10, series_progress["max_episode"])
            if progress_bonus > 0:
                score += progress_bonus
                reasons.append(f"更新到 E{series_progress['max_episode']:02d} +{progress_bonus}")
            if series_progress["max_episode"] >= 7:
                latest_bonus = min(4, series_progress["max_episode"] - 6)
                if latest_bonus > 0:
                    score += latest_bonus
                    reasons.append(f"更新进度领先 +{latest_bonus}")
        if series_like and series_progress.get("episode_count", 0) >= 3:
            pack_bonus = min(12, series_progress["episode_count"] + 2)
            score += pack_bonus
            reasons.append(f"连续剧集包 +{pack_bonus}")
            if series_progress["episode_count"] >= series_progress.get("max_episode", 0) >= 3:
                score += 4
                reasons.append("从 E01 连续覆盖到当前 +4")

        if self._score_has_any(text, ["remux", "原盘", "blu-ray", "bluray", "web-dl", "高码率"]):
            score += 8
            reasons.append("片源质量标识 +8")

        prefer_provider = self._clean_text(prefs.get("prefer_cloud_provider")).lower()
        if prefer_provider and provider and prefer_provider == provider:
            score += 5
            reasons.append(f"匹配网盘偏好 {provider} +5")
        if provider == "115" and not self._parse_bool_value(prefs.get("has_115"), True):
            message = "当前偏好未启用 115"
            risks.append(message)
            hard_risks.append(message)
            score -= 30
        if provider == "quark" and not self._parse_bool_value(prefs.get("has_quark"), True):
            message = "当前偏好未启用夸克"
            risks.append(message)
            hard_risks.append(message)
            score -= 30
        if target_path and target_path in {
            self._clean_text(prefs.get("cloud_default_path")),
            self._clean_text(prefs.get("p115_default_path")),
            self._clean_text(prefs.get("quark_default_path")),
        }:
            score += 3
            reasons.append("匹配默认目录 +3")

        if source_type == "hdhive":
            limit = max(0, self._safe_int(prefs.get("hdhive_max_unlock_points"), self._hdhive_max_unlock_points))
            points = self._resource_points_value(item)
            if points == 0:
                score += 10
                reasons.append("影巢免费 +10")
            elif points is None and limit > 0:
                reasons.append("影巢未标积分")
            elif limit > 0 and points is not None and points > limit:
                score -= 30
                message = f"影巢积分 {points} 超过上限 {limit}，禁止自动解锁"
                risks.append(message)
                hard_risks.append(message)
            elif points is not None:
                score += max(0, 10 - points)
                reasons.append(f"影巢积分 {points}")

        final_score = max(0, min(100, score))
        decision = self._score_decision(
            score=final_score,
            risk_reasons=risks,
            hard_risk_reasons=hard_risks,
            preferences=prefs,
            default_action="auto_ingest_cloud",
        )
        return {
            **decision,
            "source_type": source_type,
            "score_reasons": reasons,
        }

    def _score_pt_resource(
        self,
        item: Dict[str, Any],
        *,
        preferences: Optional[Dict[str, Any]] = None,
    ) -> Dict[str, Any]:
        prefs = self._normalize_assistant_preferences(preferences)
        text = self._score_text_blob(item)
        torrent = item.get("torrent_info") if isinstance(item.get("torrent_info"), dict) else item
        meta = item.get("meta_info") if isinstance(item.get("meta_info"), dict) else {}
        media = item.get("media_info") if isinstance(item.get("media_info"), dict) else {}
        score = 20
        reasons: List[str] = []
        risks: List[str] = []
        hard_risks: List[str] = []
        min_seeders = max(0, self._safe_int(prefs.get("pt_min_seeders"), 3))
        seeders = self._safe_int(torrent.get("seeders"), 0)
        peers = self._safe_int(torrent.get("peers"), 0)
        volume = self._clean_text(torrent.get("volume_factor") or item.get("volume_factor")).lower()
        title = self._clean_text(torrent.get("title"))
        site_name = self._clean_text(torrent.get("site_name"))
        group_name = self._clean_text(meta.get("resource_team"))
        media_title = self._clean_text(media.get("title")).lower()
        media_year = self._clean_text(media.get("year"))
        resolution_pref = self._clean_text(prefs.get("prefer_resolution")).lower()
        prefer_dovi = self._parse_bool_value(prefs.get("prefer_dolby_vision"), True)
        prefer_hdr = self._parse_bool_value(prefs.get("prefer_hdr"), True)
        prefer_subtitle = self._parse_bool_value(prefs.get("prefer_chinese_subtitle"), True)
        prefer_complete = self._parse_bool_value(prefs.get("prefer_complete_series"), True)

        if seeders <= 0:
            message = "做种数 0，禁止自动下载"
            risks.append(message)
            hard_risks.append(message)
            score -= 35
        elif seeders < min_seeders:
            message = f"做种数 {seeders}，低于阈值 {min_seeders}，禁止自动下载"
            risks.append(message)
            hard_risks.append(message)
            score -= 25
        elif seeders >= 20:
            score += 22
            reasons.append(f"做种数 {seeders} +22")
        elif seeders >= 10:
            score += 16
            reasons.append(f"做种数 {seeders} +16")
        else:
            score += 10
            reasons.append(f"做种数 {seeders} +10")

        if peers >= seeders * 5 and seeders < 5:
            score -= 8
            risks.append("下载需求高但做种偏低")
        elif peers >= max(8, seeders):
            score += 6
            reasons.append(f"下载热度 {peers} +6")
        elif peers >= 3:
            score += 3
            reasons.append(f"下载热度 {peers} +3")

        if self._score_has_any(volume, ["free", "免费", "2xfree", "2x free", "freeleech"]):
            score += 18
            reasons.append("免费/促销 +18")
        elif self._parse_bool_value(prefs.get("pt_require_free"), False):
            score -= 20
            message = "用户要求 PT 免费资源"
            risks.append(message)
            hard_risks.append(message)
        elif self._parse_bool_value(prefs.get("pt_prefer_free"), True):
            reasons.append("普通 PT 资源，未额外扣分")

        if "2160" in text or "4k" in text or "uhd" in text:
            score += 20
            reasons.append("4K/UHD +20")
        elif "1080" in text:
            score += 12
            reasons.append("1080P +12")
        elif "720" in text:
            score += 4
            reasons.append("720P +4")
        if resolution_pref and resolution_pref in text:
            score += 6
            reasons.append(f"匹配偏好分辨率 {resolution_pref.upper()} +6")
        has_dovi = self._score_has_any(text, ["dolby vision", "dovi", "dv", "杜比视界"])
        has_hdr = self._score_has_any(text, ["hdr10", "hdr", "hlg"])
        if has_dovi:
            score += 14
            reasons.append("杜比视界 +14")
        elif prefer_dovi:
            score -= 4
            risks.append("未识别到杜比视界")
        if has_hdr:
            score += 9
            reasons.append("HDR +9")
        elif prefer_hdr:
            score -= 2
            risks.append("未识别到 HDR")
        if self._score_has_any(text, ["中字", "简中", "繁中", "双语", "内封", "字幕"]):
            score += 10
            reasons.append("字幕信息 +10")
        elif prefer_subtitle:
            score -= 5
            risks.append("未识别到中文字幕")
        if self._score_has_any(text, ["remux", "原盘", "blu-ray", "bluray", "web-dl", "高码率"]):
            score += 8
            reasons.append("片源质量标识 +8")
        if self._score_has_any(text, ["s01", "season", "全集", "全季", "complete", "完结", "更新至", "更至"]):
            score += 6
            reasons.append("季/全集标识 +6")
        elif prefer_complete and self._score_has_any(text, ["s01", "s02", "e01", "第1集", "season"]):
            score -= 4
            risks.append("未识别到全集/完整季")

        if media_title:
            if media_title in title.lower():
                score += 8
                reasons.append("标题匹配媒体名 +8")
            else:
                score -= 4
                risks.append("标题与识别媒体名匹配一般")
        if media_year and media_year in title:
            score += 4
            reasons.append(f"年份匹配 {media_year} +4")
        if site_name:
            score += 2
            reasons.append(f"站点标识 {site_name} +2")
        if group_name:
            score += 2
            reasons.append(f"发布组 {group_name} +2")

        size_text = self._clean_text(torrent.get("size") or item.get("size"))
        size_value = 0.0
        size_match = re.search(r"(\d+(?:\.\d+)?)\s*(tb|gb|mb)", size_text, flags=re.IGNORECASE)
        if size_match:
            size_value = float(size_match.group(1))
            unit = size_match.group(2).lower()
            if unit == "tb":
                size_value *= 1024
            elif unit == "mb":
                size_value /= 1024
        if size_value > 0:
            if self._score_has_any(text, ["2160", "4k", "uhd", "remux", "原盘"]) and size_value < 8:
                score -= 6
                risks.append(f"体积 {size_text} 偏小，需留意是否压制过度")
            elif self._score_has_any(text, ["1080", "web-dl", "bluray"]) and size_value >= 4:
                score += 3
                reasons.append(f"体积 {size_text} 较充足 +3")
        if peers >= 30 and seeders >= min_seeders:
            score += 4
            reasons.append("热度稳定 +4")

        final_score = max(0, min(100, score))
        decision = self._score_decision(
            score=final_score,
            risk_reasons=risks,
            hard_risk_reasons=hard_risks,
            preferences=prefs,
            default_action="auto_download_pt",
        )
        return {
            **decision,
            "source_type": "pt",
            "score_reasons": reasons,
            "seeders": seeders,
            "peers": peers,
            "min_seeders": min_seeders,
            "volume_factor": volume,
            "site_name": site_name,
            "resource_team": group_name,
        }

    def _attach_cloud_scores(
        self,
        items: List[Dict[str, Any]],
        *,
        preferences: Optional[Dict[str, Any]] = None,
        source_type: str = "cloud",
        target_path: str = "",
    ) -> List[Dict[str, Any]]:
        return [
            {
                **dict(item or {}),
                "score": self._score_cloud_resource(
                    dict(item or {}),
                    preferences=preferences,
                    source_type=source_type,
                    target_path=target_path,
                ),
            }
            for item in items
            if isinstance(item, dict)
        ]

    def _rank_pansou_items(
        self,
        items: List[Dict[str, Any]],
        *,
        channel_order: Optional[List[str]] = None,
        limit_per_channel: int = 20,
    ) -> List[Dict[str, Any]]:
        grouped: Dict[str, List[Dict[str, Any]]] = {}
        for item in items:
            if not isinstance(item, dict):
                continue
            channel = self._normalize_pansou_channel_name(item.get("channel"))
            grouped.setdefault(channel, []).append(dict(item))

        def sort_key(entry: Dict[str, Any]) -> Tuple[Any, ...]:
            score = entry.get("score") if isinstance(entry.get("score"), dict) else {}
            score_value = self._safe_int(score.get("score"), 0)
            hard_risk_count = len(score.get("hard_risk_reasons") or [])
            risk_count = len(score.get("risk_reasons") or [])
            dt = self._clean_text(entry.get("datetime"))
            note = self._clean_text(entry.get("note"))
            return (
                score_value,
                self._score_quality_rank(entry),
                -hard_risk_count,
                -risk_count,
                dt,
                len(note),
            )

        ordered_channels = channel_order or ["115", "quark"]
        ranked: List[Dict[str, Any]] = []
        for channel in ordered_channels:
            channel_items = sorted(grouped.get(channel) or [], key=sort_key, reverse=True)
            ranked.extend(channel_items[:max(1, limit_per_channel)])
        for index, item in enumerate(ranked, start=1):
            item["index"] = index
        return ranked

    def _public_pansou_items(self, items: List[Dict[str, Any]]) -> List[Dict[str, Any]]:
        public_items: List[Dict[str, Any]] = []
        for item in items or []:
            if not isinstance(item, dict):
                continue
            public_item = {
                "index": self._safe_int(item.get("index"), 0),
                "channel": self._normalize_pansou_channel_name(item.get("channel")),
                "note": self._clean_text(item.get("note")),
                "source": self._clean_text(item.get("source")),
                "datetime": self._clean_text(item.get("datetime")),
                "display_datetime": self._format_pansou_display_datetime(item.get("datetime")),
                "password": self._clean_text(item.get("password")),
                "url": self._clean_text(item.get("url")),
                "brief_summary": self._pansou_item_brief_summary(item),
            }
            for extra_key in [
                "title",
                "remark",
                "description",
                "desc",
                "detail",
                "details",
                "summary",
                "share_size",
                "size",
                "subtitle",
                "subtitles",
                "subtitle_language",
                "subtitle_languages",
                "video_resolution",
                "videoFormat",
                "media_type",
                "type",
                "episode",
                "episodes",
                "episode_range",
                "update_status",
                "update_info",
            ]:
                value = item.get(extra_key)
                if value not in (None, "", []):
                    public_item[extra_key] = value
            public_items.append(public_item)
        return public_items

    @staticmethod
    def _public_hdhive_items(items: List[Dict[str, Any]]) -> List[Dict[str, Any]]:
        public_items: List[Dict[str, Any]] = []
        for item in items or []:
            if not isinstance(item, dict):
                continue
            public_items.append({
                "index": AgentResourceOfficer._safe_int(item.get("index"), 0),
                "cloud_index": AgentResourceOfficer._safe_int(item.get("cloud_index"), 0),
                "title": AgentResourceOfficer._clean_text(item.get("title")),
                "pan_type": AgentResourceOfficer._clean_text(item.get("pan_type")),
                "share_size": AgentResourceOfficer._list_text(item.get("share_size") or item.get("size")),
                "source": AgentResourceOfficer._list_text(item.get("source")),
                "subtitle_text": AgentResourceOfficer._resource_subtitle_text(item),
                "episode_text": AgentResourceOfficer._resource_episode_text(item),
                "remark": AgentResourceOfficer._resource_remark_text(item),
                "points_text": AgentResourceOfficer._resource_points_text(item),
                "video_resolution": item.get("video_resolution") or [],
                "slug": AgentResourceOfficer._clean_text(item.get("slug")),
            })
        return public_items

    @staticmethod
    def _prepend_search_note(message: str, note: str) -> str:
        clean_message = str(message or "").strip()
        clean_note = str(note or "").strip()
        if not clean_note:
            return clean_message
        if not clean_message:
            return clean_note
        return f"{clean_note}\n\n{clean_message}"

    def _assistant_finalize_pansou_result(
        self,
        *,
        session: str,
        cache_key: str,
        keyword: str,
        items: List[Dict[str, Any]],
        total: int,
        target_path: str,
        action_name: str,
        search_scope: str,
        recommend_handoff: Optional[Dict[str, Any]] = None,
        lead_note: str = "",
    ) -> Dict[str, Any]:
        page_size = self._assistant_result_page_size
        self._save_session(
            cache_key,
            {
                "kind": "assistant_pansou",
                "stage": "result",
                "keyword": keyword,
                "target_path": target_path or self._hdhive_default_path,
                "items": items,
                "total": self._safe_int(total, len(items)),
                "page": 1,
                "page_size": page_size,
                **({"recommend_handoff": dict(recommend_handoff)} if recommend_handoff else {}),
            },
        )
        text_message = self._format_pansou_text(keyword, items, total, page=1, page_size=page_size)
        if lead_note:
            text_message = self._prepend_search_note(text_message, lead_note)
        public_items = self._public_pansou_items(items)
        result_data = {
            "action": action_name,
            "ok": True,
            "items": public_items,
            "total": self._safe_int(total, len(items)),
            "page": 1,
            "page_size": page_size,
            "total_pages": max(1, (len(items) + page_size - 1) // page_size) if items else 1,
            "decision_summary": self._assistant_pansou_entry_summary(items),
            "search_scope": search_scope,
        }
        if recommend_handoff:
            saved_state = self._load_session(cache_key) or {}
            result_data.update(self._assistant_recommend_handoff_short_metadata(saved_state))
            result_data["decision_summary"] = self._assistant_recommend_handoff_entry_summary(saved_state)
        return {
            "success": True,
            "message": text_message,
            "data": self._assistant_response_data(session=session, data=result_data),
        }

    @staticmethod
    def _pick_cloud_hdhive_candidate(
        keyword: str,
        candidates: List[Dict[str, Any]],
        year: str = "",
    ) -> Dict[str, Any]:
        clean_year = AgentResourceOfficer._clean_text(year)[:4]
        if not candidates:
            return {}
        if len(candidates) == 1:
            return dict(candidates[0] or {})
        if not clean_year:
            return {}
        matched = [
            dict(item or {})
            for item in candidates
            if AgentResourceOfficer._clean_text((item or {}).get("year"))[:4] == clean_year
        ]
        if len(matched) == 1:
            return matched[0]
        return {}

    def _format_pansou_body_lines(self, items: List[Dict[str, Any]], total: int) -> List[str]:
        count_115 = len([x for x in items if x.get("channel") == "115"])
        count_quark = len([x for x in items if x.get("channel") == "quark"])
        lines = [f"共找到 {total} 条结果，当前展示 115 {count_115} 条、夸克 {count_quark} 条："]
        seen_115 = False
        seen_quark = False
        for cached in items:
            idx = cached["index"]
            channel = cached["channel"]
            if channel == "115" and not seen_115:
                if lines and lines[-1] != "":
                    lines.append("")
                lines.append("🟦 115 结果")
                lines.append("")
                seen_115 = True
            elif channel == "quark" and not seen_quark:
                if lines and lines[-1] != "":
                    lines.append("")
                lines.append("🟨 夸克结果")
                lines.append("")
                seen_quark = True
            display_datetime = self._format_pansou_display_datetime(cached.get("datetime"))
            date_suffix = f" — {display_datetime}" if display_datetime else ""
            lines.append(f"{idx}. {self._format_pansou_list_title(cached)}{date_suffix}")
            if cached.get("password"):
                lines.append(f"   提取码：{cached['password']}")
            brief = self._pansou_item_brief_summary(cached)
            if brief:
                lines.append(f"   摘要：{brief}")
        return lines

    @classmethod
    def _format_pansou_list_title(cls, item: Dict[str, Any]) -> str:
        channel = cls._normalize_pansou_channel_name(item.get("channel"))
        emoji = "📺" if channel == "115" else "🗄" if channel == "quark" else "🔗"
        title = cls._clean_text(item.get("note") or item.get("title") or "未命名资源")
        title = re.sub(r"^\s*\[(?:115|quark|QUARK)\]\s*", "", title).strip()
        title = re.sub(r"^\s*#(?:剧集|电影|动漫|资源)\s*", "", title).strip()
        title = cls._truncate_text(title, 110)
        if title.startswith(("📺", "🗄", "🗃", "📁", "🔗")):
            return title
        return f"{emoji} {title}".strip()

    def _format_pansou_text(
        self,
        keyword: str,
        items: List[Dict[str, Any]],
        total: int,
        *,
        page: int = 1,
        page_size: int = 10,
    ) -> str:
        safe_page, safe_page_size, total_pages, start, end = self._page_bounds(len(items), page=page, page_size=page_size)
        page_items = items[start:end]
        count_115 = len([x for x in page_items if x.get("channel") == "115"])
        count_quark = len([x for x in page_items if x.get("channel") == "quark"])
        first_visible_index = self._safe_int((page_items[0] or {}).get("index"), 1) if page_items else 1
        last_visible_index = self._safe_int((page_items[-1] or {}).get("index"), first_visible_index) if page_items else first_visible_index
        lines = [
            f"盘搜搜索：{keyword}",
            f"共找到 {total} 条结果，当前第 {safe_page}/{total_pages} 页，展示全局编号 {first_visible_index}-{last_visible_index}（本次缓存 {len(items)} 条候选），本页 115 {count_115} 条、夸克 {count_quark} 条：",
        ]
        seen_115 = False
        seen_quark = False
        for cached in page_items:
            idx = cached["index"]
            channel = cached["channel"]
            if channel == "115" and not seen_115:
                if lines and lines[-1] != "":
                    lines.append("")
                lines.append("🟦 115 结果")
                lines.append("")
                seen_115 = True
            elif channel == "quark" and not seen_quark:
                if lines and lines[-1] != "":
                    lines.append("")
                lines.append("🟨 夸克结果")
                lines.append("")
                seen_quark = True
            display_datetime = self._format_pansou_display_datetime(cached.get("datetime"))
            date_suffix = f" — {display_datetime}" if display_datetime else ""
            lines.append(f"{idx}. {self._format_pansou_list_title(cached)}{date_suffix}")
            if cached.get("password"):
                lines.append(f"   提取码：{cached['password']}")
            brief = self._pansou_item_brief_summary(cached)
            if brief:
                lines.append(f"   摘要：{brief}")
        next_quark_hint = next((self._safe_int(item.get("index"), 0) for item in page_items if item.get("channel") == "quark"), 0)
        suggestion_lines = self._format_pansou_selection_suggestion(items)
        if suggestion_lines:
            lines.extend(["", *suggestion_lines])
        lines.append("下一步：直接回全局编号即可转存；想先确认可发“选择 编号 详情”。")
        if next_quark_hint > 0 and next_quark_hint != first_visible_index:
            lines.append(f"注意：本页夸克结果从全局编号 {next_quark_hint} 开始；例如直接回复“{next_quark_hint}”即可处理本页第 1 条夸克结果，不要重新从 1 开始。")
        if safe_page < total_pages:
            lines.append("如需继续翻页，可回复：n 下一页")
        return "\n".join(lines)

    @classmethod
    def _human_resource_signal_text(cls, title: str, reasons: List[str]) -> str:
        blob = f"{title} {' '.join(reasons or [])}".lower()
        signals: List[str] = []
        if any(token in blob for token in ["4k", "2160", "uhd", "臻彩"]):
            signals.append("画质规格更高")
        if any(token in blob for token in ["hdr", "dv", "杜比", "dolby", "高码率", "60fps", "60帧"]):
            signals.append("视频规格更完整")
        if any(token in blob for token in ["e01", "s01", "全集", "全季", "连续", "更新至", "更至", "覆盖到当前"]):
            signals.append("集数覆盖更明确")
        if any(token in blob for token in ["中字", "简中", "繁中", "字幕", "内封", "内嵌"]):
            signals.append("字幕信息更清楚")
        if any(token in blob for token in ["免费", "积分 0", "影巢免费"]):
            signals.append("成本更低")
        if not signals:
            return "综合画质、完整度和可转存性更均衡"
        return "、".join(signals[:3])

    @classmethod
    def _human_resource_provider_text(cls, provider: str) -> str:
        normalized = cls._clean_text(provider).lower()
        if normalized == "115" or "115" in normalized:
            return "115 资源更适合做主收藏和后续入库"
        if normalized == "quark" or "夸克" in normalized:
            return "夸克资源更适合走夸克转存链路"
        return "这个资源整体更适合优先处理"

    @classmethod
    def _human_resource_suggestion_line(cls, best_index: int, best_title: str, provider: str, reasons: List[str]) -> str:
        title_part = f"：{best_title}" if best_title else ""
        provider_text = cls._human_resource_provider_text(provider)
        signal_text = cls._human_resource_signal_text(best_title, reasons)
        return f"优先选 {best_index}{title_part}。{provider_text}，主要优势是{signal_text}。"

    @classmethod
    def _human_quark_fallback_line(cls, quark_index: int, quark_title: str, reasons: List[str]) -> str:
        title_part = f"：{quark_title}" if quark_title else ""
        signal_text = cls._human_resource_signal_text(quark_title, reasons)
        return f"如果这次明确只走夸克，备选 {quark_index}{title_part}。它在夸克结果里相对更稳，优势是{signal_text}。"

    def _format_pansou_selection_suggestion(self, items: List[Dict[str, Any]]) -> List[str]:
        summary = self._score_summary(items, limit=5)
        best = summary.get("best") if isinstance(summary.get("best"), dict) else {}
        best_index = self._safe_int(best.get("index"), 0)
        if best_index <= 0:
            return []
        best_title = self._clean_text(best.get("title"))
        best_reasons = [self._clean_text(value) for value in (best.get("score_reasons") or [])[:4] if self._clean_text(value)]
        lines = ["智能建议"]
        lines.append(self._human_resource_suggestion_line(best_index, best_title, self._clean_text(best.get("provider")), best_reasons))
        quark_items = [
            dict(item or {})
            for item in (items or [])
            if isinstance(item, dict) and self._normalize_pansou_channel_name(item.get("channel")) == "quark"
        ]
        best_quark = self._best_scored_source_item(quark_items)
        quark_index = self._safe_int(best_quark.get("index") or best_quark.get("pick_index"), 0)
        if quark_index > 0 and quark_index != best_index:
            quark_title = self._clean_text(best_quark.get("note") or best_quark.get("title"))
            quark_score = best_quark.get("score") if isinstance(best_quark.get("score"), dict) else {}
            quark_reasons = [self._clean_text(value) for value in (quark_score.get("score_reasons") or [])[:3] if self._clean_text(value)]
            lines.append(self._human_quark_fallback_line(quark_index, quark_title, quark_reasons))
        return lines

    def _format_hdhive_resource_body_lines(
        self,
        resources: List[Dict[str, Any]],
        *,
        candidate: Optional[Dict[str, Any]] = None,
        start_index: int = 1,
    ) -> List[str]:
        lines: List[str] = []
        if candidate:
            candidate_title = str(candidate.get("title") or "未命名")
            candidate_year = str(candidate.get("year") or "?")
            lines.append(f"已选影片：{candidate_title} ({candidate_year})")
        lines.append(f"资源结果：共 {len(resources)} 条")
        current_provider = ""
        for offset, item in enumerate(resources, start=start_index):
            provider = str(item.get("pan_type") or "?").lower()
            if provider != current_provider:
                current_provider = provider
                if lines and lines[-1] != "":
                    lines.append("")
                if provider == "115":
                    lines.append("🟦 115 结果")
                elif provider == "quark":
                    lines.append("🟨 夸克结果")
                else:
                    lines.append(f"{provider} 结果")
            lines.append(self._format_hdhive_resource_summary_line(item, offset))
            lines.append("")
        return [line for line in lines if line is not None]

    @classmethod
    def _format_hdhive_resource_summary_line(cls, item: Dict[str, Any], index: int) -> str:
        provider = str(item.get("pan_type") or "?").lower()
        emoji = "📺" if provider == "115" else "🗄" if provider == "quark" else "🔗"
        title = cls._clean_text(item.get("title") or "未命名资源")
        points_text = cls._resource_points_text(item)
        share_size = cls._list_text(item.get("share_size") or item.get("size"))
        episode = cls._resource_episode_text(item)
        resolution = "/".join(item.get("video_resolution") or []) or ""
        source = cls._list_text(item.get("source"))
        subtitle = cls._resource_subtitle_text(item)
        remark = cls._resource_remark_text(item)
        detail_parts = [
            points_text,
            share_size,
            episode,
            resolution,
            source,
            subtitle,
            remark,
        ]
        details = " · ".join(part for part in detail_parts if part)
        return f"{index}. {emoji} {title}" + (f" · {details}" if details else "")

    def _format_hdhive_selection_suggestion(self, resources: List[Dict[str, Any]]) -> List[str]:
        summary = self._score_summary(resources, limit=5)
        best = summary.get("best") if isinstance(summary.get("best"), dict) else {}
        best_index = self._safe_int(best.get("index"), 0)
        if best_index <= 0:
            return []
        quark_items = [
            dict(item or {})
            for item in (resources or [])
            if isinstance(item, dict) and str(item.get("pan_type") or "").lower() == "quark"
        ]
        best_quark = self._best_scored_source_item(quark_items)
        quark_index = self._safe_int(best_quark.get("pick_index") or best_quark.get("index"), 0)
        best_title = self._clean_text(best.get("title"))
        best_reasons = [self._clean_text(value) for value in (best.get("score_reasons") or [])[:3] if self._clean_text(value)]
        lines = ["智能建议"]
        lines.append(self._human_resource_suggestion_line(best_index, best_title, self._clean_text(best.get("provider")), best_reasons))
        if quark_index > 0 and quark_index != best_index:
            quark_title = self._clean_text(best_quark.get("title"))
            quark_score = best_quark.get("score") if isinstance(best_quark.get("score"), dict) else {}
            quark_reasons = [self._clean_text(value) for value in (quark_score.get("score_reasons") or [])[:3] if self._clean_text(value)]
            lines.append(self._human_quark_fallback_line(quark_index, quark_title, quark_reasons))
        return lines

    def _format_cloud_selection_suggestion(
        self,
        pansou_items: List[Dict[str, Any]],
        hdhive_resources: List[Dict[str, Any]],
    ) -> List[str]:
        combined: List[Dict[str, Any]] = []
        for item in pansou_items or []:
            if isinstance(item, dict):
                combined.append(dict(item))
        for item in hdhive_resources or []:
            if not isinstance(item, dict):
                continue
            current = dict(item)
            cloud_index = self._safe_int(
                current.get("cloud_index") or current.get("pick_index") or current.get("index"),
                0,
            )
            current["index"] = cloud_index
            current["pick_index"] = cloud_index
            combined.append(current)
        summary = self._score_summary(combined, limit=5)
        best = summary.get("best") if isinstance(summary.get("best"), dict) else {}
        best_index = self._safe_int(best.get("index"), 0)
        if best_index <= 0:
            return []
        best_title = self._clean_text(best.get("title"))
        best_reasons = [self._clean_text(value) for value in (best.get("score_reasons") or [])[:3] if self._clean_text(value)]
        lines = ["智能建议"]
        lines.append(self._human_resource_suggestion_line(best_index, best_title, self._clean_text(best.get("provider")), best_reasons))
        quark_candidates = [
            dict(item or {})
            for item in combined
            if isinstance(item, dict)
            and self._normalize_pansou_channel_name(item.get("channel") or item.get("pan_type")) == "quark"
        ]
        best_quark = self._best_scored_source_item(quark_candidates)
        quark_index = self._safe_int(best_quark.get("index") or best_quark.get("pick_index") or best_quark.get("cloud_index"), 0)
        if quark_index > 0 and quark_index != best_index:
            quark_title = self._clean_text(best_quark.get("note") or best_quark.get("title"))
            quark_score = best_quark.get("score") if isinstance(best_quark.get("score"), dict) else {}
            quark_reasons = [self._clean_text(value) for value in (quark_score.get("score_reasons") or [])[:3] if self._clean_text(value)]
            lines.append(self._human_quark_fallback_line(quark_index, quark_title, quark_reasons))
        return lines

    def _assistant_cloud_entry_summary(
        self,
        pansou_items: List[Dict[str, Any]],
        hdhive_resources: List[Dict[str, Any]],
    ) -> Dict[str, Any]:
        preferred_index = 0
        if pansou_items:
            preferred_index = self._safe_int((pansou_items[0] or {}).get("index"), 0)
        elif hdhive_resources:
            preferred_index = self._safe_int((hdhive_resources[0] or {}).get("cloud_index") or (hdhive_resources[0] or {}).get("index"), 0)
        if preferred_index <= 0:
            return {
                "stage": "cloud_search",
                "label": "盘搜+影巢结果已返回",
                "preferred_command": "",
                "fallback_command": "",
                "recommended_agent_behavior": "show_only",
            }
        return {
            "stage": "cloud_search",
            "label": "盘搜+影巢结果已返回",
            "decision_hint": "默认按编号直接选择；想先看详情可回复“选择 编号 详情”。",
            "preferred_command": str(preferred_index),
            "fallback_command": f"选择 {preferred_index} 详情",
            "compact_commands": [str(preferred_index), f"选择 {preferred_index} 详情"],
            "preferred_requires_confirmation": True,
            "fallback_requires_confirmation": False,
            "can_auto_run_preferred": False,
            "recommended_agent_behavior": "show_only",
        }

    def _assistant_finalize_cloud_result(
        self,
        *,
        session: str,
        cache_key: str,
        keyword: str,
        pansou_items: List[Dict[str, Any]],
        pansou_total: int,
        hdhive_resources: List[Dict[str, Any]],
        hdhive_candidate: Optional[Dict[str, Any]],
        hdhive_candidates: List[Dict[str, Any]],
        target_path: str,
        lead_note: str = "",
    ) -> Dict[str, Any]:
        page_size = self._assistant_result_page_size
        self._save_session(
            cache_key,
            {
                "kind": "assistant_cloud",
                "stage": "result",
                "keyword": keyword,
                "target_path": target_path or self._hdhive_default_path,
                "pansou_items": pansou_items,
                "pansou_total": pansou_total,
                "hdhive_resources": hdhive_resources,
                "hdhive_candidate": dict(hdhive_candidate or {}),
                "hdhive_candidates": hdhive_candidates,
                "page": 1,
                "page_size": page_size,
            },
        )
        text_message = self._format_cloud_text(
            keyword=keyword,
            pansou_items=pansou_items,
            pansou_total=pansou_total,
            hdhive_resources=hdhive_resources,
            hdhive_candidate=hdhive_candidate,
            hdhive_candidates=hdhive_candidates,
            page=1,
            page_size=page_size,
        )
        if lead_note:
            text_message = self._prepend_search_note(text_message, lead_note)
        return {
            "success": True,
            "message": text_message,
            "data": self._assistant_response_data(session=session, data={
                "action": "cloud_search",
                "ok": True,
                "items": self._public_pansou_items(pansou_items),
                "hdhive_resources": self._public_hdhive_items(hdhive_resources),
                "hdhive_candidate": dict(hdhive_candidate or {}),
                "hdhive_candidate_count": len(hdhive_candidates or []),
                "page": 1,
                "page_size": page_size,
                "total_pages": max(1, ((len(pansou_items) + len(hdhive_resources)) + page_size - 1) // page_size) if (pansou_items or hdhive_resources) else 1,
                "decision_summary": self._assistant_cloud_entry_summary(pansou_items, hdhive_resources),
                "search_scope": "pansou_and_hdhive",
            }),
        }

    def _format_cloud_text(
        self,
        *,
        keyword: str,
        pansou_items: List[Dict[str, Any]],
        pansou_total: int,
        hdhive_resources: List[Dict[str, Any]],
        hdhive_candidate: Optional[Dict[str, Any]],
        hdhive_candidates: List[Dict[str, Any]],
        page: int = 1,
        page_size: int = 10,
    ) -> str:
        total_items = len(pansou_items) + len(hdhive_resources)
        safe_page, safe_page_size, total_pages, start, end = self._page_bounds(total_items, page=page, page_size=page_size)
        start_index = start + 1
        end_index = min(total_items, end)
        lines = [f"盘搜 + 影巢结果：{keyword}"]
        if total_items > 0:
            lines.append(f"当前第 {safe_page}/{total_pages} 页，展示编号 {start_index}-{end_index} / 共 {total_items} 条已展开结果：")
        pansou_page_items = [item for item in pansou_items if start < self._safe_int(item.get('index'), 0) <= end]
        hdhive_page_items = [item for item in hdhive_resources if start < self._safe_int(item.get('cloud_index') or item.get('index'), 0) <= end]
        lines.extend(["", "盘搜结果"])
        if pansou_page_items:
            lines.extend(self._format_pansou_body_lines(pansou_page_items, pansou_total))
        elif pansou_items:
            lines.append("本页无盘搜结果")
        else:
            lines.append("暂无结果")
        lines.extend(["", "影巢结果"])
        if hdhive_page_items:
            lines.extend(self._format_hdhive_resource_body_lines(
                hdhive_page_items,
                candidate=hdhive_candidate,
                start_index=self._safe_int((hdhive_page_items[0] or {}).get("cloud_index") or (hdhive_page_items[0] or {}).get("index"), 1),
            ))
        elif hdhive_resources:
            lines.append("本页无影巢结果")
        elif hdhive_candidates:
            lines.append(f"候选影片 {len(hdhive_candidates)} 个，当前未自动展开。")
            lines.append(f"如需细看影巢，请发送：影巢搜索 {keyword}")
        else:
            lines.append("暂无结果")
        suggestion_lines = self._format_cloud_selection_suggestion(pansou_items, hdhive_resources)
        if suggestion_lines:
            lines.extend(["", *suggestion_lines])
        lines.append("下一步：直接回编号即可转存；想先确认可发“选择 编号 详情”。")
        lines.append("如需只看单一来源，可继续发：盘搜搜索 片名 / 影巢搜索 片名。")
        if safe_page < total_pages:
            lines.append("如需继续翻页，可回复：n 下一页")
        return "\n".join(lines)

    def _assistant_finalize_hdhive_candidates(
        self,
        *,
        session: str,
        cache_key: str,
        keyword: str,
        candidates: List[Dict[str, Any]],
        media_type: str,
        year: str,
        target_path: str,
        recommend_handoff: Optional[Dict[str, Any]] = None,
        lead_note: str = "",
    ) -> Dict[str, Any]:
        self._save_session(
            cache_key,
            {
                "kind": "assistant_hdhive",
                "stage": "candidate",
                "keyword": keyword,
                "media_type": media_type,
                "year": year,
                "target_path": target_path or self._hdhive_default_path,
                "candidates": candidates,
                "page": 1,
                "page_size": self._hdhive_candidate_page_size,
                **({"recommend_handoff": dict(recommend_handoff)} if recommend_handoff else {}),
            },
        )
        text_message = self._format_candidate_lines(candidates, page=1, page_size=self._hdhive_candidate_page_size)
        if lead_note:
            text_message = self._prepend_search_note(text_message, lead_note)
        return {
            "success": True,
            "message": text_message,
            "data": self._assistant_response_data(session=session, data={
                "action": "hdhive_candidates",
                "ok": True,
                "candidates": candidates,
                "search_scope": "hdhive",
            }),
        }

    @staticmethod
    def _format_score_label(item: Dict[str, Any]) -> str:
        score = item.get("score") if isinstance(item.get("score"), dict) else {}
        if not score:
            return ""
        try:
            value = int(float(score.get("score") or 0))
        except Exception:
            value = 0
        action = AgentResourceOfficer._clean_text(score.get("recommended_action"))
        if score.get("can_auto_execute"):
            suffix = "可自动入库"
        elif action == "ask_confirm":
            suffix = "建议确认"
        else:
            suffix = "不建议自动"
        return f"{value}分 {suffix}"

    @staticmethod
    def _score_decision_label(value: Any) -> str:
        action = AgentResourceOfficer._clean_text(value)
        if action == "ask_confirm":
            return "建议确认"
        if action == "do_not_auto":
            return "不建议自动"
        if action == "auto_ingest_cloud":
            return "可自动入库"
        if action == "auto_download_pt":
            return "可自动下载"
        return action or "待判断"

    def _score_brief_item(self, item: Dict[str, Any], fallback_index: int = 0) -> Dict[str, Any]:
        current = dict(item or {})
        score = current.get("score") if isinstance(current.get("score"), dict) else {}
        if not score:
            return {}
        torrent = current.get("torrent_info") if isinstance(current.get("torrent_info"), dict) else {}
        index = self._safe_int(
            current.get("pick_index") or current.get("index") or fallback_index,
            fallback_index,
        )
        title = (
            self._clean_text(torrent.get("title"))
            or self._clean_text(current.get("note"))
            or self._clean_text(current.get("title") or current.get("matched_title"))
            or "未命名资源"
        )
        provider = (
            self._clean_text(current.get("pan_type") or current.get("channel"))
            or self._clean_text(torrent.get("site_name"))
            or self._clean_text(current.get("site"))
        )
        reasons = [self._clean_text(value) for value in (score.get("score_reasons") or []) if self._clean_text(value)]
        risks = [self._clean_text(value) for value in (score.get("risk_reasons") or []) if self._clean_text(value)]
        hard_risks = [self._clean_text(value) for value in (score.get("hard_risk_reasons") or []) if self._clean_text(value)]
        brief = {
            "index": index,
            "title": title[:160],
            "provider": provider,
            "source_type": self._clean_text(score.get("source_type")),
            "score": self._safe_int(score.get("score"), 0),
            "quality_rank": self._score_quality_rank(current),
            "score_level": self._clean_text(score.get("score_level")),
            "recommended_action": self._clean_text(score.get("recommended_action")),
            "can_auto_execute": bool(score.get("can_auto_execute")),
            "score_reasons": reasons[:3],
            "risk_reasons": risks[:2],
            "hard_risk_reasons": hard_risks[:2],
        }
        points_text = self._resource_points_text(current) if current and brief.get("source_type") != "pt" else ""
        if points_text and points_text != "积分未知":
            brief["points_text"] = points_text
        seeders = torrent.get("seeders") if torrent else score.get("seeders")
        if seeders is not None:
            brief["seeders"] = seeders
        volume = self._clean_text(torrent.get("volume_factor") if torrent else score.get("volume_factor"))
        if volume:
            brief["volume_factor"] = volume
        size = self._clean_text(current.get("share_size") or current.get("size") or torrent.get("size"))
        if size:
            brief["size"] = size
        return brief

    def _score_summary(self, items: List[Dict[str, Any]], *, limit: int = 5) -> Dict[str, Any]:
        scored: List[Dict[str, Any]] = []
        for index, item in enumerate(items or [], 1):
            if not isinstance(item, dict):
                continue
            brief = self._score_brief_item(item, fallback_index=index)
            if brief:
                scored.append(brief)
        scored.sort(key=lambda value: (
            1 if value.get("can_auto_execute") else 0,
            self._safe_int(value.get("score"), 0),
            self._safe_int(value.get("quality_rank"), 0),
        ), reverse=True)
        auto_count = len([item for item in scored if item.get("can_auto_execute")])
        confirm_count = len([item for item in scored if item.get("recommended_action") == "ask_confirm"])
        blocked_count = len([item for item in scored if item.get("hard_risk_reasons")])
        warning_count = len([item for item in scored if item.get("risk_reasons")])
        summary = {
            "total_scored": len(scored),
            "auto_count": auto_count,
            "confirm_count": confirm_count,
            "blocked_count": blocked_count,
            "warning_count": warning_count,
            "best": scored[0] if scored else None,
            "top_recommendations": scored[:max(1, min(10, self._safe_int(limit, 5)))],
        }
        summary["decision"] = self._score_summary_decision(summary)
        return summary

    def _score_summary_decision(self, summary: Optional[Dict[str, Any]]) -> Dict[str, Any]:
        data = dict(summary or {})
        best = data.get("best") if isinstance(data.get("best"), dict) else {}
        if not best:
            return {
                "stage": "no_scored_items",
                "label": "暂无评分结果",
                "requires_confirmation": False,
                "prefer_plan_first": True,
                "decision_hint": "当前没有可评分条目，先完成搜索或选择后再判断。",
                "command_policy": "none",
                "preferred_requires_confirmation": False,
                "fallback_requires_confirmation": False,
                "can_auto_run_preferred": False,
                "preferred_command": "",
                "fallback_command": "",
                "compact_commands": [],
                "recommended_commands": [],
            }
        choice = self._safe_int(best.get("index"), 0)
        source_type = self._clean_text(best.get("source_type")).lower()
        recommended_action = self._clean_text(best.get("recommended_action"))
        title = self._clean_text(best.get("title"))
        hard_risks = [self._clean_text(value) for value in (best.get("hard_risk_reasons") or []) if self._clean_text(value)]
        risks = [self._clean_text(value) for value in (best.get("risk_reasons") or []) if self._clean_text(value)]
        risks = [risk for risk in risks if risk not in hard_risks]
        is_pt = source_type == "pt"
        if is_pt:
            detail_command = ""
            plan_command = ""
            commands = [command for command in [str(choice) if choice else ""] if command]
            if best.get("can_auto_execute"):
                hint = f"当前最高分候选是 #{choice}{'：' + title if title else ''}，可以直接回编号下载。"
                stage = "auto_candidate"
            elif hard_risks:
                hint = f"当前最高分候选是 #{choice}{'：' + title if title else ''}，但存在硬风险；仍可直接回编号下载。"
                stage = "blocked"
            elif recommended_action == "ask_confirm":
                hint = f"当前最高分候选是 #{choice}{'：' + title if title else ''}，建议直接回编号下载。"
                stage = "confirm"
            else:
                hint = f"当前最高分候选是 #{choice}{'：' + title if title else ''}，但综合评分偏低；建议直接回编号下载。"
                stage = "low_score"
        else:
            detail_command = f"选择 {choice} 详情"
            plan_command = f"计划选择 {choice}" if choice > 0 else ""
            commands = [command for command in [detail_command if choice else "", plan_command if choice else "", "执行计划"] if command]
            if best.get("can_auto_execute"):
                hint = f"当前最高分候选是 #{choice}{'：' + title if title else ''}，已达到自动化阈值，但默认仍建议先生成计划再执行。"
                stage = "auto_candidate"
            elif hard_risks:
                hint = f"当前最高分候选是 #{choice}{'：' + title if title else ''}，但存在硬风险，不能自动执行。"
                stage = "blocked"
            elif recommended_action == "ask_confirm":
                hint = f"当前最高分候选是 #{choice}{'：' + title if title else ''}，风险可控，建议先看详情再决定。"
                stage = "confirm"
            else:
                hint = f"当前最高分候选是 #{choice}{'：' + title if title else ''}，但综合评分偏低，不建议直接处理。"
                stage = "low_score"
        return {
            "stage": stage,
            "label": self._score_decision_label("auto_download_pt" if best.get("can_auto_execute") and is_pt else "auto_ingest_cloud" if best.get("can_auto_execute") else recommended_action),
            "source_type": source_type,
            "choice": choice,
            "title": title[:160],
            "score": self._safe_int(best.get("score"), 0),
            "requires_confirmation": False if is_pt else not bool(best.get("can_auto_execute")),
            "prefer_plan_first": not is_pt,
            "command_policy": "auto_continue" if is_pt else "read_then_confirm_write" if len(commands) > 1 else "safe_read_only",
            "preferred_requires_confirmation": False,
            "fallback_requires_confirmation": False if is_pt else bool(len(commands) > 1),
            "can_auto_run_preferred": bool(commands),
            "preferred_command": commands[0] if commands else "",
            "fallback_command": commands[1] if len(commands) > 1 else "",
            "compact_commands": commands[:2],
            "recommended_commands": commands,
            "decision_hint": hint,
            "top_hard_risk": hard_risks[0] if hard_risks else "",
            "top_warning": risks[0] if risks else "",
        }

    @staticmethod
    def _format_score_summary_decision_lines(summary: Optional[Dict[str, Any]]) -> List[str]:
        data = dict(summary or {})
        decision = data.get("decision") if isinstance(data.get("decision"), dict) else {}
        if not decision:
            return []
        lines: List[str] = []
        label = AgentResourceOfficer._clean_text(decision.get("label"))
        hint = AgentResourceOfficer._clean_text(decision.get("decision_hint"))
        commands = [AgentResourceOfficer._clean_text(item) for item in (decision.get("compact_commands") or decision.get("recommended_commands") or []) if AgentResourceOfficer._clean_text(item)]
        if label:
            lines.append(f"决策建议：{label}")
        if hint:
            lines.append(f"建议：{hint}")
        if commands:
            lines.append("下一步：" + " / ".join(commands))
        return lines

    def _best_scored_source_item(self, items: List[Dict[str, Any]]) -> Dict[str, Any]:
        candidates = [
            dict(item or {})
            for item in (items or [])
            if isinstance(item, dict) and isinstance(item.get("score"), dict)
        ]
        if not candidates:
            return {}
        return max(
            candidates,
            key=lambda item: (
                1 if (item.get("score") or {}).get("can_auto_execute") else 0,
                self._safe_int((item.get("score") or {}).get("score"), 0),
                self._score_quality_rank(item),
                -self._safe_int(item.get("index") or item.get("pick_index"), 0),
            ),
        )

    def _format_cloud_item_detail_text(self, item: Dict[str, Any], *, title: str = "云盘资源详情") -> str:
        current = dict(item or {})
        score = current.get("score") if isinstance(current.get("score"), dict) else {}
        score_summary = self._score_summary([current], limit=1) if score else {}
        index = self._safe_int(current.get("index") or current.get("pick_index"), 0)
        name = (
            self._clean_text(current.get("note"))
            or self._clean_text(current.get("title"))
            or self._clean_text(current.get("matched_title"))
            or "未命名资源"
        )
        provider = self._clean_text(current.get("channel") or current.get("pan_type") or current.get("provider"))
        size = self._clean_text(current.get("share_size") or current.get("size"))
        resolution = self._clean_text(current.get("resolution"))
        source = self._clean_text(current.get("source") or current.get("source_name"))
        datetime_text = self._format_pansou_display_datetime(current.get("datetime"))
        password = self._clean_text(current.get("password"))
        url = self._clean_text(current.get("url") or current.get("share_url") or current.get("link"))
        brief = self._clean_text(current.get("brief_summary") or self._pansou_item_brief_summary(current))
        points = self._resource_points_text(current)
        lines = [title]
        if index:
            lines.append(f"编号：{index}")
        lines.append(f"资源：{name}")
        if provider:
            lines.append(f"网盘：{provider}")
        if points:
            lines.append(f"积分：{points}")
        if resolution:
            lines.append(f"分辨率：{resolution}")
        if size:
            lines.append(f"大小：{size}")
        if source:
            lines.append(f"来源：{source}")
        if datetime_text:
            lines.append(f"日期：{datetime_text}")
        if brief:
            lines.append(f"摘要：{brief}")
        if password:
            lines.append(f"提取码：{password}")
        if url:
            lines.append(f"链接：{url}")
        if score:
            lines.append("")
            lines.append("智能建议")
            lines.append(f"评分：{self._safe_int(score.get('score'), 0)} / {self._clean_text(score.get('score_level')) or '-'}")
            reasons = [self._clean_text(value) for value in (score.get("score_reasons") or []) if self._clean_text(value)]
            hard_risks = [self._clean_text(value) for value in (score.get("hard_risk_reasons") or []) if self._clean_text(value)]
            risks = [self._clean_text(value) for value in (score.get("risk_reasons") or []) if self._clean_text(value)]
            risks = [risk for risk in risks if risk not in hard_risks]
            if reasons:
                lines.append("加分理由：" + "；".join(reasons[:6]))
            if hard_risks:
                lines.append("硬风险：" + "；".join(hard_risks[:6]))
            if risks:
                lines.append("提醒：" + "；".join(risks[:6]))
        lines.extend(self._format_score_summary_decision_lines(score_summary))
        return "\n".join(lines)

