    def _assistant_mp_detect_stage(
        self,
        *,
        task_items: List[Dict[str, Any]],
        download_items: List[Dict[str, Any]],
        transfer_items: List[Dict[str, Any]],
    ) -> str:
        def has_term(value: Any, terms: List[str]) -> bool:
            text = self._clean_text(value).lower()
            return bool(text) and any(term in text for term in terms)

        failed_terms = ["失败", "错误", "error", "fail", "未识别", "识别失败", "入库失败", "整理失败"]
        success_terms = ["成功", "完成", "已入库", "已整理", "已转移", "imported", "success", "completed"]
        running_terms = ["处理中", "进行中", "转移中", "整理中", "入库中", "等待", "队列", "pending", "running"]

        for item in transfer_items:
            if has_term(item.get("status_text") or item.get("status"), failed_terms):
                return "failed"
        for item in download_items:
            if has_term(item.get("transfer_status_text") or item.get("transfer_status"), failed_terms):
                return "failed"

        if task_items:
            return "downloading"

        for item in transfer_items:
            status_value = item.get("status_text") or item.get("status")
            if has_term(status_value, success_terms):
                return "imported"
            if has_term(status_value, running_terms):
                return "transferring"

        for item in download_items:
            transfer_value = item.get("transfer_status_text") or item.get("transfer_status")
            if has_term(transfer_value, success_terms):
                return "imported"
            if has_term(transfer_value, running_terms):
                return "transferring"

        if transfer_items:
            return "transferring"
        if download_items:
            return "downloaded"
        return "not_found"

    def _assistant_mp_diagnosis_summary(
        self,
        *,
        keyword: str,
        hash_value: str,
        task_items: List[Dict[str, Any]],
        download_items: List[Dict[str, Any]],
        transfer_items: List[Dict[str, Any]],
        force_failed: bool = False,
    ) -> Dict[str, Any]:
        stage = "failed" if force_failed else self._assistant_mp_detect_stage(
            task_items=task_items,
            download_items=download_items,
            transfer_items=transfer_items,
        )
        matched_count = len(task_items) + len(download_items) + len(transfer_items)
        matched = matched_count > 0
        evidence: List[str] = []
        risk_reasons: List[str] = []
        recommended_action = ""
        follow_up_hint = ""
        confidence = 0.0

        if task_items:
            first_task = task_items[0]
            evidence.append(
                f"下载任务 {self._clean_text(first_task.get('title')) or '-'} | "
                f"{self._clean_text(first_task.get('progress')) or '-'} | "
                f"{self._clean_text(first_task.get('state')) or '-'}"
            )
        if download_items:
            first_download = download_items[0]
            evidence.append(
                f"下载历史 {self._clean_text(first_download.get('title')) or '-'} | "
                f"{self._clean_text(first_download.get('date')) or '-'} | "
                f"{self._clean_text(first_download.get('transfer_status_text')) or '-'}"
            )
            transfer_status_text = self._clean_text(first_download.get("transfer_status_text"))
            if transfer_status_text and any(word in transfer_status_text for word in ["失败", "错误"]):
                risk_reasons.append(f"下载历史显示整理状态异常：{transfer_status_text}")
        if transfer_items:
            first_transfer = transfer_items[0]
            evidence.append(
                f"整理历史 {self._clean_text(first_transfer.get('title')) or '-'} | "
                f"{self._clean_text(first_transfer.get('status_text')) or '-'} | "
                f"{self._clean_text(first_transfer.get('date')) or '-'}"
            )
            status_text = self._clean_text(first_transfer.get("status_text"))
            if status_text and any(word in status_text for word in ["失败", "错误"]):
                risk_reasons.append(f"整理历史存在失败记录：{status_text}")

        if stage == "downloading":
            confidence = 0.95
            recommended_action = "query_mp_download_tasks"
            follow_up_hint = "资源仍在下载阶段，优先查看下载任务进度。"
        elif stage == "downloaded":
            confidence = 0.85
            recommended_action = "query_mp_transfer_history"
            follow_up_hint = "已找到下载历史，但还没有明确的入库记录，下一步查看整理/入库历史。"
        elif stage == "transferring":
            confidence = 0.9
            recommended_action = "query_mp_transfer_history"
            follow_up_hint = "资源已经进入整理/入库链路，优先查看最近整理历史。"
        elif stage == "imported":
            confidence = 0.98
            recommended_action = "query_mp_transfer_history"
            follow_up_hint = "已经找到成功入库线索，如需确认最终落地可查看最近整理历史。"
        elif stage == "failed":
            confidence = 0.92 if matched else 0.65
            recommended_action = "query_mp_local_diagnose"
            follow_up_hint = "已发现失败线索，建议进入本地诊断汇总失败原因和下一步处理建议。"
        elif stage == "not_found":
            confidence = 0.95
            recommended_action = "query_mp_download_history"
            follow_up_hint = "当前没有找到相关下载任务、下载历史或整理记录。先检查是否真的提交过下载/订阅。"
        else:
            confidence = 0.5
            recommended_action = "query_mp_lifecycle_status"
            follow_up_hint = "状态不足以判断，建议继续查看生命周期聚合结果。"

        if hash_value:
            evidence.append(f"Hash 检索：{hash_value}")
        elif keyword:
            evidence.append(f"关键词检索：{keyword}")

        return {
            "status": "ok" if matched else "not_found",
            "matched": matched,
            "stage": stage,
            "confidence": confidence,
            "evidence": evidence[:6],
            "risk_reasons": risk_reasons[:6],
            "recommended_action": recommended_action,
            "follow_up_hint": follow_up_hint,
        }

    def _assistant_mp_diagnosis_followups(
        self,
        *,
        session: str,
        session_id: str,
        keyword: str,
        hash_value: str,
        preferred: str,
    ) -> Tuple[List[str], List[Dict[str, Any]]]:
        base_body = {
            "session": session,
            "session_id": session_id,
        }
        keyword_body = dict(base_body)
        if keyword:
            keyword_body["keyword"] = keyword
        if hash_value:
            keyword_body["hash"] = hash_value
        action_order = [preferred]
        for name in ["query_mp_lifecycle_status", "query_mp_download_history", "query_mp_transfer_history", "query_mp_local_diagnose"]:
            if name not in action_order:
                action_order.append(name)
        templates = [
            self._assistant_action_template(
                name=name,
                description={
                    "query_mp_lifecycle_status": "聚合查看下载任务、下载历史和整理/入库历史",
                    "query_mp_download_history": "查看下载历史，并确认是否已经提交过下载",
                    "query_mp_transfer_history": "查看整理/入库历史，确认是否已经落库或失败",
                    "query_mp_local_diagnose": "汇总本地/PT 链路的失败线索与处理建议",
                }.get(name, name),
                endpoint="/api/v1/plugin/AgentResourceOfficer/assistant/action",
                tool="agent_resource_officer_execute_action",
                body={**keyword_body, "name": name, "compact": True},
            )
            for name in action_order[:4]
        ]
        return action_order[:4], templates

    def _assistant_followup_command(self, action_name: str, *, keyword: str = "", hash_value: str = "") -> str:
        target = self._clean_text(keyword or hash_value)
        mapping = {
            "query_execution_followup": "后续",
            "query_mp_download_tasks": "下载任务",
            "query_mp_subscribes": "订阅列表",
        }
        if action_name in mapping:
            return mapping[action_name]
        if action_name == "query_mp_ingest_status":
            return f"入库 {target}".strip()
        if action_name == "query_mp_lifecycle_status":
            return f"状态 {target}".strip()
        if action_name == "query_mp_download_history":
            return f"记录 {target}".strip()
        if action_name == "query_mp_transfer_history":
            return f"入库记录 {target}".strip()
        if action_name == "query_mp_local_diagnose":
            return f"诊断 {target}".strip()
        if action_name == "query_ai_failed_samples":
            return f"失败样本 {target}".strip() if target else "失败样本"
        if action_name == "query_ai_sample_worklist":
            return f"工作清单 {target}".strip() if target else "工作清单"
        if action_name == "query_ai_sample_insights":
            return f"样本洞察 {target}".strip() if target else "样本洞察"
        if action_name == "start_mp_media_search":
            return f"MP搜索 {target}".strip()
        return ""

    def _assistant_template_command(
        self,
        template: Dict[str, Any],
        *,
        keyword: str = "",
        hash_value: str = "",
        target: str = "",
    ) -> str:
        if not isinstance(template, dict):
            return ""
        body = dict(template.get("action_body") or template.get("body") or {})
        action_name = self._clean_text(body.get("name")) or self._clean_text(template.get("name"))
        target_text = self._clean_text(target or body.get("keyword") or body.get("hash") or body.get("target"))
        command = self._assistant_followup_command(
            action_name,
            keyword=self._clean_text(keyword or body.get("keyword") or target_text),
            hash_value=self._clean_text(hash_value or body.get("hash")),
        )
        if command:
            return command
        if action_name == "query_mp_recent_activity":
            return "最近"
        if action_name == "execute_session_latest_plan":
            return "执行计划"
        if action_name == "mp_download_control":
            control = self._clean_text(body.get("control"))
            mapping = {
                "pause": "暂停下载",
                "resume": "恢复下载",
                "delete": "删除下载",
            }
            prefix = mapping.get(control)
            if prefix and target_text:
                return f"{prefix} {target_text}"
            return prefix or "下载任务"
        if action_name == "mp_subscribe_control":
            control = self._clean_text(body.get("control"))
            mapping = {
                "pause": "暂停订阅",
                "resume": "恢复订阅",
                "delete": "删除订阅",
                "search": "刷新订阅",
            }
            prefix = mapping.get(control)
            if prefix and target_text:
                return f"{prefix} {target_text}"
            return prefix or "订阅列表"
        return ""

    def _assistant_error_summary(
        self,
        *,
        error_code: str,
        recommended_action: str = "",
        message_head: str = "",
        next_actions: Optional[List[Any]] = None,
        action_templates: Optional[List[Dict[str, Any]]] = None,
        keyword: str = "",
        hash_value: str = "",
        target: str = "",
    ) -> Dict[str, Any]:
        code = self._clean_text(error_code)
        if not code:
            return {}
        label_map = {
            "latest_plan_not_executed": "当前会话还有待执行计划",
            "plan_not_executed": "指定计划还没有执行",
            "executed_plan_not_found": "当前没有可追踪的已执行计划",
            "followup_not_available": "当前计划没有自动追踪动作",
            "invalid_download_control_args": "下载任务参数不完整",
            "download_target_not_found": "没有匹配到可操作的下载任务",
            "invalid_subscribe_control_args": "订阅操作参数不完整",
            "subscribe_target_not_found": "没有匹配到可操作的订阅",
        }
        hint_map = {
            "latest_plan_not_executed": "先执行计划，再继续查看后续状态。",
            "plan_not_executed": "先执行这条计划，再继续查看执行后追踪。",
            "executed_plan_not_found": "先执行下载、订阅或转存计划，再查看后续。",
            "followup_not_available": "当前计划只能改查状态、记录或最近活动。",
            "invalid_download_control_args": "先发“下载任务”获取列表，再按编号暂停、恢复或删除。",
            "download_target_not_found": "先发“下载任务”刷新列表，再按编号操作。",
            "invalid_subscribe_control_args": "先发“订阅列表”获取列表，再按编号暂停、恢复或删除。",
            "subscribe_target_not_found": "先发“订阅列表”刷新列表，再按编号操作。",
        }
        command_candidates: List[str] = []
        fallback_map = {
            "latest_plan_not_executed": ["执行计划", "后续"],
            "plan_not_executed": ["执行计划", "后续"],
            "executed_plan_not_found": ["最近"],
            "followup_not_available": [f"状态 {target}".strip(), f"记录 {target}".strip(), "最近"],
            "invalid_download_control_args": ["下载任务"],
            "download_target_not_found": ["下载任务"],
            "invalid_subscribe_control_args": ["订阅列表"],
            "subscribe_target_not_found": ["订阅列表"],
        }
        for command in fallback_map.get(code, []):
            command_text = self._clean_text(command)
            if command_text and command_text not in command_candidates:
                command_candidates.append(command_text)
        synthetic_templates: List[Dict[str, Any]] = []
        action_name = self._clean_text(recommended_action)
        if action_name:
            synthetic_templates.append({
                "name": action_name,
                "action_body": {
                    "name": action_name,
                    "keyword": keyword,
                    "hash": hash_value,
                    "target": target,
                },
            })
        synthetic_templates.extend(
            item for item in (action_templates or []) if isinstance(item, dict)
        )
        for item in synthetic_templates:
            command = self._assistant_template_command(
                item,
                keyword=keyword,
                hash_value=hash_value,
                target=target,
            )
            if command and command not in command_candidates:
                command_candidates.append(command)
        for name in [self._clean_text(item) for item in (next_actions or []) if self._clean_text(item)]:
            command = self._assistant_followup_command(name, keyword=keyword or target, hash_value=hash_value)
            if command and command not in command_candidates:
                command_candidates.append(command)
        preferred_requires_confirmation = code in {"latest_plan_not_executed", "plan_not_executed"}
        return {
            "error_code": code,
            "label": label_map.get(code, message_head or code),
            "decision_hint": hint_map.get(code, message_head or "当前请求未完成，请先按建议补充上下文。"),
            "command_policy": "confirm_then_resume" if preferred_requires_confirmation else "safe_read_recovery",
            "preferred_requires_confirmation": preferred_requires_confirmation,
            "fallback_requires_confirmation": False,
            "can_auto_run_preferred": not preferred_requires_confirmation and bool(command_candidates),
            "preferred_command": command_candidates[0] if command_candidates else "",
            "fallback_command": command_candidates[1] if len(command_candidates) > 1 else "",
            "compact_commands": command_candidates[:2],
            "recommended_commands": command_candidates[:3],
        }

    def _format_quark_transfer_failure(self, detail: str = "", target_path: str = "") -> str:
        text = self._clean_text(detail)
        target = self._clean_text(target_path) or self._quark_default_path or "/飞书"
        if "41031" in text or "分享者用户封禁链接查看受限" in text:
            return (
                "夸克转存失败：当前分享链接已受限或分享者账号受限，"
                "建议改选同一列表里的其他夸克资源。"
            )
        if "未获取到 stoken" in text:
            try:
                cookie_ok, _cookie_message = self._ensure_quark_service().check_cookie()
            except Exception:
                cookie_ok = False
            if cookie_ok:
                return (
                    "夸克转存失败：当前夸克登录态正常，但这条分享无法获取 stoken，"
                    "更可能是分享链接失效、提取码错误或分享已受限。建议改选同一列表里的其他夸克资源。"
                )
            return (
                f"夸克转存失败：当前夸克登录态不足，无法转存到 {target}。"
                "建议先刷新夸克登录后再试。"
            )
        if "分享链接为空" in text or "无权查看内容" in text:
            return (
                "夸克转存失败：当前分享内容为空或账号无权查看，"
                "更可能是分享链接失效、内容被取消分享或分享受限。建议改选其他资源。"
            )
        if "require login [guest]" in text or "未配置夸克 Cookie" in text:
            return (
                f"夸克转存失败：当前夸克登录态不足，无法转存到 {target}。"
                "建议先刷新夸克登录后再试。"
            )
        if not text or text == f"无法转存到 {target}":
            try:
                cookie_ok, cookie_message = self._ensure_quark_service().check_cookie()
            except Exception:
                cookie_ok, cookie_message = True, ""
            cookie_text = self._clean_text(cookie_message)
            if (not cookie_ok) and (
                "require login [guest]" in cookie_text
                or "未配置夸克 Cookie" in cookie_text
                or "cookie" in cookie_text.lower()
                or "login" in cookie_text.lower()
            ):
                return (
                    f"夸克转存失败：当前夸克登录态不足，无法转存到 {target}。"
                    "建议先刷新夸克登录后再试。"
                )
        if not text:
            return (
                f"夸克转存失败：无法转存到 {target}。"
                "当前原因未明，请先不要自行推断为路径问题，可稍后重试或先检查夸克登录态。"
            )
        return f"夸克转存失败：{text}"

    @staticmethod
    def _is_quark_share_restricted_message(detail: str) -> bool:
        text = str(detail or "").strip()
        if not text:
            return False
        return "41031" in text or "分享者用户封禁链接查看受限" in text

    async def _assistant_retry_pansou_quark_candidates(
        self,
        request: Request,
        *,
        items: List[Dict[str, Any]],
        selected_index: int,
        selected_url: str,
        session: str,
        target_path: str,
        apikey: str,
    ) -> Optional[Dict[str, Any]]:
        candidates: List[Tuple[int, Dict[str, Any]]] = []
        for offset, raw_item in enumerate(items[selected_index:], start=selected_index + 1):
            item = dict(raw_item or {})
            share_url = self._clean_text(item.get("url"))
            if not share_url or not self._is_quark_url(share_url):
                continue
            if share_url == selected_url:
                continue
            candidates.append((offset, item))
            if len(candidates) >= 3:
                break

        if not candidates:
            return None

        for alt_index, alt_item in candidates:
            alt_url = self._clean_text(alt_item.get("url"))
            alt_code = self._clean_text(alt_item.get("password"))
            alt_result = await self.api_share_route(
                _JsonRequestShim(request, {
                    "url": alt_url,
                    "access_code": alt_code,
                    "path": target_path,
                    "trigger": "Agent影视助手 盘搜夸克候选自动切换",
                    "apikey": apikey,
                })
            )
            if alt_result.get("success"):
                message = (
                    f"原夸克链接已受限，已自动切换到同列表夸克候选 #{alt_index}。\n"
                    f"{str(alt_result.get('message') or '夸克转存成功')}"
                )
                data = dict(alt_result.get("data") or {})
                data.update(
                    {
                        "provider": "quark",
                        "selected_choice": alt_index,
                        "auto_switched_from_choice": selected_index,
                        "auto_switched": True,
                        "selected_item": alt_item,
                    }
                )
                return {
                    "success": True,
                    "message": message,
                    "data": self._assistant_response_data(session=session, data=data),
                }

        hint_choices = "、".join(f"#{idx}" for idx, _ in candidates)
        return {
            "success": False,
            "message": (
                "夸克转存失败：当前分享链接已受限或分享者账号受限，"
                f"可改试同列表夸克候选 {hint_choices}。"
            ),
            "data": self._assistant_response_data(
                session=session,
                data={
                    "provider": "quark",
                    "auto_switched": False,
                    "fallback_choices": [idx for idx, _ in candidates],
                },
            ),
        }

    def _assistant_followup_summary(
        self,
        *,
        category: str,
        stage: str,
        recommended_action: str,
        follow_up_hint: str,
        next_actions: Optional[List[str]] = None,
        action_templates: Optional[List[Dict[str, Any]]] = None,
        keyword: str = "",
        hash_value: str = "",
    ) -> Dict[str, Any]:
        action_names = [self._clean_text(item) for item in (next_actions or []) if self._clean_text(item)]
        command_candidates: List[str] = []
        for name in action_names:
            command = self._assistant_followup_command(name, keyword=keyword, hash_value=hash_value)
            if command and command not in command_candidates:
                command_candidates.append(command)
        label_map = {
            "mp_download": "下载后追踪",
            "mp_subscribe": "订阅后追踪",
            "cloud_write": "云盘落库追踪",
            "mp_diagnosis": "本地/PT 状态追踪",
            "ai_reingest": "AI 二次识别重放追踪",
        }
        summary = {
            "category": category,
            "stage": self._clean_text(stage),
            "label": label_map.get(category, category or "后续追踪"),
            "preferred_action": self._clean_text(recommended_action),
            "decision_hint": self._clean_text(follow_up_hint),
            "command_policy": "safe_read_only",
            "preferred_requires_confirmation": False,
            "fallback_requires_confirmation": False,
            "can_auto_run_preferred": bool(command_candidates),
            "preferred_command": command_candidates[0] if command_candidates else "",
            "fallback_command": command_candidates[1] if len(command_candidates) > 1 else "",
            "compact_commands": command_candidates[:2],
            "recommended_commands": command_candidates[:3],
            "next_actions": action_names[:4],
            "action_templates_count": len([item for item in (action_templates or []) if isinstance(item, dict)]),
        }
        if category == "ai_reingest" and keyword:
            summary.update({
                "preferred_command": "诊断",
                "fallback_command": "入库状态",
                "compact_commands": ["诊断", "入库状态"],
                "recommended_commands": ["诊断", "入库状态", "工作清单"],
                "can_auto_run_preferred": True,
                "recommended_agent_behavior": "auto_continue",
                "auto_run_command": "诊断",
                "confirm_command": "",
                "display_command": "诊断",
            })
        return summary

    @staticmethod
    def _format_followup_summary_lines(summary: Optional[Dict[str, Any]]) -> List[str]:
        data = dict(summary or {})
        if not data:
            return []
        lines: List[str] = []
        label = AgentResourceOfficer._clean_text(data.get("label"))
        stage = AgentResourceOfficer._clean_text(data.get("stage"))
        hint = AgentResourceOfficer._clean_text(data.get("decision_hint"))
        commands = [AgentResourceOfficer._clean_text(item) for item in (data.get("compact_commands") or data.get("recommended_commands") or []) if AgentResourceOfficer._clean_text(item)]
        if label:
            lines.append(f"后续追踪：{label}{f' | {stage}' if stage else ''}")
        if hint:
            lines.append(f"建议：{hint}")
        if commands:
            lines.append("可直接继续：" + " / ".join(commands))
        return lines

    @staticmethod
    def _assistant_local_api_base_urls() -> List[str]:
        return [
            "http://127.0.0.1:3001",
            "http://127.0.0.1:3000",
            "http://host.docker.internal:3000",
        ]

    def _assistant_plugin_api_request(
        self,
        *,
        plugin_name: str,
        path: str,
        query: Optional[Dict[str, Any]] = None,
        body: Optional[Dict[str, Any]] = None,
        method: str = "GET",
        timeout: int = 15,
    ) -> Dict[str, Any]:
        token = self._clean_text(getattr(settings, "API_TOKEN", "") if settings is not None else "")
        if not token:
            return {"success": False, "message": "服务端未配置 API Token"}
        safe_path = "/" + self._clean_text(path).lstrip("/")
        query_payload = dict(query or {})
        query_payload["apikey"] = token
        last_error = ""
        payload_bytes: Optional[bytes] = None
        headers = {"Accept": "application/json"}
        if body is not None:
            headers["Content-Type"] = "application/json"
            payload_bytes = json.dumps(dict(body or {}), ensure_ascii=False).encode("utf-8")
        for base_url in self._assistant_local_api_base_urls():
            try:
                url = f"{base_url}/api/v1/plugin/{plugin_name}{safe_path}?{urlencode(query_payload)}"
                request = UrlRequest(
                    url=url,
                    data=payload_bytes,
                    headers=headers,
                    method=(method or "GET").upper(),
                )
                with urlopen(request, timeout=max(5, self._safe_int(timeout, 15))) as response:
                    raw = response.read().decode("utf-8", errors="ignore")
                payload = json.loads(raw or "{}")
                if isinstance(payload, dict):
                    return payload
                last_error = f"插件 {plugin_name} 返回了非字典 JSON"
            except Exception as exc:
                last_error = str(exc)
        return {
            "success": False,
            "message": f"调用 {plugin_name}{safe_path} 失败：{last_error or '未知错误'}",
        }

    @staticmethod
    def _assistant_ai_recognizer_plugin() -> Any:
        if PluginManager is None:
            return None
        try:
            running_plugins = PluginManager().running_plugins or {}
        except Exception:
            return None
        return running_plugins.get("AIRecognizerEnhancer")

    def _assistant_ai_failed_samples_payload(self, *, limit: int) -> Dict[str, Any]:
        plugin = self._assistant_ai_recognizer_plugin()
        if plugin is not None and hasattr(plugin, "_read_failed_samples") and hasattr(plugin, "_inject_sample_indices"):
            try:
                samples = plugin._inject_sample_indices(plugin._read_failed_samples(limit=max(1, min(limit, 100))))
                return {
                    "success": True,
                    "data": {
                        "count": len(samples),
                        "samples": samples,
                    },
                }
            except Exception as exc:
                logger.warning(f"[AgentResourceOfficer] 读取 AI 失败样本失败，改走 HTTP 兜底：{exc}")
        return self._assistant_plugin_api_request(
            plugin_name="AIRecognizerEnhancer",
            path="/failed_samples",
            query={"limit": max(1, min(limit, 100))},
            method="GET",
        )

    def _assistant_ai_sample_worklist_payload(self, *, limit: int) -> Dict[str, Any]:
        plugin = self._assistant_ai_recognizer_plugin()
        if plugin is not None and hasattr(plugin, "_read_failed_samples") and hasattr(plugin, "_inject_sample_indices") and hasattr(plugin, "_summarize_sample"):
            try:
                samples = plugin._inject_sample_indices(plugin._read_failed_samples(limit=max(1, min(limit, 100))))
                worklist = [plugin._summarize_sample(sample) for sample in samples]
                return {
                    "success": True,
                    "data": {
                        "count": len(worklist),
                        "samples": worklist,
                    },
                }
            except Exception as exc:
                logger.warning(f"[AgentResourceOfficer] 读取 AI 工作清单失败，改走 HTTP 兜底：{exc}")
        return self._assistant_plugin_api_request(
            plugin_name="AIRecognizerEnhancer",
            path="/sample_worklist",
            query={"limit": max(1, min(limit, 100))},
            method="GET",
        )

    def _assistant_ai_sample_insights_payload(self, *, limit: int, top: int) -> Dict[str, Any]:
        plugin = self._assistant_ai_recognizer_plugin()
        if plugin is not None and hasattr(plugin, "_read_failed_samples") and hasattr(plugin, "_inject_sample_indices") and hasattr(plugin, "_build_sample_insights"):
            try:
                samples = plugin._inject_sample_indices(plugin._read_failed_samples(limit=max(1, min(limit, 200))))
                insights = plugin._build_sample_insights(samples, top=max(1, min(top, 20)))
                return {
                    "success": True,
                    "data": insights,
                }
            except Exception as exc:
                logger.warning(f"[AgentResourceOfficer] 读取 AI 样本洞察失败，改走 HTTP 兜底：{exc}")
        return self._assistant_plugin_api_request(
            plugin_name="AIRecognizerEnhancer",
            path="/sample_insights",
            query={"limit": max(1, min(limit, 200)), "top": max(1, min(top, 20))},
            method="GET",
        )

    def _assistant_ai_replay_failed_sample_payload(
        self,
        *,
        sample_index: int,
        remove_if_resolved: bool,
    ) -> Dict[str, Any]:
        body = {
            "sample_index": max(0, self._safe_int(sample_index, 0)),
            "remove_if_resolved": bool(remove_if_resolved),
        }
        plugin = self._assistant_ai_recognizer_plugin()
        if plugin is not None and hasattr(plugin, "_replay_failed_sample"):
            try:
                result = plugin._replay_failed_sample(body)
                if isinstance(result, dict):
                    return result
            except Exception as exc:
                logger.warning(f"[AgentResourceOfficer] 重放 AI 失败样本失败，改走 HTTP 兜底：{exc}")
        return self._assistant_plugin_api_request(
            plugin_name="AIRecognizerEnhancer",
            path="/replay_failed_sample",
            method="POST",
            body=body,
        )

    def _assistant_ai_sample_by_index(self, *, cache_key: str, sample_index: int) -> Dict[str, Any]:
        desired = self._safe_int(sample_index, 0)
        if desired <= 0:
            return {}
        state = self._load_session(cache_key) or {}
        items = state.get("items") if isinstance(state.get("items"), list) else []
        for item in items:
            current = item if isinstance(item, dict) else {}
            if self._safe_int(current.get("sample_index"), 0) == desired:
                return dict(current)
            if self._safe_int(current.get("index"), 0) == desired:
                return dict(current)
        return {}

    @staticmethod
    def _assistant_quarkdisk_plugin() -> Any:
        if PluginManager is None:
            return None
        try:
            running_plugins = PluginManager().running_plugins or {}
        except Exception:
            return None
        plugin = running_plugins.get("QuarkDisk") or running_plugins.get("quarkdisk")
        if plugin is not None:
            return plugin
        for candidate in running_plugins.values():
            if candidate is None:
                continue
            if candidate.__class__.__name__ == "QuarkDisk":
                return candidate
            if getattr(candidate, "plugin_name", "") == "夸克网盘存储":
                return candidate
        return None

    def _assistant_quarkdisk_clear_directory(self, path: str) -> Optional[Tuple[bool, Dict[str, Any], str]]:
        plugin = self._assistant_quarkdisk_plugin()
        if plugin is None or app_schemas is None:
            return None
        try:
            storage_name = self._clean_text(getattr(plugin, "_disk_name", "")) or "夸克网盘"
            clear_cache = getattr(plugin, "clear_cache", None)

            def _safe_clear_cache() -> None:
                if callable(clear_cache):
                    try:
                        clear_cache()
                    except Exception:
                        pass

            def _resolve_folder() -> Any:
                resolved = None
                if hasattr(plugin, "get_folder"):
                    resolved = plugin.get_folder(storage=storage_name, path=Path(path))
                if resolved is None and hasattr(plugin, "get_file_item"):
                    resolved = plugin.get_file_item(storage=storage_name, path=Path(path))
                return resolved

            _safe_clear_cache()
            folder = _resolve_folder()
            if folder is None:
                _safe_clear_cache()
                folder = _resolve_folder()
            if folder is None:
                return False, {
                    "target_path": path,
                    "removed_count": 0,
                    "file_count": 0,
                    "folder_count": 0,
                    "items": [],
                    "time": time.strftime("%Y-%m-%d %H:%M:%S", time.localtime()),
                    "bridge": "quarkdisk",
                    "fallback_to_direct": True,
                }, "QuarkDisk 未定位到目录，改走直连夸克接口确认"

            items = []
            if hasattr(plugin, "list_files"):
                items = plugin.list_files(folder, recursion=False) or []
                if not items:
                    _safe_clear_cache()
                    folder = _resolve_folder() or folder
                    items = plugin.list_files(folder, recursion=False) or []
            files = [item for item in items if getattr(item, "type", "") != "dir"]
            folders = [item for item in items if getattr(item, "type", "") == "dir"]
            if not items:
                return False, {
                    "target_path": path,
                    "removed_count": 0,
                    "file_count": 0,
                    "folder_count": 0,
                    "items": [],
                    "time": time.strftime("%Y-%m-%d %H:%M:%S", time.localtime()),
                    "bridge": "quarkdisk",
                    "fallback_to_direct": True,
                }, "QuarkDisk 返回空列表，改走直连夸克接口确认"

            removed_count = 0
            failed_items: List[str] = []
            for item in items:
                ok = plugin.delete_file(item) if hasattr(plugin, "delete_file") else None
                if ok:
                    removed_count += 1
                    continue
                item_path = self._clean_text(getattr(item, "path", "")) or self._clean_text(getattr(item, "name", ""))
                if item_path:
                    failed_items.append(item_path)
            result = {
                "target_path": path,
                "removed_count": removed_count,
                "file_count": len(files),
                "folder_count": len(folders),
                "items": [self._clean_text(getattr(item, "name", "")) for item in items[:20] if self._clean_text(getattr(item, "name", ""))],
                "failed_items": failed_items[:20],
                "time": time.strftime("%Y-%m-%d %H:%M:%S", time.localtime()),
                "bridge": "quarkdisk",
            }
            if failed_items:
                return False, result, f"夸克网盘存储删除失败：{len(failed_items)} 项未删除"
            return True, result, "success"
        except Exception as exc:
            logger.warning(f"[AgentResourceOfficer] 调用 quarkdisk 清空目录失败，改走直连夸克接口：{exc}")
            return None

    def _assistant_ai_sample_reference(self, *, cache_key: str, sample_index: int) -> Dict[str, Any]:
        desired = self._safe_int(sample_index, 0)
        if desired <= 0:
            return {}
        cached = self._assistant_ai_sample_by_index(cache_key=cache_key, sample_index=desired)
        if cached:
            return cached
        for payload in (
            self._assistant_ai_failed_samples_payload(limit=1000),
            self._assistant_ai_sample_worklist_payload(limit=1000),
        ):
            rows = []
            if isinstance((payload or {}).get("data"), dict):
                rows = (payload.get("data") or {}).get("samples") or []
            if not isinstance(rows, list):
                continue
            for item in rows:
                current = dict(item or {})
                if self._safe_int(current.get("sample_index") or current.get("index"), 0) == desired:
                    return current
        return {}

    def _assistant_ai_replay_target_title(self, *, sample: Dict[str, Any], target: Dict[str, Any]) -> str:
        current_sample = dict(sample or {})
        current_target = dict(target or {})
        return (
            self._clean_text(current_target.get("name"))
            or self._clean_text(current_sample.get("verified_title"))
            or self._clean_text(current_sample.get("guess_name"))
            or self._clean_text(current_sample.get("title"))
            or self._clean_text(current_sample.get("path"))
        )

    def _assistant_ai_sample_matches(self, sample: Dict[str, Any], keyword: str) -> bool:
        needle = self._clean_text(keyword).lower()
        if not needle:
            return True
        target = sample.get("inferred_target") if isinstance(sample.get("inferred_target"), dict) else {}
        fields = [
            sample.get("title"),
            sample.get("path"),
            sample.get("reason"),
            sample.get("guess_name"),
            sample.get("verified_title"),
            target.get("name"),
        ]
        for value in fields:
            text = self._clean_text(value).lower()
            if text and needle in text:
                return True
        return False

    def _assistant_ai_filtered_rows(self, rows: List[Dict[str, Any]], keyword: str) -> List[Dict[str, Any]]:
        if not keyword:
            return [dict(item or {}) for item in rows]
        return [
            dict(item or {})
            for item in rows
            if self._assistant_ai_sample_matches(dict(item or {}), keyword)
        ]

    def _assistant_ai_followups(
        self,
        *,
        session: str,
        session_id: str,
        keyword: str,
    ) -> Tuple[List[str], List[Dict[str, Any]]]:
        base_body = {
            "session": session,
            "session_id": session_id,
            "keyword": keyword,
            "compact": True,
        }
        action_order = [
            "query_ai_sample_worklist",
            "query_ai_sample_insights",
            "query_ai_failed_samples",
            "query_mp_local_diagnose",
        ]
        templates = [
            self._assistant_action_template(
                name=name,
                description={
                    "query_ai_sample_worklist": "查看 AI 识别失败样本工作清单，适合先挑目标",
                    "query_ai_sample_insights": "查看 AI 失败样本洞察，适合看重复样本和优先处理项",
                    "query_ai_failed_samples": "查看 AI 原始失败样本列表，适合核对标题、路径和失败原因",
                    "query_mp_local_diagnose": "回到本地/PT 诊断链，继续看入库失败阶段和证据",
                }.get(name, name),
                endpoint="/api/v1/plugin/AgentResourceOfficer/assistant/action",
                tool="agent_resource_officer_execute_action",
                body={**base_body, "name": name},
            )
            for name in action_order
        ]
        return action_order, templates

    def _assistant_ai_sample_brief_lines(
        self,
        rows: List[Dict[str, Any]],
        *,
        limit: int = 5,
    ) -> List[str]:
        lines: List[str] = []
        for item in rows[: max(1, min(limit, 10))]:
            label = (
                self._clean_text(
                    ((item.get("inferred_target") or {}).get("name"))
                    if isinstance(item.get("inferred_target"), dict)
                    else ""
                )
                or self._clean_text(item.get("verified_title"))
                or self._clean_text(item.get("guess_name"))
                or self._clean_text(item.get("title"))
                or "未命名样本"
            )
            confidence = round(self._safe_float(item.get("guess_confidence"), 0.0), 2)
            reason = self._clean_text(item.get("reason")) or "-"
            lines.append(
                f"{self._safe_int(item.get('sample_index'), 0)}. {label} | 置信度 {confidence} | {reason}"
            )
        return lines

    def _assistant_mp_recent_activity_summary(
        self,
        *,
        download_items: List[Dict[str, Any]],
        transfer_items: List[Dict[str, Any]],
    ) -> Dict[str, Any]:
        evidence: List[str] = []
        for item in download_items[:3]:
            evidence.append(
                f"下载 {self._clean_text(item.get('title')) or '-'} | "
                f"{self._clean_text(item.get('date')) or '-'} | "
                f"{self._clean_text(item.get('transfer_status_text')) or '-'}"
            )
        for item in transfer_items[:3]:
            evidence.append(
                f"入库 {self._clean_text(item.get('title')) or '-'} | "
                f"{self._clean_text(item.get('date')) or '-'} | "
                f"{self._clean_text(item.get('status_text')) or '-'}"
            )
        return {
            "status": "ok" if (download_items or transfer_items) else "not_found",
            "matched": bool(download_items or transfer_items),
            "stage": "unknown",
            "confidence": 0.8 if (download_items or transfer_items) else 0.95,
            "evidence": evidence[:6],
            "risk_reasons": [],
            "recommended_action": "query_mp_lifecycle_status",
            "follow_up_hint": "先从最近活动里挑目标，再继续看单个资源的生命周期或本地诊断。",
        }

    async def _assistant_mp_lifecycle_status(
        self,
        *,
        session: str,
        cache_key: str,
        title: str = "",
        hash_value: str = "",
        limit: int = 5,
    ) -> Dict[str, Any]:
        safe_limit = max(1, min(10, self._safe_int(limit, 5)))
        channel = self._ensure_feishu_channel()
        task_result = channel._query_download_tasks(
            status="all",
            title=title,
            hash_value=hash_value,
            limit=safe_limit,
        )
        download_result = channel._query_download_history(
            title=title,
            hash_value=hash_value,
            limit=safe_limit,
        )
        transfer_result = channel._query_transfer_history(
            title=title,
            status="all",
            limit=safe_limit,
        )
        task_items = task_result.get("items") if isinstance(task_result.get("items"), list) else []
        download_items = download_result.get("items") if isinstance(download_result.get("items"), list) else []
        transfer_items = transfer_result.get("items") if isinstance(transfer_result.get("items"), list) else []
        keyword = title or hash_value or "全部"
        diagnosis_summary = self._assistant_mp_diagnosis_summary(
            keyword=title,
            hash_value=hash_value,
            task_items=task_items,
            download_items=download_items,
            transfer_items=transfer_items,
        )
        next_actions, action_templates = self._assistant_mp_diagnosis_followups(
            session=session,
            session_id=cache_key,
            keyword=title,
            hash_value=hash_value,
            preferred=self._clean_text(diagnosis_summary.get("recommended_action")) or "query_mp_download_history",
        )
        followup_summary = self._assistant_followup_summary(
            category="mp_diagnosis",
            stage=self._clean_text(diagnosis_summary.get("stage")),
            recommended_action=self._clean_text(diagnosis_summary.get("recommended_action")),
            follow_up_hint=self._clean_text(diagnosis_summary.get("follow_up_hint")),
            next_actions=next_actions,
            action_templates=action_templates,
            keyword=title,
            hash_value=hash_value,
        )
        diagnosis_summary["followup_summary"] = followup_summary
        lines = [f"MP 生命周期追踪：{keyword}"]
        lines.append(
            f"结论：{diagnosis_summary.get('stage') or 'unknown'} | "
            f"置信度 {int(float(diagnosis_summary.get('confidence') or 0) * 100)}%"
        )
        lines.append(f"活动下载任务：{len(task_items)} 条；下载历史：{download_result.get('total', len(download_items))} 条；整理历史：{transfer_result.get('total', len(transfer_items))} 条")
        if task_items:
            lines.append("下载任务：")
            for item in task_items[:safe_limit]:
                lines.append(f"{item.get('index')}. {item.get('title')} | {item.get('progress') or '-'} | {item.get('state') or '-'} | Hash:{item.get('hash_short') or '-'}")
        if download_items:
            lines.append("下载历史：")
            for item in download_items[:safe_limit]:
                lines.append(f"{item.get('index')}. {item.get('title')} ({item.get('year') or '-'}) | {item.get('date') or '-'} | {item.get('transfer_status_text') or '-'} | Hash:{item.get('download_hash_short') or '-'}")
        if transfer_items:
            lines.append("整理/入库历史：")
            for item in transfer_items[:safe_limit]:
                lines.append(f"{item.get('index')}. {item.get('title')} ({item.get('year') or '-'}) | {item.get('status_text') or '-'} | {item.get('date') or '-'}")
        if not task_items and not download_items and not transfer_items:
            lines.append("未找到相关任务、下载历史或整理历史。")
        lines.extend(self._format_followup_summary_lines(followup_summary))
        lines.append("说明：这是只读聚合查询，用于判断资源处于搜索后、下载中、已下载还是已落库阶段。")
        self._save_session(cache_key, {
            "kind": "assistant_mp_lifecycle_status",
            "stage": "lifecycle_status",
            "keyword": keyword,
            "items": {
                "download_tasks": task_items,
                "download_history": download_items,
                "transfer_history": transfer_items,
            },
            "target_path": "",
        })
        ok = bool(task_result.get("success")) and bool(download_result.get("success")) and bool(transfer_result.get("success"))
        return {
            "success": ok,
            "message": "\n".join(lines),
            "data": self._assistant_response_data(session=session, data={
                "action": "mp_lifecycle_status",
                "ok": ok,
                "source_type": "moviepilot_lifecycle_status",
                "title": title,
                "hash": hash_value,
                "download_tasks": {
                    "ok": bool(task_result.get("success")),
                    "total": self._safe_int(task_result.get("total"), len(task_items)),
                    "items": task_items,
                },
                "download_history": {
                    "ok": bool(download_result.get("success")),
                    "total": self._safe_int(download_result.get("total"), len(download_items)),
                    "items": download_items,
                },
                "transfer_history": {
                    "ok": bool(transfer_result.get("success")),
                    "total": self._safe_int(transfer_result.get("total"), len(transfer_items)),
                    "items": transfer_items,
                },
                "diagnosis_summary": diagnosis_summary,
                "followup_summary": followup_summary,
                "recommended_action": diagnosis_summary.get("recommended_action"),
                "follow_up_hint": diagnosis_summary.get("follow_up_hint"),
                "next_actions": next_actions,
                "action_templates": action_templates,
            }),
        }

    async def _assistant_mp_ingest_status(
        self,
        *,
        session: str,
        cache_key: str,
        title: str = "",
        hash_value: str = "",
        limit: int = 5,
    ) -> Dict[str, Any]:
        lifecycle = await self._assistant_mp_lifecycle_status(
            session=session,
            cache_key=cache_key,
            title=title,
            hash_value=hash_value,
            limit=limit,
        )
        lifecycle_data = dict((lifecycle or {}).get("data") or {})
        diagnosis_summary = dict(lifecycle_data.get("diagnosis_summary") or {})
        stage = self._clean_text(diagnosis_summary.get("stage")) or "unknown"
        lines = [
            f"本地/PT 入库状态：{self._clean_text(title or hash_value) or '全部'}",
            f"当前阶段：{stage}",
        ]
        if diagnosis_summary.get("evidence"):
            lines.append("证据：")
            for item in (diagnosis_summary.get("evidence") or [])[:5]:
                lines.append(f"- {item}")
        if diagnosis_summary.get("risk_reasons"):
            lines.append("风险：")
            for item in (diagnosis_summary.get("risk_reasons") or [])[:5]:
                lines.append(f"- {item}")
        lines.extend(self._format_followup_summary_lines(diagnosis_summary.get("followup_summary")))
        lifecycle_data["action"] = "mp_ingest_status"
        return {
            "success": bool(lifecycle.get("success")),
            "message": "\n".join(lines),
            "data": lifecycle_data,
        }

    async def _assistant_mp_ingest_failures(
        self,
        *,
        session: str,
        cache_key: str,
        title: str = "",
        limit: int = 10,
        page: int = 1,
    ) -> Dict[str, Any]:
        result = self._ensure_feishu_channel()._query_transfer_history(
            title=title,
            status="failed",
            limit=max(1, min(50, self._safe_int(limit, 10))),
            page=max(1, self._safe_int(page, 1)),
        )
        items = result.get("items") if isinstance(result.get("items"), list) else []
        diagnosis_summary = self._assistant_mp_diagnosis_summary(
            keyword=title,
            hash_value="",
            task_items=[],
            download_items=[],
            transfer_items=items,
            force_failed=bool(items),
        )
        next_actions, action_templates = self._assistant_mp_diagnosis_followups(
            session=session,
            session_id=cache_key,
            keyword=title,
            hash_value="",
            preferred="query_mp_local_diagnose",
        )
        lines = [f"本地/PT 失败线索：{self._clean_text(title) or '最近失败'}"]
        if items:
            for item in items[: min(len(items), 6)]:
                lines.append(
                    f"{item.get('index')}. {item.get('title')} ({item.get('year') or '-'}) | "
                    f"{item.get('status_text') or '-'} | {item.get('date') or '-'}"
                )
        else:
            lines.append("未找到匹配的整理/入库失败记录。")
        self._save_session(cache_key, {
            "kind": "assistant_mp_ingest_failures",
            "stage": "ingest_failures",
            "keyword": title or "failed",
            "items": items,
            "target_path": "",
        })
        return {
            "success": bool(result.get("success")),
            "message": "\n".join(lines),
            "data": self._assistant_response_data(session=session, data={
                "action": "mp_ingest_failures",
                "ok": bool(result.get("success")),
                "source_type": "moviepilot_transfer_failures",
                "title": title,
                "status": "failed",
                "items": items,
                "total": self._safe_int(result.get("total"), len(items)),
                "page": self._safe_int(result.get("page"), page),
                "limit": self._safe_int(result.get("limit"), limit),
                "diagnosis_summary": diagnosis_summary,
                "recommended_action": diagnosis_summary.get("recommended_action"),
                "follow_up_hint": diagnosis_summary.get("follow_up_hint"),
                "next_actions": next_actions,
                "action_templates": action_templates,
            }),
        }

