    async def _assistant_ai_sample_insights(
        self,
        *,
        session: str,
        cache_key: str,
        keyword: str = "",
        limit: int = 20,
        top: int = 5,
    ) -> Dict[str, Any]:
        safe_limit = max(1, min(100, self._safe_int(limit, 20)))
        safe_top = max(1, min(10, self._safe_int(top, 5)))
        result = self._assistant_ai_sample_insights_payload(limit=safe_limit, top=safe_top)
        insights = dict((result.get("data") or {})) if isinstance(result.get("data"), dict) else {}
        next_actions, action_templates = self._assistant_ai_followups(
            session=session,
            session_id=cache_key,
            keyword=keyword,
        )
        priority_samples = insights.get("priority_samples") if isinstance(insights.get("priority_samples"), list) else []
        decision_summary = self._assistant_ai_reingest_decision_summary(
            items=priority_samples,
            fallback_command="工作清单",
        )
        lines = [f"AI 样本洞察：{self._clean_text(keyword) or '全局'}"]
        total_count = self._safe_int(insights.get("total_count"), 0)
        if total_count > 0:
            lines.append(f"样本总数：{total_count}")
            reason_counts = insights.get("reason_counts") if isinstance(insights.get("reason_counts"), list) else []
            if reason_counts:
                lines.append("主要失败原因：")
                for item in reason_counts[:safe_top]:
                    lines.append(f"- {self._clean_text(item.get('reason')) or '-'}：{self._safe_int(item.get('count'), 0)}")
            repeated_groups = insights.get("repeated_groups") if isinstance(insights.get("repeated_groups"), list) else []
            if repeated_groups:
                lines.append("重复出现的样本组：")
                for item in repeated_groups[:safe_top]:
                    lines.append(f"- {self._clean_text(item.get('title')) or '-'}：{self._safe_int(item.get('count'), 0)}")
            if priority_samples:
                lines.append("优先处理样本：")
                lines.extend(self._assistant_ai_sample_brief_lines(priority_samples, limit=safe_top))
        else:
            lines.append("当前没有可分析的 AI 失败样本洞察。")
        self._save_session(cache_key, {
            "kind": "assistant_ai_sample_insights",
            "stage": "ai_sample_insights",
            "keyword": keyword or "all",
            "items": insights,
            "target_path": "",
        })
        return {
            "success": bool(result.get("success")),
            "message": "\n".join(lines),
            "data": self._assistant_response_data(session=session, data={
                "action": "ai_sample_insights",
                "ok": bool(result.get("success")),
                "keyword": keyword,
                "insights": insights,
                "next_actions": next_actions,
                "action_templates": action_templates,
                "decision_summary": decision_summary,
                "recommended_action": "query_ai_sample_worklist",
                "follow_up_hint": "先挑优先样本，再确认是否进入 AI 二次识别重放。",
            }),
        }

    def _assistant_ai_replay_followups(
        self,
        *,
        session: str,
        session_id: str,
        keyword: str,
    ) -> Tuple[List[str], List[Dict[str, Any]]]:
        next_actions: List[str] = [
            "query_ai_sample_worklist",
            "query_ai_failed_samples",
            "query_ai_sample_insights",
        ]
        if keyword:
            next_actions = ["query_mp_local_diagnose", "query_mp_ingest_status", *next_actions]
        base_body = {
            "session": session,
            "session_id": session_id,
            "compact": True,
        }
        templates: List[Dict[str, Any]] = []
        if keyword:
            templates.extend([
                self._assistant_action_template(
                    name="query_mp_local_diagnose",
                    description="继续查看这次二次识别相关的本地/PT 入库诊断线索",
                    endpoint="/api/v1/plugin/AgentResourceOfficer/assistant/action",
                    tool="agent_resource_officer_execute_action",
                    body={**base_body, "name": "query_mp_local_diagnose", "keyword": keyword, "limit": 5},
                ),
                self._assistant_action_template(
                    name="query_mp_ingest_status",
                    description="按目标标题查看当前是否已重新识别、整理或入库",
                    endpoint="/api/v1/plugin/AgentResourceOfficer/assistant/action",
                    tool="agent_resource_officer_execute_action",
                    body={**base_body, "name": "query_mp_ingest_status", "keyword": keyword, "limit": 5},
                ),
            ])
        templates.extend([
            self._assistant_action_template(
                name="query_ai_sample_worklist",
                description="回看 AI 工作清单，继续挑需要重放的失败样本",
                endpoint="/api/v1/plugin/AgentResourceOfficer/assistant/action",
                tool="agent_resource_officer_execute_action",
                body={**base_body, "name": "query_ai_sample_worklist", "keyword": keyword},
            ),
            self._assistant_action_template(
                name="query_ai_failed_samples",
                description="回看 AI 原始失败样本，核对标题、路径和失败原因",
                endpoint="/api/v1/plugin/AgentResourceOfficer/assistant/action",
                tool="agent_resource_officer_execute_action",
                body={**base_body, "name": "query_ai_failed_samples", "keyword": keyword},
            ),
            self._assistant_action_template(
                name="query_ai_sample_insights",
                description="查看 AI 样本洞察，判断失败原因是否仍然集中",
                endpoint="/api/v1/plugin/AgentResourceOfficer/assistant/action",
                tool="agent_resource_officer_execute_action",
                body={**base_body, "name": "query_ai_sample_insights", "keyword": keyword},
            ),
        ])
        return next_actions, templates

    def _assistant_ai_reingest_decision_summary(
        self,
        *,
        items: List[Dict[str, Any]],
        fallback_command: str,
    ) -> Dict[str, Any]:
        fallback = self._clean_text(fallback_command)
        first_index = 0
        for item in items or []:
            first_index = self._safe_int((item or {}).get("index"), 0)
            if first_index > 0:
                break
        if first_index <= 0:
            return {
                "decision_mode": "show_detail",
                "decision_reason": "当前没有可直接重放的 AI 失败样本。",
                "preferred_command": fallback,
                "fallback_command": "",
                "compact_commands": [fallback] if fallback else [],
                "recommended_agent_behavior": "show_only" if fallback else "stop",
                "auto_run_command": "",
                "confirm_command": "",
                "display_command": fallback,
            }
        replay_command = f"重放 {first_index}"
        return {
            "decision_mode": "make_plan",
            "decision_reason": f"先为样本 #{first_index} 生成二次识别重放计划，再确认是否实际重放。",
            "preferred_command": replay_command,
            "fallback_command": fallback,
            "compact_commands": [item for item in [replay_command, fallback] if item],
            "command_policy": "read_then_confirm_write",
            "preferred_requires_confirmation": False,
            "fallback_requires_confirmation": False,
            "can_auto_run_preferred": True,
            "recommended_agent_behavior": "auto_continue_then_wait_confirmation",
            "auto_run_command": replay_command,
            "confirm_command": "确认",
            "display_command": replay_command,
        }

    def _assistant_ai_replay_sample_plan_response(
        self,
        *,
        sample_index: int,
        session: str,
        cache_key: str,
        remove_if_resolved: bool = True,
    ) -> Dict[str, Any]:
        desired = self._safe_int(sample_index, 0)
        if desired <= 0:
            return {
                "success": False,
                "message": "重放样本需要有效编号，例如：重放样本 3。",
                "data": self._assistant_response_data(session=session, data={
                    "action": "ai_replay_failed_sample",
                    "ok": False,
                    "error_code": "missing_sample_index",
                }),
            }
        reference = self._assistant_ai_sample_reference(cache_key=cache_key, sample_index=desired)
        if not reference:
            return {
                "success": False,
                "message": "未找到对应的 AI 失败样本。请先发送“工作清单”或“失败样本”查看当前样本编号。",
                "data": self._assistant_response_data(session=session, data={
                    "action": "ai_replay_failed_sample",
                    "ok": False,
                    "error_code": "sample_not_found",
                    "sample_index": desired,
                }),
            }
        title = self._assistant_ai_replay_target_title(
            sample=reference,
            target=(reference.get("inferred_target") if isinstance(reference.get("inferred_target"), dict) else {}),
        )
        return self._save_assistant_pick_plan_response(
            workflow="ai_replay_failed_sample",
            session=session,
            session_id=cache_key,
            actions=[{
                "name": "replay_ai_failed_sample",
                "session": session,
                "session_id": cache_key,
                "sample_index": desired,
                "remove_if_resolved": bool(remove_if_resolved),
            }],
            execute_body={
                "workflow": "ai_replay_failed_sample",
                "session": session,
                "session_id": cache_key,
                "sample_index": desired,
                "remove_if_resolved": bool(remove_if_resolved),
                "dry_run": False,
            },
            message="AI 二次识别重放计划已生成",
            extra_data={
                "sample_index": desired,
                "remove_if_resolved": bool(remove_if_resolved),
                "source_sample": reference,
                "target": reference.get("inferred_target") if isinstance(reference.get("inferred_target"), dict) else {},
                "keyword": title,
                "decision_summary": {
                    "decision_mode": "execute_now",
                    "decision_reason": (
                        "AI 二次识别重放计划已生成，确认后才会实际重放并尝试重新识别。"
                        if bool(remove_if_resolved)
                        else "AI 二次识别重放计划已生成，确认后会实际重放，但保留原失败样本。"
                    ),
                    "preferred_command": "确认",
                    "fallback_command": "工作清单",
                    "compact_commands": ["确认", "工作清单"],
                    "command_policy": "confirm_then_resume",
                    "preferred_requires_confirmation": True,
                    "fallback_requires_confirmation": False,
                    "can_auto_run_preferred": False,
                    "recommended_agent_behavior": "wait_user_confirmation",
                    "auto_run_command": "",
                    "confirm_command": "确认",
                    "display_command": "确认",
                },
            },
        )

    def _assistant_ai_replay_execution_decision_summary(
        self,
        *,
        ok: bool,
        resolved: bool,
        has_title: bool,
    ) -> Dict[str, Any]:
        if ok and resolved and has_title:
            return {
                "decision_mode": "show_detail",
                "decision_reason": "这次二次识别已命中目标，下一步先看本地诊断确认是否已消除失败，再决定是否继续整理。",
                "preferred_command": "诊断",
                "fallback_command": "入库状态",
                "compact_commands": ["诊断", "入库状态"],
                "command_policy": "safe_read_only",
                "preferred_requires_confirmation": False,
                "fallback_requires_confirmation": False,
                "can_auto_run_preferred": True,
                "recommended_agent_behavior": "auto_continue",
                "auto_run_command": "诊断",
                "confirm_command": "",
                "display_command": "诊断",
            }
        if ok:
            return {
                "decision_mode": "show_detail",
                "decision_reason": "这次重放已完成，但暂未命中目标。先回看工作清单和样本洞察，再决定是否继续重放或补识别词。",
                "preferred_command": "工作清单",
                "fallback_command": "样本洞察",
                "compact_commands": ["工作清单", "样本洞察"],
                "command_policy": "safe_read_only",
                "preferred_requires_confirmation": False,
                "fallback_requires_confirmation": False,
                "can_auto_run_preferred": True,
                "recommended_agent_behavior": "auto_continue",
                "auto_run_command": "工作清单",
                "confirm_command": "",
                "display_command": "工作清单",
            }
        return {
            "decision_mode": "show_detail",
            "decision_reason": "这次重放没有成功执行。先回看工作清单或失败样本，确认当前还能处理哪些样本。",
            "preferred_command": "工作清单",
            "fallback_command": "失败样本",
            "compact_commands": ["工作清单", "失败样本"],
            "command_policy": "show_only",
            "preferred_requires_confirmation": False,
            "fallback_requires_confirmation": False,
            "can_auto_run_preferred": False,
            "recommended_agent_behavior": "show_only",
            "auto_run_command": "",
            "confirm_command": "",
            "display_command": "工作清单",
        }

    async def _assistant_ai_replay_failed_sample(
        self,
        *,
        sample_index: int,
        session: str,
        cache_key: str,
        remove_if_resolved: bool = True,
    ) -> Dict[str, Any]:
        desired = self._safe_int(sample_index, 0)
        if desired <= 0:
            return {
                "success": False,
                "message": "重放样本需要有效编号，例如：重放样本 3。",
                "data": self._assistant_response_data(session=session, data={
                    "action": "ai_replay_failed_sample",
                    "ok": False,
                    "error_code": "missing_sample_index",
                }),
            }
        result = self._assistant_ai_replay_failed_sample_payload(
            sample_index=desired,
            remove_if_resolved=bool(remove_if_resolved),
        )
        ok = bool(result.get("success"))
        payload = dict(result.get("data") or {}) if isinstance(result.get("data"), dict) else {}
        source_sample = dict(payload.get("source_sample") or {}) if isinstance(payload.get("source_sample"), dict) else {}
        target = dict(payload.get("target") or {}) if isinstance(payload.get("target"), dict) else {}
        title = self._assistant_ai_replay_target_title(sample=source_sample, target=target)
        next_actions, action_templates = self._assistant_ai_replay_followups(
            session=session,
            session_id=cache_key,
            keyword=title,
        )
        if ok:
            self._save_session(cache_key, {
                "kind": "assistant_ai_replay",
                "stage": "ai_replay_failed_sample",
                "keyword": title or f"sample-{desired}",
                "items": [source_sample] if source_sample else [],
                "target_path": "",
                "sample_index": desired,
                "replay_result": {
                    "resolved": bool(payload.get("resolved")),
                    "resolved_by_identifiers": bool(payload.get("resolved_by_identifiers")),
                    "resolved_by_recognizer": bool(payload.get("resolved_by_recognizer")),
                    "sample_removed": bool(payload.get("sample_removed")),
                },
            })
        lines = [f"AI 二次识别重放：样本 #{desired}"]
        if title:
            lines.append(f"目标：{title}")
        if ok:
            lines.append("结果：" + ("已命中目标并完成重放" if bool(payload.get("resolved")) else "已完成重放，但暂未命中目标"))
            if payload.get("resolved_by_identifiers"):
                lines.append("来源：当前识别词已直接命中目标。")
            elif payload.get("resolved_by_recognizer"):
                lines.append("来源：识别器重跑后命中了目标。")
            if "sample_removed" in payload:
                lines.append("样本移除：" + ("已移除" if payload.get("sample_removed") else "未移除"))
        else:
            lines.append(self._clean_text(result.get("message")) or "重放失败")
        resolved = bool(payload.get("resolved"))
        recommended_action = "query_mp_local_diagnose" if ok and resolved and title else "query_ai_sample_worklist"
        follow_up_hint = (
            "先回到本地诊断或入库状态，确认这次重放是否已经消除失败。"
            if ok and resolved and title
            else "先看工作清单或失败样本，确认是否还有可重放样本。"
        )
        decision_summary = self._assistant_ai_replay_execution_decision_summary(
            ok=ok,
            resolved=resolved,
            has_title=bool(title),
        )
        return {
            "success": ok,
            "message": "\n".join(line for line in lines if line).strip(),
            "data": self._assistant_response_data(session=session, data={
                "action": "ai_replay_failed_sample",
                "ok": ok,
                "sample_index": desired,
                "source_sample": source_sample,
                "target": target,
                "identifier_preview": payload.get("identifier_preview") if isinstance(payload.get("identifier_preview"), dict) else {},
                "recognize_result": payload.get("recognize_result") if isinstance(payload.get("recognize_result"), dict) else {},
                "resolved": bool(payload.get("resolved")),
                "resolved_by_identifiers": bool(payload.get("resolved_by_identifiers")),
                "resolved_by_recognizer": bool(payload.get("resolved_by_recognizer")),
                "sample_removed": bool(payload.get("sample_removed")),
                "sample_removal_result": payload.get("sample_removal_result") if isinstance(payload.get("sample_removal_result"), dict) else {},
                "recommended_action": recommended_action,
                "follow_up_hint": follow_up_hint,
                "decision_summary": decision_summary,
                "next_actions": next_actions,
                "action_templates": action_templates,
            }),
        }

    async def _assistant_mp_recent_activity(
        self,
        *,
        session: str,
        cache_key: str,
        limit: int = 10,
        download_only: bool = False,
        transfer_only: bool = False,
    ) -> Dict[str, Any]:
        safe_limit = max(1, min(20, self._safe_int(limit, 10)))
        channel = self._ensure_feishu_channel()
        download_result = {"success": True, "items": [], "total": 0}
        transfer_result = {"success": True, "items": [], "total": 0}
        if not transfer_only:
            download_result = channel._query_download_history(title="", hash_value="", limit=safe_limit, page=1)
        if not download_only:
            transfer_result = channel._query_transfer_history(title="", status="all", limit=safe_limit, page=1)
        download_items = download_result.get("items") if isinstance(download_result.get("items"), list) else []
        transfer_items = transfer_result.get("items") if isinstance(transfer_result.get("items"), list) else []
        diagnosis_summary = self._assistant_mp_recent_activity_summary(
            download_items=download_items,
            transfer_items=transfer_items,
        )
        next_actions, action_templates = self._assistant_mp_diagnosis_followups(
            session=session,
            session_id=cache_key,
            keyword="",
            hash_value="",
            preferred="query_mp_lifecycle_status",
        )
        followup_summary = self._assistant_followup_summary(
            category="mp_diagnosis",
            stage=self._clean_text(diagnosis_summary.get("stage")),
            recommended_action=self._clean_text(diagnosis_summary.get("recommended_action")),
            follow_up_hint=self._clean_text(diagnosis_summary.get("follow_up_hint")),
            next_actions=next_actions,
            action_templates=action_templates,
            keyword="",
            hash_value="",
        )
        diagnosis_summary["followup_summary"] = followup_summary
        lines = ["最近本地/PT 活动："]
        if download_items:
            lines.append(f"最近下载：{len(download_items)} 条")
        if transfer_items:
            lines.append(f"最近入库：{len(transfer_items)} 条")
        if not download_items and not transfer_items:
            lines.append("当前没有可展示的最近下载或入库活动。")
        lines.extend(self._format_followup_summary_lines(followup_summary))
        self._save_session(cache_key, {
            "kind": "assistant_mp_recent_activity",
            "stage": "recent_activity",
            "keyword": "recent_activity",
            "items": {
                "download_history": download_items,
                "transfer_history": transfer_items,
            },
            "target_path": "",
        })
        return {
            "success": bool(download_result.get("success")) and bool(transfer_result.get("success")),
            "message": "\n".join(lines),
            "data": self._assistant_response_data(session=session, data={
                "action": "mp_recent_activity",
                "ok": bool(download_result.get("success")) and bool(transfer_result.get("success")),
                "download_history": {
                    "ok": bool(download_result.get("success")),
                    "total": self._safe_int(download_result.get("total"), len(download_items)),
                    "items": download_items,
                },
                "transfer_history": {
                    "ok": bool(transfer_result.get("success")),
                    "total": self._safe_int(transfer_result.get("total"), len(transfer_items)),
                    "items": transfer_items,
                },
                "diagnosis_summary": diagnosis_summary,
                "followup_summary": followup_summary,
                "recommended_action": diagnosis_summary.get("recommended_action"),
                "follow_up_hint": diagnosis_summary.get("follow_up_hint"),
                "next_actions": next_actions,
                "action_templates": action_templates,
            }),
        }

    async def _assistant_mp_local_diagnose(
        self,
        *,
        session: str,
        cache_key: str,
        title: str = "",
        hash_value: str = "",
        limit: int = 5,
    ) -> Dict[str, Any]:
        lifecycle = await self._assistant_mp_lifecycle_status(
            session=session,
            cache_key=cache_key,
            title=title,
            hash_value=hash_value,
            limit=limit,
        )
        lifecycle_data = dict((lifecycle or {}).get("data") or {})
        diagnosis_summary = dict(lifecycle_data.get("diagnosis_summary") or {})
        stage = self._clean_text(diagnosis_summary.get("stage")) or "unknown"
        risk_reasons = diagnosis_summary.get("risk_reasons") or []
        evidence = diagnosis_summary.get("evidence") or []
        ai_worklist = await self._assistant_ai_sample_worklist(
            session=session,
            cache_key=cache_key,
            keyword=title,
            limit=max(5, limit),
        )
        ai_data = dict((ai_worklist or {}).get("data") or {})
        ai_items = ai_data.get("items") if isinstance(ai_data.get("items"), list) else []
        if ai_items:
            evidence.append(f"AI 失败样本命中 {len(ai_items)} 条")
            risk_reasons.append("存在可用于二次识别重放的 AI 失败样本")
        message_lines = [
            f"本地诊断：{self._clean_text(title or hash_value) or '全部'}",
            f"判断阶段：{stage}",
            f"是否命中记录：{'是' if diagnosis_summary.get('matched') else '否'}",
        ]
        if evidence:
            message_lines.append("诊断证据：")
            for item in evidence[:6]:
                message_lines.append(f"- {item}")
        if risk_reasons:
            message_lines.append("风险与失败线索：")
            for item in risk_reasons[:6]:
                message_lines.append(f"- {item}")
        if ai_items:
            message_lines.append("AI 失败样本：")
            for item in self._assistant_ai_sample_brief_lines(ai_items, limit=3):
                message_lines.append(f"- {item}")
        if diagnosis_summary.get("follow_up_hint"):
            message_lines.append(f"建议动作：{diagnosis_summary.get('follow_up_hint')}")
        next_actions = []
        for name in lifecycle_data.get("next_actions") or []:
            text = self._clean_text(name)
            if text and text not in next_actions:
                next_actions.append(text)
        for name in ai_data.get("next_actions") or []:
            text = self._clean_text(name)
            if text and text not in next_actions:
                next_actions.append(text)
        action_templates = []
        for item in (lifecycle_data.get("action_templates") or []) + (ai_data.get("action_templates") or []):
            if isinstance(item, dict):
                action_templates.append(item)
        diagnosis_summary["risk_reasons"] = risk_reasons[:6]
        diagnosis_summary["evidence"] = evidence[:6]
        lifecycle_data["diagnosis_summary"] = diagnosis_summary
        lifecycle_data["action"] = "mp_local_diagnose"
        lifecycle_data["ai_sample_worklist"] = {
            "ok": bool(ai_data.get("ok")),
            "count": self._safe_int(ai_data.get("count"), len(ai_items)),
            "items": ai_items[:10],
        }
        lifecycle_data["next_actions"] = next_actions[:6]
        lifecycle_data["action_templates"] = action_templates[:6]
        return {
            "success": bool(lifecycle.get("success")),
            "message": "\n".join(message_lines),
            "data": lifecycle_data,
        }

    async def _assistant_mp_recommendations(
        self,
        *,
        source: str = "tmdb_trending",
        media_type: str = "all",
        limit: int = 20,
        session: str = "default",
        cache_key: str = "",
    ) -> Dict[str, Any]:
        try:
            from app.chain.recommend import RecommendChain
            from app.schemas.types import MediaType, media_type_to_agent
        except Exception as exc:
            return {
                "success": False,
                "message": f"MP 推荐失败：当前环境缺少推荐依赖 {exc}",
                "data": self._assistant_response_data(session=session, data={"action": "mp_recommendations", "ok": False}),
            }
        max_limit = max(1, min(50, self._safe_int(limit, 20)))
        source_name = self._clean_text(source) or "tmdb_trending"
        media_type_name = self._clean_text(media_type) or "all"
        chain = RecommendChain()
        try:
            def collect_items(raw_results: List[Dict[str, Any]], media_type_filter: str = "") -> List[Dict[str, Any]]:
                current_media_type = media_type_filter or media_type_name
                collected = []
                for raw_item in (raw_results or [])[:max_limit]:
                    if not isinstance(raw_item, dict):
                        continue
                    item_type = raw_item.get("type")
                    if current_media_type != "all":
                        enum_type = MediaType.from_agent(current_media_type)
                        agent_type = media_type_to_agent(item_type)
                        expected_types = {current_media_type}
                        if current_media_type == "movie":
                            expected_types.add("电影")
                        elif current_media_type == "tv":
                            expected_types.update({"电视剧", "剧集"})
                        if enum_type and item_type != enum_type and agent_type not in expected_types:
                            continue
                    collected.append({
                        "index": len(collected) + 1,
                        "title": raw_item.get("title"),
                        "year": raw_item.get("year"),
                        "type": media_type_to_agent(item_type),
                        "tmdb_id": raw_item.get("tmdb_id"),
                        "douban_id": raw_item.get("douban_id"),
                        "vote_average": raw_item.get("vote_average"),
                        "poster_path": raw_item.get("poster_path"),
                        "detail_link": raw_item.get("detail_link"),
                    })
                return collected

            results: List[Dict[str, Any]] = []
            if source_name == "tmdb_trending":
                results = await chain.async_tmdb_trending(page=1)
            elif source_name == "tmdb_movies":
                results = await chain.async_tmdb_movies(page=1)
            elif source_name == "tmdb_tvs":
                results = await chain.async_tmdb_tvs(page=1)
            elif source_name in {"douban_hot", "douban_movie_hot"}:
                results = await chain.async_douban_movie_hot(page=1, count=max_limit)
                if source_name == "douban_hot" and media_type_name in {"all", "tv"}:
                    results.extend(await chain.async_douban_tv_hot(page=1, count=max_limit))
            elif source_name == "douban_tv_hot":
                results = await chain.async_douban_tv_hot(page=1, count=max_limit)
            elif source_name == "douban_movie_showing":
                results = await chain.async_douban_movie_showing(page=1, count=max_limit)
            elif source_name == "douban_movie_top250":
                results = await chain.async_douban_movie_top250(page=1, count=max_limit)
            elif source_name == "douban_tv_animation":
                results = await chain.async_douban_tv_animation(page=1, count=max_limit)
            elif source_name == "bangumi_calendar":
                results = await chain.async_bangumi_calendar(page=1, count=max_limit)
            else:
                return {
                    "success": False,
                    "message": f"不支持的推荐来源：{source_name}",
                    "data": self._assistant_response_data(session=session, data={"action": "mp_recommendations", "ok": False}),
                }
            items = collect_items(results)
            fallback_source = ""
            fallback_notice = ""

            async def fetch_source_items(next_source: str, next_media_type: str) -> List[Dict[str, Any]]:
                if next_source == "tmdb_trending":
                    return collect_items(await chain.async_tmdb_trending(page=1), next_media_type)
                if next_source == "tmdb_movies":
                    return collect_items(await chain.async_tmdb_movies(page=1), next_media_type)
                if next_source == "tmdb_tvs":
                    return collect_items(await chain.async_tmdb_tvs(page=1), next_media_type)
                if next_source == "douban_movie_hot":
                    return collect_items(await chain.async_douban_movie_hot(page=1, count=max_limit), next_media_type)
                if next_source == "douban_tv_hot":
                    return collect_items(await chain.async_douban_tv_hot(page=1, count=max_limit), next_media_type)
                if next_source == "douban_movie_showing":
                    return collect_items(await chain.async_douban_movie_showing(page=1, count=max_limit), next_media_type)
                if next_source == "douban_movie_top250":
                    return collect_items(await chain.async_douban_movie_top250(page=1, count=max_limit), next_media_type)
                if next_source == "douban_tv_animation":
                    return collect_items(await chain.async_douban_tv_animation(page=1, count=max_limit), next_media_type)
                if next_source == "bangumi_calendar":
                    return collect_items(await chain.async_bangumi_calendar(page=1, count=max_limit), next_media_type)
                if next_source == "douban_hot":
                    mixed = collect_items(await chain.async_douban_movie_hot(page=1, count=max_limit), "movie")
                    if media_type_name in {"all", "tv"}:
                        mixed.extend(collect_items(await chain.async_douban_tv_hot(page=1, count=max_limit), "tv"))
                    for idx, item in enumerate(mixed, start=1):
                        item["index"] = idx
                    return mixed[:max_limit]
                return []

            fallback_candidates: List[Tuple[str, str]] = []
            if media_type_name == "tv":
                fallback_candidates = [
                    ("douban_tv_hot", "tv"),
                    ("douban_tv_animation", "tv"),
                    ("tmdb_tvs", "tv"),
                    ("tmdb_trending", "tv"),
                ]
            elif media_type_name == "movie":
                fallback_candidates = [
                    ("douban_movie_showing", "movie"),
                    ("douban_movie_hot", "movie"),
                    ("tmdb_movies", "movie"),
                    ("tmdb_trending", "movie"),
                ]
            else:
                fallback_candidates = [
                    ("douban_hot", "all"),
                    ("douban_movie_showing", "movie"),
                    ("tmdb_trending", "all"),
                ]
            if not items:
                for candidate_source, candidate_media_type in fallback_candidates:
                    if candidate_source == source_name:
                        continue
                    candidate_items = await fetch_source_items(candidate_source, candidate_media_type)
                    if candidate_items:
                        fallback_source = candidate_source
                        fallback_notice = f"{source_name} 当前暂无结果，已自动回退 {candidate_source}。"
                        items = candidate_items
                        break
            if not items:
                return {
                    "success": False,
                    "message": (
                        f"MP 推荐暂无结果：{source_name}。已尝试备用推荐源，仍没有可展示条目。"
                        " 请换一个推荐来源，例如：豆瓣热门 / 豆瓣热映 / 热门电影 / 热门剧集。"
                    ),
                    "data": self._assistant_response_data(session=session, data={
                        "action": "mp_recommendations",
                        "ok": False,
                        "source_type": "moviepilot_recommendation",
                        "source": source_name,
                        "requested_source": source_name,
                        "media_type": media_type_name,
                        "items": [],
                        "fallback_tried": [item[0] for item in fallback_candidates if item[0] != source_name],
                    }),
                }
            display_source = fallback_source or source_name
            lines = [f"MP 热门推荐：{display_source}，共 {len(items)} 条"]
            if fallback_notice:
                lines.append(f"注：{fallback_notice}")
            for item in items[:10]:
                lines.append(f"{item.get('index')}. {item.get('title') or '-'} ({item.get('year') or '-'}) | {item.get('type') or '-'} | 评分 {item.get('vote_average') or '-'}")
            lines.append("下一步：回复“选择 1 决策”进入统一资源决策。")
            lines.append("如果已经明确意图，也可以直接发“选择 1 计划”或“选择 1 确认”；也支持直接回复“详情”“计划”“确认”，默认作用于当前榜单首项。")
            lines.append("如果想走单源，也可以回复“选择 1”进入 MP 原生搜索，或“选择 1 影巢”“选择 1 盘搜”。")
            decision_summary = self._assistant_mp_recommendation_decision_summary()
            if cache_key:
                self._save_session(cache_key, {
                    "kind": "assistant_mp_recommend",
                    "stage": "result",
                    "source": fallback_source or source_name,
                    "requested_source": source_name,
                    "media_type": media_type_name,
                    "keyword": "",
                    "items": items,
                    "target_path": "",
                    "decision_summary": decision_summary,
                    "detail_short_command": "详情",
                    "plan_short_command": "计划",
                    "confirm_short_command": "确认",
                    "decision_short_command": "决策",
                    "pansou_short_command": "盘搜",
                    "hdhive_short_command": "影巢",
                    "mp_short_command": "原生",
                })
            return {
                "success": True,
                "message": "\n".join(lines),
                "data": self._assistant_response_data(session=session, data={
                    "action": "mp_recommendations",
                    "ok": True,
                    "source_type": "moviepilot_recommendation",
                    "source": fallback_source or source_name,
                    "requested_source": source_name,
                    "fallback_source": fallback_source,
                    "media_type": media_type_name,
                    "items": items,
                    "decision_summary": decision_summary,
                    "detail_short_command": "详情",
                    "plan_short_command": "计划",
                    "confirm_short_command": "确认",
                    "decision_short_command": "决策",
                    "pansou_short_command": "盘搜",
                    "hdhive_short_command": "影巢",
                    "mp_short_command": "原生",
                }),
            }
        except Exception as exc:
            logger.error(f"MP 推荐失败：{source_name} {exc}", exc_info=True)
            return {
                "success": False,
                "message": f"MP 推荐失败：{exc}",
                "data": self._assistant_response_data(session=session, data={"action": "mp_recommendations", "ok": False}),
            }

    async def _assistant_streaming_recommend(
        self,
        *,
        media_type: str = "all",
        intent: str = "hot",
        month: str = "",
        window_days: int = 90,
        session: str = "default",
        cache_key: str = "",
        compact: bool = False,
    ) -> Dict[str, Any]:
        """流媒体推荐：TMDB discover 直连，返回按热度+评分综合排序的推荐列表"""
        try:
            from datetime import date as _date, timedelta as _td
            from .services.streaming_recommend import StreamingRecommendService
        except Exception as exc:
            return {
                "success": False,
                "message": f"流媒体推荐加载失败：{exc}",
                "data": self._assistant_response_data(session=session, data={"action": "streaming_recommend", "ok": False}),
            }

        tmdb_api_key = self._read_tmdb_api_key()
        if not tmdb_api_key:
            return {
                "success": False,
                "message": "TMDB API Key 未配置，无法查询流媒体推荐。请在 MoviePilot 系统设置中配置 TMDB API Key。",
                "data": self._assistant_response_data(session=session, data={"action": "streaming_recommend", "ok": False}),
            }

        today = _date.today()

        # ── 时间范围 ──
        start_date = ""
        end_date = ""
        if month:
            # month 格式：2026-05 → 严格按自然月
            try:
                y, m = (int(x) for x in month.split("-"))
                month_start = _date(y, m, 1)
                if m == 12:
                    month_end = _date(y + 1, 1, 1) - _td(days=1)
                else:
                    month_end = _date(y, m + 1, 1) - _td(days=1)
                start_date = month_start.isoformat()
                end_date = month_end.isoformat()
            except Exception:
                start_date = today.isoformat()
                end_date = today.isoformat()
        elif window_days > 0:
            start_date = (today - _td(days=window_days)).isoformat()
            end_date = today.isoformat()
        else:
            start_date = today.isoformat()
            end_date = today.isoformat()

        service = StreamingRecommendService(tmdb_api_key=tmdb_api_key)
        result = await service.query(
            media_type=media_type,
            intent=intent,
            start_date=start_date,
            end_date=end_date,
            window_days=window_days,
            limit=10,
        )

        if not result.get("success"):
            return {
                "success": False,
                "message": result.get("message") or "流媒体推荐查询失败。",
                "data": self._assistant_response_data(session=session, data={"action": "streaming_recommend", "ok": False}),
            }

        items = result.get("items") or []
        query_params = result.get("query_params") or {}

        if month:
            try:
                _y, _m = (int(x) for x in month.split("-"))
                time_desc = f"{_y}年{_m:02d}月"
            except Exception:
                time_desc = month
        else:
            time_desc = f"近{window_days}天"

        if not items:
            type_desc = {"movie": "电影", "tv": "剧集"}.get(media_type, "影视")
            return {
                "success": True,
                "message": f"流媒体推荐（{time_desc} · {type_desc}）暂无结果。请换个条件试试。",
                "data": self._assistant_response_data(session=session, data={
                    "action": "streaming_recommend",
                    "ok": True,
                    "items": [],
                }),
            }

        # ── 格式化输出 ──
        intent_labels = {"hot": "热门", "new": "上新", "big_titles": "大作"}
        type_labels = {"movie": "电影", "tv": "剧集", "all": "影视"}
        header = f"流媒体推荐（{time_desc} · {intent_labels.get(intent, '热门')} · {type_labels.get(media_type, '影视')}）共 {len(items)} 条"

        lines = [header]
        for item in items:
            idx = item.get("index", "")
            title = item.get("title", "-")
            year = item.get("year", "-")
            media_t = item.get("media_type", "-")
            avg = item.get("vote_average", "-")
            pop = item.get("popularity", "-")
            release = item.get("release_date", "")
            reason = item.get("reason", "")
            display_release = release[:10] if release else "-"

            emoji = "🎬" if media_t == "电影" else "📺"
            lines.append(
                f"{idx}. {emoji} {title} ({year}) | 评分 {avg} | 热度 {pop}"
            )
            lines.append(
                f"   上线：{display_release} | {reason}"
            )

        lines.append("当前结果为只读推荐列表；如需继续处理，请改发 MP搜索 / PT搜索 / 盘搜搜索 / 影巢搜索 片名。")

        # ── 存 session ──
        if cache_key:
            self._save_session(cache_key, {
                "kind": "assistant_streaming_recommend",
                "stage": "result",
                "media_type": media_type,
                "intent": intent,
                "month": month,
                "window_days": window_days,
                "items": items,
                "query_params": query_params,
            })

        return {
            "success": True,
            "message": "\n".join(lines),
            "data": self._assistant_response_data(session=session, data={
                "action": "streaming_recommend",
                "ok": True,
                "media_type": media_type,
                "intent": intent,
                "month": month,
                "window_days": window_days,
                "items": items,
                "query_params": query_params,
            }),
        }

    def _format_mp_recommend_item_detail_text(self, item: Dict[str, Any]) -> str:
        title = self._clean_text(item.get("title")) or "-"
        year = self._clean_text(item.get("year")) or "-"
        media_type = self._clean_text(item.get("type")) or "-"
        tmdb_id = self._clean_text(item.get("tmdb_id")) or "-"
        douban_id = self._clean_text(item.get("douban_id")) or "-"
        vote = self._clean_text(item.get("vote_average")) or "-"
        lines = [
            "MP 推荐条目详情",
            f"标题：{title}",
            f"年份：{year}",
            f"类型：{media_type}",
            f"评分：{vote}",
            f"TMDB：{tmdb_id}",
            f"豆瓣：{douban_id}",
            "下一步：回复“决策”“计划”“确认”，或“盘搜”“影巢”“原生”。",
        ]
        return "\n".join(lines)

