                "mp_subscribe_plan",
                "mp_subscribe_search_plan",
                "mp_subscribes",
                "mp_subscribe_control_plan",
                "mp_transfer_history",
                "mp_ingest_failures",
                "mp_recent_activity",
                "mp_local_diagnose",
